begin;

insert into public.lesson_records (lesson_record_id, student_id, course_id, staff_id, lesson_date, start_time, end_time, title, content, homework, memo) values
  ('885f0da8-0291-5ae0-811f-277ebaab5aa5', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-11-20', '17:30:00', null, '振替 / メッセージ、「止める」ブロック', '前回の追いかけっこを軽く復習し、今回のダイヤ探しを遊んでもらいました。 一緒に細分化したり、どのブロックを使うか問いかけたりすると、クラゲやダイヤのおおまかな動きが比較的スムーズに作れました。ゲームオーバーのところで「止める」ブロックを使うということもしっかり分かっていました。また今回は「～秒でどこかへ行く」と「どこかへ行く」を両方使いましたが、その違いも理解していました。', '続き', 'タイピング: 最初はココアタイピングの腕試しをやりました。 レッスンの最後の方にえにしくんがタイピングコロシアムという対戦ゲーム型のタイピングサイトで遊んでいて興味津々だったので、難しかったですが一緒にやってみました。
盛り上がり: 「決められた時間頑張ったらゲームをやってもいい」と約束し、前半はメリハリをもって交互にできました。後半は他の子が遊んでいるゲームに夢中になってしまいましたが一番最後は頑張れました。'),
  ('1944a99f-bd0f-5a06-bba2-0dc989b0bb0e', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-20', '16:30:00', null, '振替 / 検定対策', '自転車のトラブルということで15分ほど遅れてきたので、すぐに課題を始めました。 赤ボールの動作の問題②で、文章の長さと見慣れない日本語に閉口したようで、「もうわからない～」と投げ出しそうになっていました。 まず、「まとまでの距離」だけに着目させ、「調べる」ブロックを見るようにとのヒントを出しました。距離で使用するブロックが分かった後も、何から手を付けてよいかわからなくなっていたようだったので、問題文にしるしをつけ、「大きくなるまで繰り返し」は作れる？という感じで文章の細分化をさせました。その後は、おとなしく最後まで問題を解いていました。 最後までは時間内に解き終えましたが、的は回るけどボールが全く動かない、と言っていたので、問題文の順に確認をさせました。 問題②のaの条件分岐の中に、b以降の設問分のコードを入れていたのが原因でした。問題文の書き方も大きなヒントであることを伝えました。', '自作のゲームを見てあげられなかったので、授業時間内に見てやってほしいです。', '盛り上がり: 教室に来たときは、自作のゲームを見せようとしていましたが、検定前最後の授業であることを伝えると、素直に問題に向き合ってくれました。検定問題が終わったらゲームを見せてね、と声掛けをしましたが、結局遅れてきた分まで検定問題の見直しをしっかりとして、すっきりしたように帰っていきました。'),
  ('0d4587e3-5be0-5a82-877b-d0424b2551df', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-11-20', '16:30:00', null, '通常 / 検定練習', '1つだけわからないところがあったと言われて答え合わせに入りました。「○○と○○」ブロックで文字列を連結するのが初めてで知らなかったようなので使い方を伝えました。また、問題文に「そうでなければ」とあった場所について、「もし～なら...でなければ...」でなく普通の「もし～なら」を使ってやっていたのでそのことを伝えました。するとすぐに修正できたので、本質的に理解はしていたと思います。前回の課題だった不等号の向きについては、今回はきちんとできていました。', null, '盛り上がり: できない場所があっても、落ち着いて状況を整理していました。'),
  ('87c11152-328e-58df-82cf-7783cbd9d170', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-11-18', null, null, '通常 / ゆうれいから逃走', 'ゆうれいから逃走を遊んでもらったあと、最初は例によって自分のアイデアを話し始めようとしましたが、「アレンジはこれの通りに作り終わったらね」と言うと納得してくれました。また、お手本と同じものを作ることはわかっていても、何回か作成の順番がごちゃごちゃになってしまいそうだったので、その都度「1つずつこの順番でやろう」と言って細分化された画面を見せるとその通りにやってくれました。 作成はスムーズに進みました。特に、動作の干渉を防ぐための「1秒待つ」を使いこなせていて、うまく動かないときに「ここはちょっと待てばいいな」と気づいていました。また、「もし～なら」とセットで「ずっと」を使うことや「回転を左右のみにする」の使い方など、以前に習ったことは定着してきている感じがしました。', null, '時間帯: その他
盛り上がり: 今日は良い方向性で集中できていました。'),
  ('2a793e83-31c1-5dcf-9ba2-9c6550f3744b', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-11-18', '16:30:00', null, '通常 / 検定問題３級 応用課題６', 'ずっとのループ処理と四則演算の見分け方でつまづいていました。四則演算に関しては、知らなかったようなので、教えたら納得していました。ループ処理に関しては、終わりのメッセージをどのように送るのかを悩んでいましたが、ループの外へ配置してあげた結果正常に動いたので、こちらの内容についても納得していました。コードの複雑化というよりも文章の長さや読みやすさが原因で間違っているのかもしれないと感じました。', null, '盛り上がり: 応用課題を完成させて、自分の間違いがなぜ起こったのかを理解し、正常に動くにはどのようにコードを変えていけば良いのかを理解することができていたので、今回の問題に満足していました。'),
  ('0bf533c9-5c03-5b88-8717-8df0f1ce13ef', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-11-18', '16:30:00', null, '通常 / 基本操作コース10_細分化バージョン', 'レッスンの内容は細分化されていたこともあって、理解はかなり早くすることができていました。不等号やゲームのクリア条件のコードについてもサクサクと解くことができていたので、余った時間でアレンジなどもしていました。細分化されていた方が一つ一つの目標がかなり近いのでモチベーションも続いていくのではないかと感じました。', null, '盛り上がり: 早めに終わったレッスンの内容を、キャラクターやキャッチするもののコスチュームなどを変えて遊んでいました。作成中に自分で作りたいデザインがあったようで、どのようにするのか楽しそうに語ってくれました。'),
  ('50006af4-0759-51c2-a4b4-c24a6ed310c0', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-11-18', null, null, '通常 / プラットフォーマーを進める', '前回は背景のx座標をどうすればいいのかわからなかったようですが、x座標の値と画面に対しての位置がどう対応しているのか紙に書いて整理すると、背景の動きが理解できました。細分化して「クローンを配置→x<0まで動く→クローンを作る→x<-480まで動かす」という流れを共有すると、少しヒントを出しつつも自分の手で作れました。 そのあと放物ジャンプをやる予定でしたが、まず等速ジャンプの理解が怪しかったようなのでそちらをやりました。一緒に細分化すると、「上に行く→下に行く」ということはすぐわかりました。そのあと「～回繰り返す」の使い方で試行錯誤しましたが、きちんとコードが書けました。必要なスキルは全部扱ったので、プラットフォーマーゲームを作る準備ができました。', 'プラットフォーマー 続き', '時間帯: その他
タイピング: 収支±0円を目指して頑張っていましたがまだ難しかったみたいです
盛り上がり: 最初は「スクロールは世界一難しい」と言っていましたが、集中すると乗り越えられました。'),
  ('d94ce715-5702-529a-8002-88f88dbf7aa1', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-18', null, null, '通常 / 検定対策', '途中でキャラクターの動きがおかしいと言って質問したそうにしていましたが、できないところで止まらずに問題をやり切るのも練習だと伝えると、そのまま続行していました。 問題自体は余裕を持って40分以内で解き終わったようでした。キャラクターの動きに納得がいっていないのと、使用する位置がわからなかったブロックが2つあったため、ムービーの動きを元に使いどころを予想してもらいました。 動きから考えると正解を導き出すことができていました。ただ、大貴君としては、最初も同じ位置に入れたはずなのに、キャラクターが動かなくなってしまったので外した、とのことでした。条件分岐の中での位置がずれていた可能性もあるので、本番はそのあたりの確認を丁寧に、ということと、動きがおかしいと思ったら、一度確実に停止ボタンを押してから実行しなおしてみることを伝えました。', null, '時間帯: その他
盛り上がり: 上記以外はスッキリと解き終えたようでした。今日のゲームは面白かったようで、気分よく取り組めていたようでした。'),
  ('fbfd16ee-c16b-5067-9ad9-7401cfc06b57', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-11-18', null, null, '通常 / 検定問題３級 応用課題６', '今回の問題では、アルスタジオでの四則演算でかけると割るがどの記号で表すのかが分からなかったようですが、それ以外の箇所では目立った間違いは見当たらず完璧に仕上げていました。問題の内容自体は四則演算の箇所を除いて、時間より早く終わることができていたので実力的には問題ないと感じました。', null, '時間帯: その他
盛り上がり: 四則演算の間違いを発見、修正できていたので自分の間違えた理由がわかり納得していました。'),
  ('2c71ecc8-d277-511d-80b6-55d6a8093f4e', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-18', null, null, '振替 / 検定対策', '来室した時から検定対策をする気満々で、授業開始と同時に始めました。 問題自体は35分ほどで解き終えたようで、スプライトのジャンプの動きがコスチュームによって違って見えると言って10分ほど検証していたようでした。 完成例を他の端末で試し、これが仕様なことが確認できたのでスッキリしたようでした。自分でコードや問題文も見直していて、バグが見つからずに悩んだようだったので、ゲームの完成度として自分が納得できないことがあるかもしれないとは伝えました。 念のためという本人の希望で、検定の各級の出題範囲一覧と応用課題3の問題を持って帰りました。', null, '時間帯: その他
盛り上がり: 時間的にも余裕を持ってほぼ完ぺきに仕上げることができ、自信もついたようでした。 合格したらパソコンを買ってもらうんだと嬉しそうに帰りました。
備考: 今日の授業分は振替か追加か確認、追加の場合は料金をお父さんにLINE'),
  ('6ace0cc3-e710-5a50-953a-d2715222b161', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-11-18', null, null, '通常 / プラットフォーマー系ゲームの作成', 'オリジナルのプラットフォーマー系ゲームを作成しました。個人的に制作していた音楽を使用していったり、着地するとはねるトランポリンのような地面を作ったりと自分のアイデアをたくさん作品内に入れていました。今回は、ステージの土台やキャラクターの動きを主に作っていたので、次回からは背景スクロールなどに取り掛っていければ良いと思いました。', null, '時間帯: その他
タイピング: ミスをすることはほとんどなく打つことができていました。途中でキーがどこにあるのかわからなくなっている箇所があったので、その部分だけ気をつけていけばスピードをさらに上げていくことができると思います。
盛り上がり: 自分で作った音楽の導入は今までになかった要素なので、本人の中でもかなり気に入っている部分のようでした。'),
  ('10254d54-9dcb-5b04-b90c-1054d4e20b0c', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-11-17', '17:30:00', null, '通常 / 猫とネズミの追いかけっこ完成', '前回からだいぶ空いたので、前半はどんなコードを作ったのか復習しました。変数が使われいたところがあったが、間接的に答えらていて、それぞれにだいたいは答えられていたので良かったです。残りのコード作成は、動画を見ながら自分で進んでいく様子が見られました。「止まる」のブロックも意味核にしてみたところ、正しく答えられていました。この一時の集中は良いが、自分は何も思わないが、攻撃まがいの接触が多いと思いました。', null, null),
  ('f2a55f01-0073-5d69-9d0b-99fc689bb3fd', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-11-17', '18:40:00', null, '通常 / ジャンプの種類を覚えよう', 'プラットフォーマ―の作成のルートをたどるため、まずはジャンプの種類を学びました。等速ジャンプは、ただ上がり下がりすればいいとy座標ずつのブロックを2つ並べただけでほかの背景をいじろうとしていたので、とりあえず型を見せて、質問形式でコードを理解させました。高さを変数をいじるときも説明に対して、自分の言葉でかみ砕いいて作業をするので、深い理解になっていると思います。 放物ジャンプも上がり幅が1ずつ減少していくことも、ほかの子なら何をどうすればいいかわからなくて手が止まることが多いが、その表現を求めて模索してくれました。とうきくんは変数を使い慣れているせいか上がり幅を変数を介して減少させていくことにすんなり理解ができていました。', null, '盛り上がり: IDを教えましたが、遊びすぎないように'),
  ('0e6a591d-217a-5a6f-9d9a-f101dc287f8a', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-11-17', '16:30:00', null, '通常 / 検定練習', '「まで待つ」のブロックに使い方が理解していなくて、大きくバグを残してしまいました。まで待つの後の文章を中に続いて作っていました。そこで、一緒に「まで待つ」の女権を見たしら次に進むコードの場所を考えながら直したところ、ほかのまで待つの場所は自力で治せる経験を積んでおきました。文章の読み取りはできているので、コードの正しい使い方に注意してもらいたいです。', null, '盛り上がり: スイカゲームの勢いを止まらず'),
  ('aec3325a-e83b-5887-851f-f303249291da', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-11-17', '16:30:00', null, '通常 / 検定練習', '途中で詰まることなく時間通りに解きおわっていました。1ミスで本人もそこまで重いミス出なかったので、安心して受けられると思います。', null, 'タイピング: カット'),
  ('fb6528ed-5b97-56c1-b449-1b2f759bd5b7', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-11-17', '18:40:00', null, '通常 / 検定3級応用問題2', '時間内にしっかり取り組むことができました。ゴールの条件にかなり困っていた様子でしたが、こちらからのヒントなしで最後まで自分で考えきることができていました。メッセージを送る位置を間違えていたようです。ノーミスでした。アレンジとして、応援団を追加するプログラムを追加してくれました。', null, null),
  ('4dcdb706-d22c-59ab-9617-b940354abb06', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-11-17', '17:30:00', null, '通常 / 検定1級応用問題2', 'かなり時間も余裕があったようで、アレンジも含めて取り組んでいました。アレンジは元のプログラムに追加する形でやってくれましたが、アレンジする過程でもとのプログラムがうっかり消えてしまっていたり（2箇所ほど）、場所が変わったりしている部分がありました。本人には元のプログラムの完成度を重視するように伝えました。アレンジもかなり凝ったものになっていて、全体的にはよくできていたと思います。', null, null),
  ('7fc8d239-4394-5d4e-8623-a30f7aefcc8f', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-11-17', '17:30:00', null, '通常 / 検定4級応用問題5', 'アレンジも含めて時間内に取り組むことができました。1箇所読み飛ばしでプログラム忘れがありましたが、他の部分はとてもよくできていました。本人は悔しそうでしたが。アレンジとして太陽や鳥のスプライトを作成し、動きを作っていました。 後半、時間があまったのでスタンプの使い方を紹介しました。色合いに興味があったようです。', null, 'タイピング: 集中して取り組めていました。ミス率0％でした。
盛り上がり: 授業後にけいとくんとスイカゲームで盛り上がっていました。'),
  ('e452802a-b651-5e65-9032-bbc76162534c', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-11-17', '17:30:00', null, '通常 / 検定3級応用問題7', '途中つまっていしまうこともありましたが、ほぼ時間いっぱい挑戦することができました。途中、かなりうまくいかない部分もあったようですが、終了時にはほぼ修正することができていたようです。演算子はよくできていましたが、プラスマイナスのプログラムで読み間違えをしていました。また、「まで繰り返す」がどこまで続くのかを把握しきれず、プログラムの順番を間違えていました。 どこも自分で気が付ける範囲だと思うのですが、途中で集中力が低くなり自分の力を時間内にだしきれていないことがもったいないなと感じました。アレンジはしませんでしたが、構想を考えてくれました。', null, 'タイピング: ミス率も低かったです。
盛り上がり: 授業後にゆづきくんとスイカゲームで盛り上がっていました。'),
  ('9d4d38f6-afff-5085-8aad-a255274fa06d', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-11-17', '16:30:00', null, '通常 / オリジナル作品続き', '前回の振り返りをしました。敵の動きのプログラムを見直し、より論理的なものに書き換えました。再現したい敵の動きを確認し、より忠実に表現しました。 その後、体力と敵の弾の動きを作成しました。体力のプログラムは自力で作ることができていましたが、体力が０になるときの演算の使い方を復習しました。敵の弾の動きはかなり苦戦していましたが、敵の動きから敵の弾のクローンを作るプログラムを作ることで解決できました。途中変数と乱数を組み合わせた考え方を紹介しました。なんとなく理解できたようです。 ほぼ動きはプログラムできたので、来週はゲーム性を高めていく予定です。 ゲームが最後まで作り終えられたら、自分が作る予定だった作品の構想を考えたり作ったりしていきたいです。', 'ゲーム性を高める', 'タイピング: 少しミス率が高かったです。速さは良かったです。
盛り上がり: 作りたいものの具体像が分かると作品を作りやすいのかなと感じました。'),
  ('8214227a-e0d9-5568-81f9-1ba24d73daa0', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-11-16', '17:30:00', null, '通常 / スロットマシーンを作ろう', '最初に遊んでもらいなかなかで目をそろえるのに苦労していました。そして、コードも作り始めようとすると、眠気もあって、なかなかコードに目が向かなかったです。それなので、見た目のから動きから使えそうなブロックを一緒に考えました。それで、スロットマシーン動かすことはできたが、その後、音を選ぶ際に時間を食ってしまっているのが、難点です。ここを短縮できればいいと思っています。', null, 'タイピング: 授業前からずっとやっていました。'),
  ('bf08f25d-8819-53f6-99fc-5700bb24c12c', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-11-16', '16:30:00', null, '通常 / 追跡ゲーム', '作る手順を細分化して動きを見せる方式で進めました。自分の好きなように作ろうとしたときがあったので、基礎のためにもお手本の動きをきちんと再現することを促しました。キーでの移動や音を鳴らすのは比較的スムーズにできました。セリフを言ったりコスチュームを変え続けたりするところでよくわからなくなりお手本の中身のコードを見たいと言っていましたが、順を追って整理していくと無事作れました。', 'ゆうれいから逃走 続き', 'タイピング: 楽しそうにやっていました
盛り上がり: コスチュームや背景をいじるのが好きなようで、こだわっていました。'),
  ('c687590e-8ab9-5d40-aa46-7371ec76d184', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-16', '17:30:00', null, '通常 / 検定問題の最終確認', '時間内には解き終わることはできていました。 自力でバグが解決できないところはそのままにしておいて先に進め、一応完成形まで持っていくことができていました。アレンジもそれなりにできていました。 バグの一つは問題文の読み飛ばしだったため、振り返りで気づくことができました。 もう一つは、スプライトのコスチュームの名前の使い方がわからなかったようで、演算式に直接「左」「右」などと入れていたため、調べるの該当ブロックの使い方を教えました。 時間の都合で完成はできませんでしたが、やり方はわかったとのことでした。', null, '盛り上がり: 行き詰まりそうになったときでも、自分でうまく切り替えて先に進めることができるのが頼もしいです！本人も、あまりくよくよせずに、楽しんで上手に進めているようでした。'),
  ('eb7e65a5-c281-5b8c-b23e-e4b590230c1c', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-11-16', '17:30:00', null, '通常 / 文通りに作ってみよう', '検定自体は受けないが、普段使ったことないコードの組み方や仕様書通り作る練習として、3級の検定の練習問題をやりました。途中までは問題文通りに作っていたが、途中から自作に切り替わっていました。だが、見た目上の動きでは変わらない動きをできていたので、読み取って自力で作る力はかなりついていると思います。けど、問題文をみて普段使っていないブロック使ってほしかったです。', null, '盛り上がり: 自分でシュート位置を動かせるようになっていてよいアレンジでした。'),
  ('d2ad7e28-13fa-5c8e-bf6e-46d8c711d20f', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-16', '17:30:00', null, '通常 / 完成したゲームとヒントを見て、自分でゲームを作成する', '初めにゲームを見た時は、写経しないと無理と言っていましたが、いざ作成を始めると「自分で作ってみたい」と、ヒントの紙のコード部分は見ないで作成しようとしていました。 行き詰まってコードを見た時も、自分だったらこういう作り方はしないというので、オリジナリティを出しても良いと伝えると、少し嬉しそうにコードを組み直していました。 紙のマニュアルで、あとになってから変数作成指定が入るところで、「今更？！」と萎えていました…。 変数の使い方などに、納得がいかない部分があるとのことだったため、承太郎君の解釈で作成した作品がほしいと伝えるとやる気がでていたようでした。', null, '盛り上がり: ヒントと完成したゲーム（コードではなく）をよく見ては、一生懸命に作成していました。 授業後にコンテストにチャレンジして、大差の1位を取っていました！'),
  ('f4c4fcab-7385-5b1f-a98a-633c9e99c1c3', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-11-16', '17:30:00', null, '通常 / オリジナル作品の完成', '前回作りかけたゾンビゲームの続きを進めました。まずは当たり判定を作りました。どのブロックを使うか思い出すのに少し考えていましたが、「調べる」のカテゴリにあるとヒントを出すと「～に触れた」ブロックを選べていました。また、「もし～なら」とセットで「ずっと」を使わないといけないことは自分で思い出せていました。 そのあとゲームオーバーの画面が作りたいと言ったので一緒に作りました。まだ習っていないメッセージを使うことになりましたが、やる気と理解力はあったので、メッセージの概念は説明するとすぐに分かっていました。 そこまでで時間が終わってしまいましたが、ゲームクリアも作りたいと言っていました。', null, '盛り上がり: 新しいことができるようになるのが楽しそうです'),
  ('863b64cd-3644-5000-b8a1-c28b40d2b7b3', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-16', '16:30:00', null, '通常 / 基本的なコードを組み合わせて使うことに慣れる', '長いコードを写すことにはだいぶ慣れたようで、今日はサクサクと残ったスプライトのコード写経を進めていました。 完成後にバグが見つかったため、どういうところがおかしいのか説明させ、その原因を一緒に探しました。 ゲーム開始後に、すぐにゲームオーバースプライトが出てしまうため、最初に該当スプライトのコードと、そのコードが実行されるためのメッセージが送られているかを確認させ、メッセージを受け取った時のコードが動いていなかったため、メッセージを送る側を見直すことを勧めました。最終的には、スコアの条件の不等号の向きが逆だったことに気付くことができました。 もう一つは、単純に「表示する」と「隠す」の入れ間違いでした。こちらも、本来ならどういう動きをしてほしいのかを考えることで解決ができました。 時間が25分ほど余ったため、基本操作コースを勧めたところ、素直に「やってみる」と取り組み始めました。 ジャンプの動きを口頭で細分化させ、納得して作成することができました。', '基本操作コース09の02から', 'タイピング: タイピングには少しずつ慣れてきているようで、ストーリーを進めて満足そうにしていました。
盛り上がり: 飴を食べに行く回数は多かったものの、PCに向かっているときはよく集中して、自分で考えようとすることができていました。'),
  ('19e77920-1ca7-596c-96ad-faf175a105f0', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-11-16', '16:30:00', null, '通常 / 検定練習', '30分いっぱいに解いて終わっていました。そうちゃん的には後半のコードが不安でしたが、間違いなく解けていました。最初のころから比べて、文章を正しく読めていると思います。アレンジしたことも文章で伝わるようにかけていたので、しっかり練習はできたと思います。', null, 'タイピング: 指を見ながら正しく打てていました。
盛り上がり: 解き終わった後も見直す様子がセットで身についていてよかったです'),
  ('bb4dba85-1106-5652-a0ec-fe0dabf91093', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-16', '16:30:00', null, '通常 / 検定問題の最終確認', '試験中に手を挙げて、「！」はどうやって打つのかと質問がありました。メッセージ名などを全部自分で打つのが心配と言っていたので、今回のような記号の打ち方がわからないときは、質問に答えられるからと安心させました。 完成後に、キッカーがすぐに動かないと悩んでいました。「または」を入れるところを「かつ」にしていたため、それぞれの違いを説明し、問題文にもきちんと書いてあることを伝え、問題文の言葉を読み飛ばさないように注意することを伝えました。', null, '盛り上がり: 今日のゲーム作成も楽しめたようで、終わった後でキッカーのスプライトをアレンジして、ゴールの後に光るようにしたりと面白がってアレンジしていました。'),
  ('f4060d5c-fe53-556c-8907-74c8d6ef23fa', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-11-16', '16:30:00', null, '通常 / 検定練習', '問題本文は20分程度で終わり、ミスもありませんでした。特に迷う様子もなかったので検定自体は大丈夫だと思います。アレンジについては、問題文からかけ離れたものになっていそうだったので、何かを付け加えるようなアレンジをするようアドバイスしました。', null, 'タイピング: 集中して取り組んでいました
盛り上がり: スイカゲームにはまってスイカのアレンジを付け加えたのは良かったです。'),
  ('bd0a2d9d-2c47-5420-9cff-4e20ba0ac827', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-11-16', '17:30:00', null, '振替 / 検定練習', 'この問題が終わったらゲームをしてもいいという約束で始めました。解き終わったとき、「(色)に触れた」が初めて使うから分からないとのことだったので、スポイトの使い方を教えました。アレンジをやっていなかったので、本番で時間に余裕があったらやろうねと伝えました。そのほかの部分は完璧にできていたので安心です。', null, '盛り上がり: 問題を解くのにも手慣れてきた様子でした'),
  ('53136c5f-c1be-5270-afe7-104e2b3b5c00', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-14', '17:30:00', null, '通常 / 検定問題におけるスキル確認', '家でできなかったとのことだったので、応用課題2に取り組みました。 時間内には余裕で終わりましたが、ジャンプしたときにひたすら上に行ってしまうのと、穴を掘った後で上にジャンプができなくなるバグが解消できないと、なぜか嬉しそうにぼやいていました。 いずれも、そのような現象が起きるということは、どういうコードが書かれているか、逆の視点から考えさせたところ、条件分岐の中がおかしいことにあっさり気づいて、いずれも自力で直せていました。', '応用課題3あたりを', '盛り上がり: ムービー通りに動いたことで、とても満足したようでした。自力でここまでできたら100点とれるかな、100点取ってみたいな、と、前向きに考えられた様子でした。
備考: 明日から期末試験だそうで、それが終わったら検定に集中できる、とのことでした'),
  ('7bc6ad23-30ff-5ece-a6fe-86d1fa280554', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-14', '17:30:00', null, '通常 / 検定問題の確認をする', '前回解いた問題の答え合わせから入りました。自分でバグの箇所は把握していて、背景として流れるはずのビルが出てこないのと、STARTとFINISHの合図が連続して出てしまうとのことでした。 ビルのクローンが右側に固まったまま動いてこないため、直すべきコードの場所まではわかっているようでしたが、どこが違っているのかわからない、とのこと。演算式を「y座標をy座標-プレイヤーの速さずつ変える」としていたため、問題文の「y座標をプレイヤーの速さずつ変える」の記述を見直して、コードとしてはシンプルに「y座標を〇ずつ変える」となるというところまで説明し、納得できたようでした。 変数である「プレイヤーの速さ」を減らすためにマイナスにする方法を知らなかったとのことなので、計算としては中学で習う範囲だから、いま覚えれば大丈夫と安心させ、「-1」をかける方法を教えました。 合図のバグについては、問題文そのままにブロックをつなげていて動作がおかしくなっていたため、ムービーや修正するコード自体をよく見て作成するように促し、完成させることができていました。 残り時間25分のところで、本人の希望で応用課題1に入りました。1級の問題は、後々アレンジしても使えて面白いということではるちゃんも賛同してくれて、サンドイッチの課題をやってみたいと言い、一通り25分で解き終えていました。 条件分岐で入れ子にする場合と並列にする場合を混同していたところだけ指摘しました。', '応用課題1の、具材がひたすら増殖するバグの解消から', 'タイピング: 今日はすぐに課題に入りたいとのことでした
盛り上がり: 納得した上でバグが解消できたので、スッキリしたようでした。次の課題にも自分から進んで取り組んでくれました。
備考: お母さんから、高校になっても続けられるのかという質問がありました。 一応、中高生が学べるような上級コースの準備をしているとお伝えしてあります。'),
  ('2ba03ec3-7759-54f7-93be-f9428c1ed5d6', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-11-08', '17:30:00', null, '通常 / 検定問題3級①とそのアレンジ', '今回は検定の応用問題で少しつまづいているようだったので、練習問題のアレンジまでやっていきました。結果としては、問題自体は以前やったことのあるもん大だったので間違うことなく解くことができていました。アレンジに関しても、時間内に完成させることができていたので時間配分は問題ないと感じました。しかし、イマイチ集中力が続かないようなのでそこを解決していければ、さらにスピードは上がると思いました。', null, '盛り上がり: アレンジを作成することはあまりなかったようなので、どのようなものを作るのか悩んでいましたが、最終的には納得のいく作品が作れたようです。'),
  ('bf0f017c-2dbe-50ba-af32-a09425caace1', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-11-08', '16:30:00', null, '通常 / 単元別演習F-3~F-5', '単元の内容を少しヒントをもらいながらも、答えを見ずに解くことができていました。単元にないではまだ扱っていない座標を使って作成をしようとしていたので、スキルレベルはかなり高いのではないかと感じました。プログラムを一つづつ見ていく習慣がまだないようなので、そこを意識してやっていくのが良いと思いました。', null, 'タイピング: しゃやちゃなどキーボード内で３文字打つ内容や濁音についてやっていました。間違わないことを意識してできていたので、この調子で続けていけると良いと思います。
盛り上がり: 単元の内容をサクサクと解き進めていくことができていたので、進んでいることをより実感できていたと思います。'),
  ('3a0be945-5385-5882-80af-61dc7b8ee845', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-14', null, null, '通常 / Monacaの教材を進める', '今日は20分ほど早めに来て、すぐにMonacaを始めると言って準備していました。 第1章よりはプログラミングらしさが出てきて興味が持てたのか、姿勢がだらけることもなく、熱心に動画を見ているようでした。 HTMLはなんとなく見たことがある、とのことでした。 40分くらいで第二章が終了し、第三章は中途半端になるのでScratchがやりたいとのことだったので、自由作品を許可しました。Scratchでは、久しぶりに電車のシステム系の作品をいじっていたようです。', 'Monaca第三章から', '時間帯: その他
盛り上がり: 勉強形態に慣れたのか、内容に少しは興味が持てたのか、前回よりも集中して取り組めていました。
備考: 明日から期末試験だそうで、面倒だと言っていました'),
  ('d8191cb1-85ab-5b75-8fa9-8b5b0695bab5', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-14', '16:30:00', null, '通常 / 定義の使われているコードの作成をしてみる', '前回に続き、紙の資料を見ながら作成しました。基本的には紙をうつしての作成ですが、さらちゃんは疑問点があると必ず質問してくるので、コード自体はきちんと読んで納得した上で作成できているようでした。 なぞる判定のスプライトの絵がなかったため、どこにコードを書けばよいのか悩んでいました。コードの内容だけで判断するのは難しかったようです。 変数で使用するブロックで「変数を○○にする」「変数を○○ずつ変える」以外のブロックが出てくると、かなりとまどっていました。', '作成の続き', 'タイピング: 相変わらずはやかったです。
盛り上がり: この作品には、ランキングチャレンジも含めてそれなりに思い入れがあるようで、終始楽しそうに作成していました。'),
  ('2c3914b7-1649-57c4-8611-c13580fa0e36', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-11-08', '17:30:00', null, '通常 / 検定問題１級②の答え合わせ', '問題の内容をあまり読んでいない箇所があり、処理が一部抜けていた部分はあったり小数点を打ち間違えた箇所があったりしましたが、基本的な内容は正確に作成することができていたので、ケアレスミスをなくすことができればさらに点数を伸ばせると思います。', null, '盛り上がり: なぜ政界と同じように動かないのかでかなり悩んでいたので、答え合わせをした後の自分の間違いへの納得はかなり大きかったようです。'),
  ('6ea42335-3349-5043-88fd-b0c3e56847b7', '7d01236e-620e-5177-a6f4-af325a582aae', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-11-08', '17:30:00', null, '通常 / 検定問題４級応用課題３', '今回の問題では、このスプライトの他のスクリプトを止めるという処理を知らなかったようなので、その箇所は間違えてしまっていましたが、他の箇所に関しては完璧に作成することができていました。', null, '盛り上がり: 自分で作ったコードの間違いを直し、アレンジを余った時間でしていたので余裕を持って取り組むことができていました。'),
  ('5fbb7803-218e-5817-85e7-68ca0a66d01d', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-11-13', '17:30:00', null, '通常 / 【改造】密林フィッシング', 'かなり熱心に楽しそうに遊んでいましたが、いざプログラムとなるとかなり嫌そうでした。魚のスプライトが1つしかないことに言及すると複製に気が付いてくれました。プログラミングするように結構促しましたが、気が乗らないようだったのでインベーダー風ゲームを自分で作ることにしました。 味方のスプライトの動きをプログラムすることができました。一方で最近写経が多かったようなので、条件分岐や細かい動きのブロックを忘れてしまったり、難しいブロックを考えたりしまっている様子でした。ビームのプログラムが未完成でかなりこんがらがっているので来週やる予定です。', 'オリジナルゲーム続き', 'タイピング: 最近自分でも進めているそうです。集中して取り組めていました。'),
  ('ed8b3989-f81d-50e8-a44e-da7cfbfb8761', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-11-13', '17:30:00', null, '通常 / 検定3級応用問題4 文章の読み落としや数値ミスが多いので、最後に動画と比較して見直しをする', '最後に見直しをするように伝えました。すごい納得した様子でした。 見直しのお陰でミスが一つもありませんでした。条件分岐と不等号の部分で少し困ったようですが、しっかり訂正することができていました。アレンジがあまり思い浮かばなかったようなので、対戦ゲームにするアドバイスをしました。とても集中して取り組めていました。', null, null),
  ('a3b5fda0-6e4e-5a99-a9fe-3886a716d798', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-11-13', '16:30:00', null, '振替 / 検定3級応用問題4 応用問題3の復習をしてから（～まで待つ）', '応用問題3のボールのプログラムの復習をしました。「ずっと」がどこまでかかるのか、「まで待つ」の読み方について確認しました。 時間内に取り組むことができました。変数とその他の文字を同時に喋らせる方法は知らなかったようなので伝えました。読み飛ばしがありましたが、制御のブロックが入り組んでいる難しい部分はよくできていました。 見本と違うところも把握することができていたので、次のステップとして該当部分を見つけ出して考えられるようになりたいです。', null, null),
  ('e499c32e-973b-5bc9-88a4-bf0ee4b6cf96', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-11-13', '16:30:00', null, '通常 / 検定3級応用問題2', '自分の考えで「ずっと」を付け足してしまったり、「まで繰り返す」に含まれるものの整理がついていなかったり、不等号ミスがあったりしました。前者2つについては文章を読み直すように促すと自分で気が付くことができていました。不等号は向きの判断にも混乱してしまうようです。他の部分は良くできていました。読み飛ばしに関しては自分でかなり気を付けているようで、確認のときも一つずつ示しながらプログラムを説明してくれました！', null, null),
  ('af78ccda-80b8-595d-8476-6316d05700d3', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-11-11', null, null, '通常', '腹ペコザメをやる予定でしたが、話してみると「これは一度やった」と言ったので復習しようと促しました。しかし別のものをやりたそうだったので追跡ゲームにしました。自分で作っていると脱線してしまいがちなため、一つずつの手順を画面上で見せながら作ってもらいました。納得しながら進めていき、最後のレベルアップ以外は終わりました。', 'こうしろうくんと同様にキャッチゲームの分解バージョン？', '時間帯: その他
タイピング: 少しずつキーを覚えている感じがします
盛り上がり: コスチュームを色々いじるのが好きなようです'),
  ('35a3f7f3-52df-52d4-bff3-0b4abec19846', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-11', null, null, '通常 / コスチュームを使った動きの復習とマスター', '今日は自分の作りたいゲームを作る日！と決めてきたようでした。 その前に前回の復習をするという提案は受け入れて、コスチュームを使用したネコの歩く動きを作成しました。 ネコを左右に動かすコードとコスチューム変更を同じコードで作成していたため、向きによって違うポーズで移動する結果になっていたため、本人は面倒がりましたが、結果を見せて説明したところ、コードを別に作成することをかろうじて納得していました。 コスチューム変更のブロックを並べて動かなかったり、2つ目のコスチューム変更の後に待つブロックを入れないことで動きが不自然になったりするたびに、繰り返しの中の仕組みを説明し、最終的に自己解決することができました。 コスチューム確認のあとは、自分の考えたゲームを作りたいと言って、ミッキーのスプライトを熱心に作成していました。', '自作ゲーム作成を楽しんだ後、今日の授業は復習だったのでスタンプが進んでいないと不安そうにしていたので、次回はスタンプを押せるように教材を進める約束をしました。', '時間帯: その他
タイピング: ミスをしないように、と丁寧にがんばっていました
盛り上がり: 明日のディズニーランドが楽しみでたまらないようで、作品にもディズニーランドネタを入れて喜んでいました。'),
  ('7888ad06-acb7-5381-a645-a30ab554b1e6', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-11-11', null, null, '通常 / 検定練習', '検定問題を解くのは少し久しぶりでしたがやり方は忘れていない様子でした。わからないところに線を引いておくなど効率よく進めていました。答え合わせをすると「音を鳴らす」と「～まで音を鳴らす」の使い分けや不等号の向きなど、同じレベルの子によくあるミスはしていましたが、基本的なところは確実にできていました。以前と比べると文章もしっかり読めていて成長しています。', null, '時間帯: その他
盛り上がり: 一度やり始めると集中していました。'),
  ('08a40a28-affa-5c83-804d-b366f053c899', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-11', null, null, '通常 / スタンプの復習とマスター', '前回のスタンプを完全マスターすることを目的に、課題を提示しました。最初は何これ？といった感じでしたが、コードを見せて乱数を使うと言ったら、一気にやる気になりました。 ペンツールを使うときのお約束として、最初に全部消すこと、マウスが押されたならという条件を初めて見たということでそこのメモだけ渡したら、あとは写経をせずに、自力で作成しようと頑張っていました。 色の効果を乱数で変えるところは、何も見ずにスラスラと作成できていました。 スプライトが回転して渦巻き状になる⇒画像効果の渦巻きを使う、と思い込んだようで、思い通りの結果にならないと悩みだしたので、スプライト自体が回転してスタンプを押していく、ということを説明したところ、納得していました。 繰り返しを100回、回す角度を1度で作成し、思った形にならないと質問にきたので、角度は360度で円になること、1度を100回繰り返したら100度までしかいかないという話をした時点で理解できたようで、すぐに回す角度を増やしていました。 一つが完成できたら、コスチュームをどんどん増やして、色々な絵での模様を楽しんでいました。絵の先端が最終的にスタンプとして残ることを発見し、先端の色を工夫したりと、いろいろな実験を存分に楽しんでいました。', null, '時間帯: その他
タイピング: 入室当時よりも積極的に取り組めるようになってきました。指をしっかりホームポジションに置いて打とうとすることができています。
盛り上がり: 今日の教材は楽しかったようで、時間いっぱい飽きることもなく、いろいろと画像を変えたりしては楽しんでいました。
備考: 明日はディズニーランドに行くそうです。'),
  ('cbd28a22-85f8-5117-9590-d296779c4cdd', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-11-11', null, null, '通常 / 検定練習', '遊びたそうにしていたので、この問題をやり切ったら自由時間でいいよと約束するとやる気を持ってやってくれました。時間に余裕をもって解き終わったとのことなので、アレンジをやってもらい、少しずつアレンジに慣れてもらいました。答え合わせをすると、「まで繰り返す」を使うときは「ずっと繰り返す」もセットで使わないといけないと思っていたらしく、「まで"繰り返す"」だから単体で使えるよと伝えました。その他の場所はきちんとできていました。', null, '時間帯: その他
盛り上がり: あおしくんのやってる内容が気になっていましたがちゃんと解いてくれました。'),
  ('c391d799-832c-5f2f-b41d-6875a7be0874', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-11-08', '16:30:00', null, '通常 / 基本操作コース_10_キャッチゲーム', '今回は、工程をより細分化してプログラムを作っていきました。自分のオリジナル要素は今回完成するまで出さないように作成していきましたが、最初の方は少し嫌がる場面も見られましたが、後半はむしろ積極的にプログラムを作成していく姿が見て取れました。細分化しての作成で段々と完成へと近づいていることをよく実感することができていたのではないかと思いました。', null, '盛り上がり: 今回の授業内で完成させることができていたので、本人としてはとても満足しており完成してからのアレンジは特に楽しそうに作っていました。'),
  ('c30beda7-65e1-5982-be75-578403036cde', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, null, '2023-11-11', null, null, '休み（振替対象）', null, null, '時間帯: その他
備考: インフルエンザのため'),
  ('5a390005-cad6-5b71-a6dc-aece19758a36', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-11-11', null, null, '通常 / 検定問題でのスキル確認', '変数と演算の入れ子がわかっていないようで、日本語がおかしい、と言っていたそうです。', '答え合わせ', '時間帯: その他'),
  ('2c766cd4-1d12-54c8-afe0-9e08860bca4c', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-11-11', null, null, '振替 / 検定練習', '検定の時間が終わったところでバグが直らなかったとのことなので該当箇所をチェックしたところ、「～まで繰り返す」の対象を間違えていました。そのあと答え合わせをしようとしたところ少し渋りましたが、ちょっとしたバグが他にもあるかもしれないと伝えるとやってくれました。結果、「音を鳴らす」と「終わるまで音を鳴らす」の使い分け、不等号の向きのミスがありました。少し説明すると理解したようでした。合格圏内にはいるからこの調子で頑張ろうねと伝えました。', null, '時間帯: その他
盛り上がり: やる気を持って取り組んでくれました。バグが直った時は安心していました。'),
  ('0b44aa3f-bf58-5841-914c-6c6f31a049f0', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-11', null, null, '通常 / ○○に触れたら、の使い方を学習', '前回作成していたオリジナル作品のゾンビ追跡ゲームで「あたり判定」を作るために必要な課題をやるということで、素直に納得して課題に取り組み始めました。 お手本の動画を見て、「これは座標で動かすのではないか？」「次はイベントから始めると思う」など、自分で予測を立てていて、動画より先に用意したブロックが合っていると嬉しそうにしていました。 魚の色をオリジナルにしたい、と色塗りをした以外は、脱線もせずにしっかりとチュートリアル通りに進めていました。 当たり判定で「すべてを止める」を使うことにも、最初は「なんでこのブロック？」と言っていましたが、実際の動きを見て、納得できたようでした。 デジタル水族館2まで終わったところで、今日は「もし○○に触れたら」をマスターしたと伝えたら、嬉しそうに、残り時間3分でゾンビゲームを開いて続きを作成しようとしていました。お迎えが早かったので作成の続きはできませんでしたが、次回を楽しみにしていると帰っていきました。', 'オリジナル作品のゾンビゲームで当たり判定を作成', '時間帯: その他
タイピング: 丁寧に指使いを守って打とうとしているところがすばらしい！ アルファベットの読みがあやしいところはありますが、それでもだいぶ慣れてきました。 ただ、英文字だと打てているのに、たまに出てくる日本語の単語だと、下にローマ字が出ているのにも関わらず、なぜかパニックになって焦りだします…。
盛り上がり: 前回の続きから離れた課題にも関わらず、何のために学習しているかという目標がはっきりしていたせいか、とても積極的に学ぼうとしていました。'),
  ('8673c625-e513-513e-b30d-7c03df72be66', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-11-08', null, null, '通常 / プラットフォーマー系ゲームセットの続き', '背景スクロールについてやっていきましたが、不等号についてイマイチわかっていないようでした。背景をクローンするということには気づけていたようですが、どこまで行ったらクローンして、スクロールを止めて消すのかについてかなり悩んでいました。なので、次回からはx座標を基としてより詳しく説明しながら作成して行った方が良いと思いました。', 'プラットフォーマー系ゲームセットの続き', '時間帯: その他
盛り上がり: スクロールに必要なものは自分で気づくことができていたので、その部分については満足していました。'),
  ('51cf4a5d-7967-5224-be8f-c2a0e0d62a73', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-11-08', null, null, '通常 / 検定問題３級 応用問題３', '試験時間内に問題は8割ほど終えることができていました。その後完成させたところ、ボールが画面に表示されないようでしたが、不等号の向きを反対にしていたためでした。それ以外ではミスは見当たらなかったので、その箇所のみ注意していけば完璧に作成をすることができると思いました。解答速度については、一度詰まるとそこで止まってしまっているので一度飛ばして他の箇所に挑戦していくことが重要になっていくのではないかと思いました。', null, '時間帯: その他
盛り上がり: プログラムが正常に作動しない原因を発見することができていたので、結果的に問題に対して悩みを残すことなく終えることができていました。'),
  ('cf63e2dc-0b52-5015-b3a1-88c2579169f4', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-11-08', '16:30:00', null, '通常 / 検定問題２級 練習問題２', '今回の問題は２級の中でもかなり難しいということで苦戦する様子が見られました。特に、”かつ”と”または”についてどのように組み合わせて使えばよいのかかなり悩んでいました。しかし、その箇所は少し教えてあげたところすぐに理解してできるようになっていました。そして、制作にあたって”ずっと”を使うことが習慣化しているらしく、問題文をよく読まずに使っていたので、この点については今後注意して取り組んでいく必要があると感じました。', null, '盛り上がり: 今回のジャンケンをするプログラムはかなり見にくいコードの内容となっていたので、理解するのに少し時間がかかっていましたが、できた際はきちんと納得することができていました。'),
  ('8349e4fc-fa74-552a-9d9a-c548eef6a839', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-11-08', '17:30:00', null, '通常 / 検定問題４級 応用課題３', '今回の問題では、これといって詰まっている箇所はありませんでしたが、制限時間内に問題を解き終えることができていなかったので、制作のスピードに関してはもう少し早めて行った方が良いと思いました。問題文に線を引いたりと几帳面に確認しているのですが、それに少し時間を持っていかれすぎな様子も見られたので、もう少し大雑把に確認をして行っても大丈夫ではないかと感じました。', null, '盛り上がり: 問題の解答自体は間違っている箇所もなかったので満足していました。なので、次回からは時間内に解けるようになりたいと張り切っていました。'),
  ('db316f97-3da6-5949-9ba5-55e53dfdc265', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-11-08', '18:40:00', null, '通常 / フォートナイト風ゲームの作成', '約２ヶ月をかけて制作していた作品をついに完成させることができていました。今回は、座標をまだやっていなかったので背景スクロールを実装することができませんでしたが、キャラクターや敵の判定と壁の建築、プログラムにおいては定義などの幅広い内容を取り扱うことができていました。作る約束をしたということで夢中になって制作をしていたので、とても意欲的に取り組むことができていたと感じました。', null, '盛り上がり: 長い期間をかけての制作だったので、完成した際の達成感はかなり大きかったようでとても喜んでいました。また、検定に対しても挑戦してみたいと意欲的な姿勢を見せていました。
備考: スクラッチ、アルスタジオのIDを教える'),
  ('5f67b374-7915-519c-a0e9-5c74022c6203', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-11-08', '16:30:00', null, '通常 / 検定問題４級 応用問題２', '検定問題の内容については理解することができていました。難易度に関しても、ちょうど良いくらいで制限時間と同じくらいで終えることができていました。問題文をよく読んでいないせいなのか、問題文の順序が混ざってしまったり一部が抜けてしまっている箇所もありましたが、それさえ修正することができれば完璧にこなすことができると感じました。', null, '盛り上がり: 間違いを修正していきながらの完成を実施したので、自分でのケアレスミスに気づくことができていたので、納得していました。'),
  ('68ceffc4-12f8-5622-9636-c288736cfa2f', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-11-10', '17:30:00', null, '通常 / ⇒検定なら3級 ⇒応用⑤（Bronze21）', '後半ゴーストのプログラムに困っていたようなので、2分ほど早めに切り上げて答え合わせをしました。ひとつひとつのプログラムはよくできていたのですが、「～まで繰り返す」がどこまでの範囲なのかをあまり考えられていませんでした。本人的にもイマイチしっくりきていないようだったので、考えるコツを共有しました。 最後にアレンジをしてもらいました。内容を思いつきにくかったようです。月を追加していました。', null, '盛り上がり: コンテストにかなり熱中していました。'),
  ('1601af33-0ce6-558c-b62d-dfb638f4f37a', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-11-10', '16:30:00', null, '通常 / 検定3級準備 ⇒応用⑤（Bronze21）', '時間いっぱい取り組みました。前半はかなり順調でしたが、後半はかなり苦戦したようです。「まで繰り返す」を読み飛ばしてプログラムし忘れていたり、①や②の順序が守られていなかったりしました。ひとつひとつのプログラムはおおよそできているのですが、それらを順番通りにプログラムするのがなかなか難しい様子です。 答え合わせがほぼ終わっていないので、来週答え合わせの続きをやる予定です。', '検定3級応用課題⑤答え合わせ。タイピングをすると時間がなくなりそうなのでなしでいいかもです。', 'タイピング: 集中して取り組めていました。'),
  ('75a45b22-29c4-51b9-bd4b-188d688b7994', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-11-10', '16:30:00', null, '通常 / モチベーションをあげる 自由創作', 'コンテストに挑戦した後、好きなゲームの聞き取り調査をしました。家で30分のScratchまたはYouTubeの時間を選べるようなのですが、最近はYouTube（まいぜんシスターズ）を見ているそうです。好きなゲームは特にないとのことでした。 コンテストのツムツムをかなり熱心にやっていたので、展開の早いゲームに興味があると思い、インベーダー風ゲームを一緒に作ることにしました。本人もキャラを選んだり、サイズを調節したりかなり楽しそうにやっていました。 数を増やす（クローンする）ときに先読みしすぎて困ってしまうようです。とりあえず1体の動きを作った後に、親と子に分けて考えクローンを作る方法を伝えました。 まだ途中なので、次回も製作を続ける予定です。', 'オリジナル作品を続けたいようです。', 'タイピング: 始める前にかなり時間をとって集中（？）していました。思ったよりコンテストの点数が低かった影響で気負っているのかなと感じました。
盛り上がり: 楽しく取り組めていたと思います。'),
  ('71f90889-e0dd-51f2-a01b-424109ffc04c', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-11-09', '17:30:00', null, '通常 / 検定問題2級応用課題1', '時間内にアレンジも含めてかなり余裕で終わらしていました。ミスとしては読み飛ばし、「より小さい」の不等号間違いがありました。不等号ミスに関しては自分で気が付けなかったようなので、身長で例を出して細かく説明しました。なんとなく理解できたようです。アレンジとして間違えた数も言うように設定していました。うまくプログラムできていました。', null, 'タイピング: 授業の最後にやりました。とても速かったです。'),
  ('cf6b30a7-4364-5d60-8317-d7bd7ac58c96', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-11-09', '17:30:00', null, '通常 / スイカゲーム・ツムツム', '見本のプログラムを見て、内容を自分なりにかなり丁寧に分析してコメントを付けていました。とくに果物同士がぶつかったときの動きが気になるようで、変数の動きに注目しながら細かくプログラムを確認していました。時間いっぱいプログラムを確認していましたが、まだ分からない部分も多いようです。やはり一度手を動かした方が身に入ると思うので、一度作ってみることを最後におすすめしました。次回やるかも？といった感じです。', null, 'タイピング: 集中して取り組んでいました。'),
  ('4105cbce-9415-547e-8b37-6f88d4e9351d', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-11-09', '17:30:00', null, '振替 / 検定問題4級の応用課題③', '時間は少しあまりました。「他のスクリプトのプログラムを止める」という部分で困っていました。前回も同じようなところで間違えたようです。他はよくできていました。時間があまったのでアレンジに挑戦してもらいました。初めてだったようです。アレンジの考え方を説明し、新しいスプライトを追加するアレンジをやってもらいました。うまくできていました。', null, 'タイピング: かなりやりたくないようでしたが、かんたんに挑戦してもらいました。'),
  ('c67f3f5b-5b49-5c0b-9115-0fbedabb52c7', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-11-09', '16:30:00', null, '通常 / ゾンビを倒せ続き（ダメージ追加,、ゲームエンドの追加）', 'サメから逃げろをやる予定でしたが、ゾンビを倒せの続きを作りたかった様子なので、ビームの見た目を変えたり、ぶつかったときにプログラムが止まったりするようなアレンジを追加しました。あまり集中できず、数分前の出来事をすぐに忘れてしまっている印象でした。 「もし」「～に触れたら」というブロックに注目して復習しました。使ったことは覚えているようでしたが、まだ定着はしていないようです。 完成したようです。', null, 'タイピング: とても好きなようです。授業外でも時間があるときにやっていました。'),
  ('1907e157-7f57-5f8d-ac01-7b7d6588c033', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-09', '17:30:00', null, '振替 / 前回の復習と、習ったブロックを使用したオリジナル作品作成', '前回の作品を開いて説明を求めたら、嬉しそうに一つ一つのスプライトの動きを見せながら説明してくれました。 コードを作成していないスプライトが2つあったので、基本操作コースのカードの目次を見せ、使っていないコードで何か面白い動きをさせる課題を出したところ、色を変えるのと、キーが押されたときの動きを設定して面白がっていました。 キーが押されたときにマウスポインタへいく、のブロックをとても喜んで、これを使ったゲームを作りたいと言い出したので、後半はオリジナル作品作成に入りました。 キーが押されたときの左右の動き、上下のみのジャンプ、○秒で○○へ行く、を駆使してオリジナルゲームを作成していきました。 まだ難易度の判断がつかないため、とても難しいもの（スクロールなど）を作りたがったりもしますが、表を見せて、これを埋めていけば作れるようになるということを説明しました。', 'オリジナルの作品の続きで、ゾンビにつかまったらの動きを作成、または基本操作コースを進める', 'タイピング: 大文字小文字の違いに苦労しながらも、進めるにつれてキーが読めるようになってきています。ステージ5つ分を熱心に進めました。
盛り上がり: 一つ一つのコードを、とても楽しそうに作っていました。 習ったことを活用するとゲームっぽいものが作れるのが嬉しかったようでした。
備考: スイカゲームを熱心にやっていました'),
  ('d46cf606-7231-5487-9039-f73e0adb646f', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-11-09', '16:30:00', null, '通常 / 検定問題4級の応用課題③', 'すこし時間が足りなかったようなので5分ほど延長しました。「2秒ごとにコスチュームを変える」「〇秒で～～へ動く」などの表現に少し困ったようですが、どれも時間中に自力で解決できていました。アレンジの時間があまりなかったので、考えてもらいました。スプライトを作るアレンジを考え、プログラムもなんとなく想像できたようです。すごい！', null, 'タイピング: 丁寧に取り組めていました。'),
  ('07d713f1-fd78-55f7-991b-d45478218093', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-11-09', '17:30:00', null, '通常 / 今までの復習', '前回メッセージのやり取りを復習しながら、機能の確認をしました。そのまま進むと、変数が出てきたので、今までやったことの「動き」や「もし」の活用などを触れていきました。キーで動かすことは動きだけのコードは自力で作れていたが、向きも付けることが忘れていました。触れる判定ではもしとのセットで作れていたが、ずっとで囲むことが忘れていて、あと少しでした。前にも同じように復習したことはあるが、その時よりかは自分で持ってくるコードは増えていたので、成長はできていると思います。', null, 'タイピング: 英語タイピングまで進んでいました。
盛り上がり: 飼っているインコを描こうとしましたが、途中で止まってしまいました。'),
  ('37de1882-cb57-578b-9d49-2d2f8a867a93', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-09', '16:30:00', null, '通常 / 変数の確認とアレンジを楽しむ', '用意していたサメから逃げろを見せたところ、時間切れとなるゲームが苦手だと渋り始めたので、前回の続きのドーナツキャッチを作成しました。 前回は写経だったようなので、今日はドーナツと虫のコード作成を中心に、コードの意味について質疑応答を交えながら進めました。 「すべてを止める」ブロックのそれぞれの違い、座標を乱数で指定している意味などはよくわからないとのことだったので、それぞれ説明し、多少は納得できたようでした。 2つ目以降のスプライトについては、バックパックから取り出した後、一つ一つ自力で丁寧に見ながら相違点を見つけ、修正していました。丁寧にコードを見ていることをほめると、嬉しそうにしていました。', 'Butterfly2とDonut5のスプライトのコードを作成して完成', 'タイピング: 頑張ってやっていました
盛り上がり: ドーナツを作成することに決めたら、集中して手を動かしていました。 一見コードがたくさんあったり、長いコードがあったりして、開いた瞬間は引いたような態度をしても、なんだかんだ言いながら熱心に取り組んでいました。'),
  ('d2434f1e-b9f6-5c98-ae33-4a0a78960113', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-11-09', '16:30:00', null, '通常 / ピンポンゲームの作成', 'ピンポンゲームを作成しました。新しく使うブロック以外はスムーズにとってきて、特に悩むことはなかったです。ただ。スプライﾄなどにこだわりを持つので、そこで作り悩んでいました。追加に作りたいことも、段階ごとに分けて、話し合っていけば、自分で考えて作れていました。最後のスコア付けに「ずっと」と「もし」で作ろうとしていたが、「まで待つ」の新しくコードに対しては、あまり深く理解ができてなかったので、「まで待つ」が活かせるものを今後作っていければいいと思います。', null, 'タイピング: 前回よりもスコアがよく伸びていました。
盛り上がり: 跳ね返す戦闘機の横の動きもマウスポイントタ―で向けるにしていたので、傾きながら動いていたのは面白かったです。'),
  ('0d004556-40a0-5ca0-9cb8-4e13bbd48bd9', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-09', '16:30:00', null, '通常 / 検定問題に慣れる', '問題に取り組むこと自体には積極的で、真剣に取り組めていました。 乱数を座標の指定に取り入れるところと、「または」を使って条件を2つ並べるところで悩んでいましたが、どちらも「使用するブロックがヒント」との声掛けで解決できていました。', null, 'タイピング: 初めは適当に打ってまぐれでキーが合う確率を面白がっていましたが、他の子の記録を褒めていたら少しまじめにやり始め、星3つを埋めようとがんばっていました。
盛り上がり: 2か所悩んだところがあったため、印象としては難しかった、と言ってはいましたが、ムービー通りに動いたときはとても満足そうにしていました。'),
  ('1c8f3831-d6a3-53c2-9dd6-778509023de5', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-07', '17:30:00', null, '通常 / 検定問題に慣れる', '問題開始までの時間が以前より短くなりました。 途中で時間を気にして投げ出しそうなそぶりを見せましたが、すぐに戻って頑張れたところに成長を感じました。', null, '盛り上がり: 1級問題はさすがに時間も長く、苦戦する様子も見せていますが、それでも最後まで頑張っていました。'),
  ('eb6d8f11-2a3d-5f84-9f71-440ae3749500', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-07', '17:30:00', null, '通常 / 検定問題に慣れる', '時間いっぱい、真剣に取り組んでいました。', '答え合わせ', null),
  ('91e6f81b-1c72-5daa-b1cb-b87d7cf2c1f5', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-26', '17:30:00', null, '通常 / リストの課題を一つ仕上げてみる', '今日もリストの課題だと知ると、見事に引いていたので、前回、頑張ってリストの動画を見たから、今日は少し軽めの課題にして、仕上げることを目的にすることを伝えたところ、素直に取り組み始めました。 途中何度か疲れて手がとまることもありましたが、この教材のコード自体はきちんと理解できていたようで、先生がそばにいくと問題なく進めて完成させることができていました。', null, '盛り上がり: 内容に少し余裕が見られたからか、自信ありげにできていました。'),
  ('7214dd4e-32f0-5f59-bad8-849520f33484', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-26', '17:30:00', null, '通常 / 定義の使い方、判定としての変数の使い方などに着目して', 'ネコの動きの作成をメインに取り組みました。 ネコが障害物にあたったときの回転の数え方や、それが終わったら通常の動きに戻るコードの部分を読み取って解説してもらい、その作り方が面白くない？と水を向けると、確かに、と納得してくれていました。 ゲームのアウト判定の作成方法は色々あるので、こうしてたくさんの工夫されたコードに触れて、自分の中に取り込んでほしいことを話したところ、一生懸命に聴いてくれていました。 一定のレベルには達しているので、ただなんとなくゲームを作るのではなく、今後のプログラミングのネタをどんどん取り込むような形で学習してほしいことを伝えました。', null, 'タイピング: かなり真剣にやっています。
盛り上がり: こちらの話が多少理屈っぽくても、一生懸命に聴いて納得しようとする姿勢が見られました。PCやゲーム、プログラミングなどについても、少しレベルを大人向けにした感じで話すと嬉しそうにのってきてくれました。'),
  ('519bf1c5-20bc-580e-9770-0a5bc6780bd1', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-26', '16:30:00', null, '通常 / 3級から出題範囲になる音、イベント（○○が押されたとき、背景が○○になったとき）、調べる（距離、聞いて待つ、答え、○○が押された、マウスの座標）、演算、変数、音楽、ペンあたりに着目して', '問題自体は熱心に解けていましたが、ムービー通りの動きにならないと気づくと少し動揺が見られ、質問したそうにしていました。疑問点はとりあえず置いておかずにすぐに解決したいようです。 今回は初めての3級挑戦ということと、りょうやくんの性格も鑑みて、今わからなくても、わからないことが見つかってそれを直せばよいからということを説明して落ち着かせ、問題に戻らせました。 うまく動かなかったのはどこまでを繰り返しの中に入れるかというミスだったので、そこだけヒントを出し、残りは自分で頑張る事ができました。 アレンジ時間では、コースの近道を作って大いに楽しんでいました。', null, '盛り上がり: 完成させた作品にセルフツッコミを入れながらアレンジするのがとても楽しそうでした。'),
  ('9ef99b65-3fed-5d4b-ab62-c24a0ab94fc3', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-07', '16:30:00', null, '通常 / いろいろなブロックを使うことに慣れる', 'コンテストのランキングに熱心に挑戦していました。 中のコードを見て、「これならやってみたい」と、ペーパーを見ながらがんばっていました。 定義が初めてだったのですが、少し説明したらとりあえず納得できたようで、自力で作成できていました。 ペーパーを見ながら作成していたので、リストと変数と定義のブロックの見分けに少し混乱が見られましたが、それぞれがどのような使われ方をするのか整理しながら進めていきました。', '続きを作成します', 'タイピング: とても集中してやっていました
盛り上がり: 自分で課題を選んで始めたせいか、初見のブロックについても説明を聞きながら理解しようとする姿勢が見られました。楽しそうにがんばっていました！'),
  ('5ea08f15-333b-5737-93f4-3efb4aa6f6b7', '7d01236e-620e-5177-a6f4-af325a582aae', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-11-07', '17:30:00', null, '通常 / 検定問題４級 応用課題２', '今回の問題では、時間ちょうどに終わることができていました。解答内容に関しては、ケアレスミスが１つありましたがそれ以外は完璧に作成をすることができていました。本人の中でも疑問点などはなかったようです。問題の理解をさらに早くできるようになれば、時間にも余裕ができてアレンジも可能ではないかと感じました。', null, '盛り上がり: ミスをほとんどすることなく完成させることができていたので、満足していました。本人の中でも自分の実力を把握できていたようです。'),
  ('602d5ea0-2137-5087-902f-c48a4be6167e', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-11-07', '17:30:00', null, '通常 / 検定問題３級 応用課題７', '初めての応用課題への挑戦だったので、あまり集中できていなかったのではないかと感じました。問題文の内容が長文であった場合、どの箇所で区切って考えれば良いのかがイマイチ理解をできていない印象でした。プログラミングのスキル内容に関しては問題はないと感じましたが、文章読解がきちんとできるようになれば完璧に仕上げることができるようになるのではないかと思いました。', '検定問題の答え合わせ', '盛り上がり: 自分でわからない箇所を理解し、解決できるようになった際は納得することができていました。'),
  ('e2d98f75-7b38-54c7-b1d6-95b44b1ab081', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, null, '2023-11-07', '17:30:00', null, '休み（未対象）', null, null, '備考: 10/27の振替'),
  ('5b9a9058-666f-5128-a3ff-1eb1f384a030', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, null, '2023-11-06', '17:30:00', null, '休み（未対象）', null, null, null),
  ('28168654-7035-5dc5-b0a5-b528fac48331', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-11-06', '17:30:00', null, '通常 / 検定練習orプラットフォームを進める', '選択肢としてプラットフォームと検定を提示すると、検定をやる気になったので解いてもらいました。一通り素早く解き終わったのですが、答え合わせしてみるとミスが何個かありました。変数の値の打ち間違いや簡単なブロックの入れ忘れなど本質的な間違いではありませんでしたが、一回解き終わって時間が余ったら見直しをしようねと伝えました。 残りの時間はプラットフォームゲームを進めました。ジャンプしたキャラを空中で少し静止させたいとのことだったので、「上に行く→静止→下に行く」という流れでやってもらいました。その際、放物ジャンプの練習もかねて、勢いの変数がいくつになるまで座標の変化を繰り返すのか考えてもらいました。結果、無事にその動きを作れました。', null, 'タイピング: 自己ベストを出していました！
盛り上がり: プラットフォームを自分なりに完成させたい気持ちがありそうです。'),
  ('27ecbebe-88db-55c6-ab6f-1035cdafdba5', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-11-06', '16:30:00', null, '通常 / 検定練習', '解き終わって答え合わせするとミスは1つだけでした。「x座標を○○に、y座標を[○○から○○までの乱数]にする」という問題文で、一見複雑な文に見えるので迷走していましたが、乱数の部分を丸で囲ってみると、やっていることは単純だと気づいたようでした。その他の場所については、ブロックの構造など含めてしっかり理解していました。アレンジをする時間はなかったそうなので、できれば5分くらいは時間が取れるといいねと伝えました。', null, 'タイピング: 集中していました
盛り上がり: 問題にじっくりと取り組んでいる印象でした。'),
  ('eb940b6d-d946-52ee-8cfe-b2fe3cd17721', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-11-04', null, null, '通常 / 検定練習', '検定以外をやる選択肢も提示しましたがどちらでもよいという感じだったので検定にしました。解いて答え合わせをすると、以下のようなミスがありました。 ・「音を鳴らす」と「終わるまで音を鳴らす」の使い分け →違いを知らなかったようだったので伝えると納得していました。 ・繰り返しの対象を間違えていた →この繰り返しはどこからどこまで？と聞くとすぐ気づいていたので、理解はしていてうっかり見落としたという感じでした。', null, '時間帯: その他
タイピング: 集中してやっていました。
盛り上がり: 問題用紙に指さしをしながら解くなど工夫をしていました。'),
  ('08c928a9-185f-5d2a-80ce-ff96b52237c6', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-11-04', null, null, '通常 / 新しく変数を使えるようにしよう', '最初は前回やっていたゲームの写経を続けていたが、若干難しく感じていたので、スプラ委だけ残して、サメ杭ゲームをもとにアレンジをしていました。ただ漠然とアレンジを何をすればいいか、止まっていたので、星取りゲームをもとにコードを加えていきました。カードのコードがどうゆう意味が分からないときはしっかり聞いてくれました。ただ、コードがあっているが「終わるまでならす」のこーどがあって、音の長さ的に次に進まなくなったときに、その対処を教えているにもかかわらず、なかなか試してくれなったことがありました。今回スコアで変数がつけられたので、スコアに応じてステージ変換ができるといいと思います。', null, '時間帯: その他
タイピング: 乱打でもありましたが進めてくれまhした。'),
  ('e9fc9628-a3ae-59bc-bc39-6f2f1880409d', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-11-04', null, null, '通常 / 変数を使いこなす', '変数をマスターするともっと高度なゲームが作れるようになるということで、変数を使ったバレーボールに取り組みました。最初にそのゲームで遊んでもらい、どの順番でコードを書くとやりやすいかを整理して始めました。ボールの動きについては、できたところで報告してもらいましたが、レシーブはできるがそもそもボールが落ちてこなかったり、ボールが1回しか落ちてこなかったりとなかなか元のゲームを再現できず、細分化のスキルが必要と思われました。試行錯誤してボールの動きはできましたが、その後むらっちの腕の位置がおかしくなったところで詰まりました。そこで腕の座標をどうすればいいか一緒に考えましたが、まだコードは書けていません。', '続き(変数の設定を含む)', '時間帯: その他'),
  ('0ac40505-0e35-5172-b9c4-8813c7738de8', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-11-04', null, null, '休み（未対象） / 発熱のため、当日欠席連絡', null, null, '時間帯: その他'),
  ('23cc3e4a-2410-5403-a93e-a7fb940ed24a', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-11-04', null, null, '休み（振替対象） / 休み⇒振替え 11/9（木）17:30～', null, null, '時間帯: その他'),
  ('03b09bee-b28f-5ee9-8892-882d380b8bad', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-11-04', null, null, '通常 / リスト取り込み 検定練習', '最初に前回やっていたリストの読み込み機能の紹介を行いました。外部データを取り込んでプログラムを起動させるということが一般的なプログラムの基本であることを教えてあげたら、とても関心を抱いてくれました。 次に、リストがメインで出てくる検定の練習問題を解きました。リストのブロックの機能に迷うことなく、1つの凡ミスで時間的に余裕をもって解けていました。このまま安心して解けると思います。', null, '時間帯: その他'),
  ('c0182ff2-d282-50e7-9240-b5b591c50eb1', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-11-04', null, null, '通常 / 続きを実施し、基礎スキルを', 'スタンプをコンプリート！と最初から意欲的だったので、続きを実施しました。 カード教材の表面をみて、日本語と図柄だけでブロックを組んでいました。01～04まではほぼ正解を自分で作れていました。 ただ、05コスチュームを変えるは、コスチューム自体を扱うのが初めてだったようなのでやや苦戦しました。 05のカードでは、右に動かしたらコスチュームを変化させて歩いている風に見せるものですが。本人はその前のブロック「左右に動かす」を活用してコスチュームを加えたので。 左を向いているコスチュームがない、と悩みこんでいました。 コスチュームの画像を左右回転する方法を教えました。 次回、ここだけ復習した方が良さそうです。', '基本操作コース03の「05コスチュームを変えよう」の、まずは見本を見せて、それと同じブロックを作るという復習からスタートしたいです、', '時間帯: その他
タイピング: サッカーが合って少し遅れてきたので、ちょっとだけやっていました。先生が少なくて見切れてないです。
盛り上がり: 録音した声を喋らせるのが楽しかったようです。'),
  ('3343dd84-e133-5ce5-84a0-80abefb1dc50', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-11-04', null, null, '通常 / 1級問題の見直し', '前回やった1級の問題を見直しました。どこにバグが起きているか自分で検討をつけられているが、先生がそこを詳しく見返さないことがありました。そばにつけば、ロボロックスをやらずに直しをするが、具体的なコード見直しを放棄することがよく見られました。 直しが終われば、時間が次進には微妙だったので、横スクロールの復習を行いました。クローン型は検定にも出てきてなじみがあったので、メッセージ型を作りかけにして作らせるようにしました。周りのコードの正しく読み取るのは上手くできていたので、片手間に素早く終わりました。', '今日はかなり自由時間が長かったので、次は最初から検定問題をやると約束しました。', '時間帯: その他
盛り上がり: 藤田兄弟へのロボロックスの関心にそそるような自慢をしていました。'),
  ('3fce39dd-f092-528a-815e-a7bff89fca57', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-11-04', null, null, '通常 / ゲーム作成のためのスキルを身に着ける', '1時間は集中が持たないので最初の10分くらいはフリータイムにしてから始めました。話を聞くと、「カービィのゲームを作るのはあきらめたけど、パックマンは作りたい。けど今日はホラーゲームが作りたい」と言っていて、オリジナルのホラーゲームの作成を始めてしまいました。そこで、「何を作るにしてもまずはスキルを身に着ける必要があるよ」と伝えてキャッチゲームの作成を促すと、やる気を持ってそちらに移ってくれました。テキストの通りに進めていきましたが、ここでもオリジナル要素を出そうと構想を話していたので、スキルを身に着けるには一旦お手本と同じようにやるのが一番だと伝えました。内容としては、リンゴ(太陽)の座標設定と、それを落とす動きを途中まで作りました。スプライトを落とすにはy座標をマイナス〇ずつ変えるということは、少し実験して思い出せました。', null, '時間帯: その他
盛り上がり: 少しずつですが成長してきていると思います'),
  ('2fd99c46-354a-5396-8475-9e8bd9a1159f', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-11-04', null, null, '通常 / 基本操作の続き⇒スコア「変数」を使う', '今日は先生が少なかったので、みている時間が少なくなったことが要因かもしれないが。 自己流でやるシーンが多かった。 基本操作コース08さあ踊ろうの最後の単元の続きをやってスタンプをコンプリートしたいということで、「09跡を残そう」から実施。クローンを使って試行錯誤していたので。「スタンプ」を使うというヒントを出すと、自分でコードを探し出してきました。 幽霊効果や魚眼レンズ効果などに目がいき、画像アレンジでひとしきり遊んだ。最後に次のステップである追跡ゲームを案内。自分でサメから逃げろはできると自作していたところ、目を離したすきにグチャグチャニなってしまったので。カード教材がある「既存操作コース04 追跡ゲーム」に切り替えました。見本のゲームをやってから、まずはロボットを動かすコードまで自力作成にチャレンジできました。', '追跡ゲームの続きから。その前に、スタンプの復習はしておきたいです。', '時間帯: その他
タイピング: 熱心にとりくんでいて、声をかけると「もう少しやる」とのことでした。スコアがどの程度のみたかまでは見切れなかったです。
盛り上がり: 自宅でScratchでいろいろ作っているのを見せたいということでした。ScratchのIDとパスワードを今度持ってきてもらえば、教室で見れると伝えました。 備考欄、参照
備考: 自宅のScratchのIDとパスワードです。↓ ID splatoon1523 パスワード 201-22-165719 同期できれば、そうしたいです'),
  ('d5615e9c-40bc-56dd-b85b-f07d715a9b9a', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-11-04', null, null, '通常 / 検定練習', '残り10分を残して1か所を除き、ほぼ完成していました。そのミスも凡ミス程度で本人も作っている最中に悩み止まるところはなかったので、安心して受けられると思います。', null, '時間帯: その他
タイピング: よくできていました'),
  ('19adb563-2491-5a09-9fcc-814ab304e4fa', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-10-30', '16:30:00', null, '振替 / 検定練習', 'ブロックを入れる順番が違っているところがいくつかあったので、(今のうちは)文に書いてある順番そのままで入れようと伝えました。そのとき問題用紙に印をつけながら伝えたので印象には残ったと思いますが、別にどっちでもよくない？と言われたので、検定だと文章をちゃんと読んでその通りにしないと減点されて不合格になるかもしれないことを伝えました。また、使うブロックが微妙に間違っているところもありました。検定問題のやる気はありましたが、いつもと比べて今回は結果が振るわなかったようでした。ただ本人はあまり気にしていない様子でした。', null, '盛り上がり: 「おもちゃの棚にビーカーっておかしくない？」などスプライトや背景にツッコミを入れていました'),
  ('0d620a46-f4e6-58d6-b8ae-376c169bb01c', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-10-30', '17:30:00', null, '通常 / 穴掘りゲームの完成', '前回に引き続き写経で進めました。途中ちゃんと写しているはずなのにバグが起こり、おかしいと言っていたので、一緒に原因を探りました。ツルハシを振れないということだったので、それを動かしているコードはどこかな？と質問するとその場所を表示してくれました。その周辺のミスが怪しいよねと伝えると、変数のミスタイプが見つかり、無事直すことができました。座標を「-210+(乱数)*60」にするところは大事なポイントなので、乱数に色々な数を入れて座標の取る値を確認してもらおうとしました。しかし算数で習っていない負の数の計算で混乱してしまい断念し、乱数が変わると座標も変わるということだけ共有して終わりました。本編は全部できましたが、アレンジについては時間が間に合わなかったので次回やりたいです。', '穴掘りゲーム アレンジ？', '盛り上がり: 行き詰まるとやる気がそがれてしまいますが、それが解決した時は安心していました。'),
  ('c06ee832-2ddb-5598-b4ad-47e5f68b0cbe', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-10-30', '16:30:00', null, '振替 / プラットフォームゲームを進める', 'まずは前回の復習として背景スクロールの方法をどのようにやったか聞くと、クローンを作ってx座標を変えていくことを覚えていて、それを活用してプラットフォームを作り始めました。次にクマの放物ジャンプの動きを作ることを促しましたが、「大丈夫です」と言っていて乗り気ではなかったようです。そこでとりあえずは放物よりも楽な等速ジャンプで作ってもらいました。クマが取っていくリンゴについては、背景と同様にクローンを作って動かしましたが、「クローンを削除する」ブロックがうまく働かないなどクローン特有のバグが多くみられました。こちらから軽くヒントを出すと自分で考えて直すことができ、クローンの扱いには慣れてきたように思います。ゲーム性については、しばらく遊ぶとレベルアップしてそれを音声で知らせ、リンゴが増えていくという面白い仕掛けができていました。放物ジャンプや軽いバグなど修正の余地はありますが、ゲームとして成立するところまではいきました。', null, '盛り上がり: できることが増えてきていると思いますが、興味がもてない題材だとやはり練習したくないようです'),
  ('b8d1771f-054e-57e1-968d-e8a470e0ae72', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-10-30', '17:30:00', null, '通常 / プラットフォーマーセット：横スクロールまでやったので自由作品作成しかかり。先生とアイデア出しあいながら、作品つくっていきましょう', '前回までに背景スクロールにねこちゃんの変数ジャンプを組み合わせていたので、内容を確認したあとに要素を追加していきました。 ねこのコスチュームが変わるプログラムや、鍵を動かすプログラムを加えました。鍵の動かし方に困っていたので、背景のプログラムから動く速さを参考にするように伝えました。メッセージをうまく使って敵の出現をコントロールしたり、ねこのコスチュームを作ったり楽しく取り組めていました。最後はプログラムの動くタイミングの調節に苦戦しました。', null, 'タイピング: 集中して取り組めました。'),
  ('2b9626fe-8429-5d8a-b1a3-6286a5c9c446', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-10-30', '16:30:00', null, '通常 / 検定問題3級に挑戦', '40分かけて最後の部分まで取り組めました。答え合わせをすると、①やaなどの細かい内容はプログラムできていましたが、項目ごとの関連が苦手なようです。読み飛ばしや自分で考えすぎな部分もあり、出来はあまりよくありませんでした。「ずっと」「まで繰り返す」を読み落としがちです。 新しくスクリプトを作成するのか、つづきでプログラムをするのかを判断するのも苦手なようです。慣れが必要かな？', '3級検定類問', 'タイピング: 集中して取り組むことができました。丁寧です。'),
  ('dae55916-e5d6-5f23-bc33-d6a628a692c8', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-10-30', '16:30:00', null, '振替 / ゾンビをたおせ続き', '前回作ったプログラムが消えてしまっていたので、イチから作り直すことにしました。（おそらく消えてしまった原因は最後のパソコンを拭くときの雑な動作だと思います）ディラックくんの左右に動く動作、ゾンビの動きもうまくプログラムできていました。角度の意識があったのがすごいです。 ビームのプログラムは少し手こずりました。やりたいことをイメージはできているようですが、ブロックにある言葉で置き換えるのはもう少し練習が必要な様子です。次回はあたり判定などをつけていきたいです。', null, 'タイピング: 長い間すごい集中していました。ミス率にこだわりがあるようで、間違えないように頑張っています。'),
  ('77651b53-3fad-53b7-a06d-c6b9d2e35766', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-10-28', null, null, '通常', '前回遊びたいアイアンマンのジャンプゲームをリミックスしてくれたものを写経しながらつくりました。コード全体の難しさは思ったり難しいところが少ないので、集中して取り組めていました。今回はコードの1つ目の塊で作り途中になったので、それが出来上がったら、とうきくんみたいにどうゆう動きができるようになったか確認してみるといいと思います。', null, '時間帯: その他
盛り上がり: アメコミやスターウォーズなどが好きみたいです。'),
  ('d29a7786-5bfb-55b7-b425-f75e9794c8d2', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-10-28', null, null, '通常 / よこすクロームを作ろう', '1度クローン型の横スクロールはやったことあったらしいので、メッセージ型の方をやりました。作り方を道筋を教えると、ある程度は自力できました。ただ、「まで繰り返す」の後にメッセージを送ってほしいところを、なかに「もし」を使うミスを犯していました。このミスは、検定をやっていれば、一度は通るミスだったので、コードの意味を含めてフォローしました。背景をループさせるときもメッセージの送り相手が区別がしっかりできていたので、スムーズにできました。これで作品に生きればいいと思います。', null, '時間帯: その他
タイピング: 不安定ながらもお得になるようなタイプができていました。
盛り上がり: 音符のコードで作った曲のクオリティーがすごかったです。'),
  ('aa2f1737-9cb2-5cce-9df6-a756153c6278', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-10-24', null, null, '通常 / 検定問題４級 応用課題②', '時間内に問題を終わらせることもでき、間違っていた箇所も今回初めてやる箇所のみだったため、検定の難易度に対しての実力は十分に足りていると感じました。どこがどのように間違っていたのかも、解答の際にしっかりと理解をすることが出来ていたので、新たな内容であってもすぐに飲み込むことができるのではないかと感じました。', null, '時間帯: その他
タイピング: 様々なモードに挑戦してどれくらいまでできるのかを試していました。タイピング速度は速かったので、正確性を突き詰めていくことでさらにスコアを伸ばせるのではないかと感じました。
盛り上がり: 今までにやったことのない箇所がわかった際には自分の中でちゃんと納得していた様子でした。'),
  ('609d4c02-3bc0-5dd5-bc09-c49fe153fb0e', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-10-28', null, null, '通常 / 3級検定練習', '30分時間かけて解いたかがまだ2割ほど解き終わっていなかったから、10分延長して解きました。出来具合はまで繰り返すあたりにところに悩んでしまったそうです。実際、不等号の向きが違ってうまく動いてなかったから、手が進んでいなかったそうです。ほかは「ではない」のブロックを使ったことがなくて悩んでいたそうです。それ以外できていたので、あとはわからない所は速く切り捨てて進むことが大切だと思います。', null, '時間帯: その他
タイピング: 五本指で使って打てていました。
盛り上がり: スイカゲームうまかったです'),
  ('40ae3e8b-6af1-5de6-b4af-05611986b51a', '28d52d6e-7571-5090-a2d9-492c997b719e', null, null, '2023-10-28', null, null, '休み（振替対象）', null, null, '時間帯: その他
備考: 11/30に振替予定'),
  ('7d1ffd6f-b30c-541c-a135-d4762cac814b', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, null, '2023-10-28', null, null, '休み（振替対象）', null, null, '時間帯: その他
備考: 11/30に振替予定'),
  ('4a953e83-51c0-5633-a3d6-fb37507b8514', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, 'd61e30aa-9c3d-5cd4-8626-4f13fd854b99', '2023-10-28', null, null, '休み（振替対象）', null, null, '時間帯: その他'),
  ('eb8fa1da-e9f7-59f6-b062-61dcc8537989', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, null, '2023-10-28', null, null, '休み（振替対象）', null, null, '時間帯: その他'),
  ('b6fd6612-78d8-53c6-8bf5-c3bb83d034cc', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, null, '2023-10-28', null, null, '休み（振替対象）', null, null, '時間帯: その他
備考: 10/30に振替予定'),
  ('c999bc45-cc0e-5813-92b4-1e6f9654f006', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, null, '2023-10-28', null, null, '休み（振替対象）', null, null, '時間帯: その他
備考: 10/26に振替済み'),
  ('835956b6-04ad-54bb-88cf-f53766606012', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, null, '2023-10-28', null, null, '休み（振替対象）', null, null, '時間帯: その他'),
  ('24f353c3-94d7-580d-81c4-713516ad212c', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, null, '2023-10-21', null, null, '通常 / 検定問題3級に慣れる', '基本的にはよくできています。 どこまでを条件分岐や繰り返しの中に入れるか、というところで小さなミスをすることがあるので、問題文の書き方もヒントにして丁寧に解いていくことを勧めました。', null, '時間帯: その他
盛り上がり: 検定対策で、毎回違うタイプの作品が作れるのをそれなりに楽しめているようでした。'),
  ('11b92aaf-369d-50fc-832f-a3abc0aa16f2', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, null, '2023-10-21', null, null, '通常 / 検定問題3級に慣れる', '順調に取り組めています。', null, '時間帯: その他'),
  ('6b063293-520b-5aaf-88da-ad52d3334ce9', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-10-27', '18:40:00', null, '通常 / 3級検定問題①', '時間内に全部は終わらなかったようなので、5分ほど延長しました。変数と制御が複雑な部分のプログラムが少し難しかったようですが、他の部分（～ではないまで待つ）はあまり困らなかったようです。冷静に考えればよくできる印象です。アレンジのことも伝えました。犬を追加しようとしてくれましたが、時間がなく最後までできていません。', null, 'タイピング: 何度か練習した後に本番でした。'),
  ('89a88a76-872f-5fd1-9e1c-8e01318394fe', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-10-27', '17:30:00', null, '通常 / 大会出品作品作成', '今までつくっていた作品が消えてしまったようです。取っておいた使えそうなコードを元に、イチから作り直していました。素材や音を準備し、重力を付けた動きのプログラムを作成していました。重力の言葉の意味を確認したり、効果音辞典を紹介したりしました。 （出品予定の大会） https://pcn.club/contest/nominate13.html PCNこどもプロコン スケジュール 11/中旬（中間試験終わる頃まで）オープニング作る 11/末 全体像をある程度作る 12月いっぱいで完成 次回以降も、スケジュールは意識させて毎回確認したいです。', '必ずスケジュール確認', 'タイピング: 集中して取り組んでいました。
備考: （出品予定の大会） https://pcn.club/contest/nominate13.html PCNこどもプロコン'),
  ('37cf5c76-42c6-5582-8a83-76c00d731602', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-10-27', '17:30:00', null, '通常 / 前回の復習＆もう1種類のスクロール 作成中の作品を一緒に確認', '前回の振り返りをした後、小技の背景スクロールに挑戦しました。見本通りに作ったあとに中身を一緒に確認しましたが、背景が動くのは面白いみたいですが、その仕組みにほぼ興味がない様子でした。最後にネコを設定して画面上を歩いているように見せていました。地面のプログラムも、「地面にあたるまで落ち続ける」というヒントを渡すと全てひとりでプログラムしていました。ちょっとジャンプしているところがポイントです。 授業の後半は自分で作っている作品を見せてもらいました。元ネタをリミックスしているようなものの、ミニゲームの内容は自分で考えているそうです。かなりの内容のプログラムを読んだあとに追加修正していてすごいです。次回までに卵を使ったミニゲームを作ってくるそうです。', null, 'タイピング: 「ふつう」に取り組んでもらいました。
盛り上がり: 自分の作ってきた作品について話すのが楽しみなようです。'),
  ('8776a61e-b7d1-5acf-a8ea-f54aa2eb3942', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-10-27', '17:30:00', null, '通常 / 放物線ジャンプと横スクロールを組み合わせよう', '1週あいたので、まずは振り替ええて放物線ジャンプを思い出してもらいました。たっちゃんと同じく段差に登ることを苦戦していたが、色判定でなんかできそうな発想はできていました。そこで、ジャンプの上りと下りでコードを分けてあげることをヒントで出したが、悩み止まっていました。０で切り替えることは感が付いたがコードの組み方がわからなかったので、押しててあげもました。出来上がった後もそのコードがどうゆう意味を果たしているか聞いて、忘れさせないようにしました。', null, '盛り上がり: 最後はるくんとみせあってそれぞれのアレンジを見ました。'),
  ('c5a61add-403d-54d0-8d58-1498fa85766c', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-10-27', '17:30:00', null, '通常 / 気分転換にイライラゲームを作ろう', '検定が続いていたので、最初に検定練習するか気分転換に簡単なゲームをするか聞いてみたところは、後者を取ったのでイライラゲームを作りました。作ることは簡単にできるが、コスチューム画面のいろいろな操作が学べるので、よい機会になったと思います。迷路の背景も独自のルートになっていて難しくなるようなアレンジができていました。ゲームオーバー・クリアの画面も凝っていて楽しんで作れていました。', '検定練習', 'タイピング: 正答率が高かったです。
盛り上がり: 終わった後けいとくんとコスチュームの大きさを大きくして通れる限界を試していました。'),
  ('ab1476cf-145e-58a7-9604-c0c2e43d7b66', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-10-27', '16:30:00', null, '通常 / 検定見直し（応用課題3）そのあと応用課題5へ', '最初に時間をとってプログラムを確認してもらいました。ミスとして、①日本語で説明される大小（より小さい）、②思い込みでの付け足し、③数字ミス、④プログラムの順番ミスがありました。特に①に関してはあまりよく理解できていなかったので、身長を例に具体的に考えてもらいました。④に関しては「まで繰り返す」があると混乱するようです。応用課題の中でも難しい問題でしたが、基本的な部分はよくできていたと思います。 余った時間で等速ジャンプの復習をしました。動き、見た目の部分を別のスクリプトでつくるメリットを説明しました。また変数を自分で設定し、挑戦していました。まだ、ジャンプで下るときの変数の使い方がうまくいっていません。', '（ジャンプで下るときの変数の使い方）', 'タイピング: 集中して取り組めました。ミス率も少なかったです。'),
  ('39fc688b-9168-5afd-aefc-22443b469ec4', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-10-27', '16:30:00', null, '通常 / 3級検定問題①', '後半が少し時間がかかっていたようです。ドラゴンの動きがうまくプログラムできず、かなり悩んでいましたが、時間いっぱいしっかり取り組めていました。（最後は頭がぼーっとしていたようです）本人が答え合わせは次週以降がいいと言っていたので、さらっと軽く見直しました。うまくいかなかった原因として、①や②の関係を整理できていなかったことがありました。かたまりごとのプログラムはおおよそできていたので、全体を考える力がもう少し必要かなと思います。', '3級検定問題①答え合わせ', 'タイピング: 集中して取り組むことができました。'),
  ('e225b3aa-fb50-5318-8ca1-45167ccc3fbc', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-10-27', '16:30:00', null, '通常 / リストへの理解', '1000問自動作成計算問題を作っていきました。タイピングに集中しすぎて疲れ気味だったので、ノーヒントで考えてみても手が進みませんでした。とりあえず、考え方の道筋を伝えてあげたが、生後判定のときに足した数の表現の仕方が上手くできず、その後は動画見てもらいました。リスト使わなくてもできるじゃんと思っていたが、複雑になったときのしやすさを学ぶためと軌道修正はしておきました。かなりだれていたので、都道府県の問題はやれませんでした。', null, 'タイピング: 先週やり損ねた和文Aを取り組みました。
盛り上がり: いつもやっていたゲームがなくっていたそうです。'),
  ('97e57c98-5505-532b-b9bc-e1dd93a1da7c', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-10-27', '16:30:00', null, '通常 / 段差を上るジャンプを身に着けよう', '前回足場に乗れずに困っていたので、いきなりコードを作るのはなく、理解しやすいためにアルくんの冒険２を動画を見ながら作りました。ジャンプの動作で上り下りで起こる条件のクイズに答えられていたので、理解はできたと思います。段差に登ることを等速から放物線ジャンプに作り替えることは苦戦していました。放物線ジャンプで上り下りが変わる部分の変数の値を意識するのが難しく教えるだけな感じなってしまいました。ただ、作り終えたジャンプで見ると喜んでいて、アレンジマグマに落ちたら止まるような仕組みを作れていてゲーム性は上がっていました。', null, 'タイピング: 毎パソの効果もあってスコアが伸びていました'),
  ('fdea8fb1-9741-50b1-b5aa-b348da5eb373', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-10-21', null, null, '通常 / スキル整理', 'ダイヤの動きは前回できたので軽く振り返り、プレイヤーや敵の動きの作成に入りました。一から考えるのは難しそうだったため写経の形をとり、「マウスに向ける/行く」、「もしーに触れたなら」の意味を重点的にチェックしました。ゲームオーバーのところが作りかけですが、その際使うメッセージの流れの理解が曖昧に見えたので次回確認したいです。', '続き(もうすぐ完成)', '時間帯: その他
盛り上がり: スプライトをいろいろ好きなものに変えていて、自分なりの世界観ができていました'),
  ('55c1420f-8dba-5727-a2b8-e8e7457bafc1', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-10-21', null, null, '通常 / プラットフォームゲーム', '作れるゲームの幅を広げるという目標を再確認し、クローンを使ったスクロールから始めました。どのタイミングでどこにクローンを出すかが難しいので、紙に書きながら一緒に考えました。しかし複雑なクローンの動きにはあまり慣れていなかったようで、一応コードは書けたがバグが出て直らないという状況でしばらく考えていました。そこで自分のコードとお手本のコードを見比べさせ、どこが違っているのかを見つけてもらいました。「クローンと本体の処理が同じところに混ざっていた」などの間違ったポイントがわかり、少し納得した様子でした。 その後、その背景スクロールを使ったゲームの製作を始めました。クマが走ってリンゴを取っていくゲームとのことで、習得したスクロールを早速リンゴにも応用していました。', 'プラットフォーム続き', '時間帯: その他
盛り上がり: 少しずつ思考力が身についてきていると感じます'),
  ('09575e25-4cbc-56c6-9c38-95fafcb1b554', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-10-20', '17:30:00', null, '休み（未対象）', null, null, null),
  ('9bbf3881-9f72-530e-b8e8-893452cb0687', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-10-26', '17:30:00', null, '振替 / 検定に慣れていく', '時間に余裕を持って終わり、答え合わせをすると2か所のケアレスミスがありましたがその他は合っていて、本質的には理解しています。解けたらミスがないかもう一回見直そうとだけ伝えました。アレンジをしなかったとのことなので理由を聞くと、「僕はまだ難しいアレンジはできない」とのことだったので、簡単なものから始めることを促しました。いくつかアレンジのヒントになりそうなものを伝えると、キャラクターに触ったとき音が出るようにしていました。', null, 'タイピング: 一番楽な「伸ばし棒(-)の練習」でふざけていました
盛り上がり: 何かにつけて自信のなさそうな発言をしますが、ポテンシャルはあると思うのでサポートしたいところです'),
  ('f393d6c2-65cf-59a9-ba66-00ed81675a88', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-10-21', null, null, '振替 / マウスについていくスプライト、ランダム出現 など', 'ダイバーをマウスについて行かせるのは、少し考えていましたが「マウスに向ける」「マウスに行く」を組み合わせてできました。ダイヤのランダム出現、ゲームオーバーの処理などは以前やったことがある要素なのでできていました。クラゲを動かす時、歩数と回転角度を色々変えると面白い動きになるのでアレンジしていました。ダイヤを取った時やゲームクリアの時の演出にはあまり興味がなさそうでやりませんでしたが、ゲームとして成立させることはできました。', null, '時間帯: その他
盛り上がり: ゲームの見た目の部分よりもゲーム性のある部分の方が興味を持てそうです'),
  ('cb183de3-dfde-58a0-b2cd-06b999dc97d3', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-10-26', '17:30:00', null, '通常 / メッセージの練習', 'メッセージのついて理解があやふやだったようなので練習しました。「メッセージを送る」、「メッセージを受け取ったとき」というブロックを使うことはわかっていましたがごちゃごちゃの順番で置かれていました。そこで「〇〇が□□に『～して』と合図する」というように、具体的なイメージを使いながら時系列を追っていくと、納得した反応をして正しい順番に並び替えられました。1問目が終わったところで少し疲れたようで2問目に行くのを渋っていましたが、しばらくすると「スプライトをくるくる回してみたい」と言ったので一緒に作り、せっかくなので1問目と同様にメッセージを使って完成させました。', null, 'タイピング: 頑張っていました
盛り上がり: 一度興味をもった題材だとモチベーションをよく保てます'),
  ('d95ee68a-8ecd-5eb1-8f00-0a6844702eae', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-26', '16:30:00', null, '通常 / 検定問題のいろいろなパターンに慣れる', '検定問題には積極的に取り組んでいます。今日も来てすぐ始めました。 条件分岐の中に〇回繰り返しが入ると、その中に続きのブロックを入れる傾向があるので、問題文の改行などにも注意して読むことを勧めました。 台詞を消す、というブロックを探してとまどっていました。今日覚えたので、今後は大丈夫と声掛けをしたら安心したようでした。 画像効果もあまり使ったことがないようでしたが、問題文を読みながらブロックを探し出すことができていました。', null, 'タイピング: 授業開始直後に来室したため、すぐにプログラミングを始めたがりました
盛り上がり: 難しい～と何度かぼやいてはいましたが、あきらめないで最後までやりきっていました。 今日覚えたことも自分で復唱して、もう大丈夫！と得意そうにしていました。'),
  ('b17935d9-486a-5f69-850e-93bf522541d2', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-10-26', '17:30:00', null, '通常 / 検定の見直し、リストの練習', 'まずは検定の見直しをしました。できたところには"OK"を、わからなかったところには"?"を書いていて、整理しようとする意志が感じられました。じゃんけんで「自分の手が相手の手に勝つ」をコードで表現するのが難しくてできなかったそうなのでヒントを出しました。自分が勝つパターンは3つあるので、紙に書きだしてみると理解したようで、「かつ」や「または」を自分で適切に組み合わせてコードが書けました。', null, 'タイピング: 相変わらず高速のタイピングです
盛り上がり: 前回は苦戦したようですが、今回は落ち着いて直すことができたと思います。'),
  ('e40196e6-d7ff-52c0-a370-1b278a046a24', '57f45872-1f3e-5540-b676-bf9023444e39', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-10-26', '16:30:00', null, '通常 / ピンポンゲームの続き', 'ゲームオーバーの処理は順調に作れました。そのあとスコアをつけましたが、変数は一度やっているので、流れを誘導しながらやってみました。変数をどうするのか、そのブロックをどこに入れるのかを問いかけていくと、きちんと答えられてコードが書けました。 ピンポンゲームは完成したので好きなゲームをアルスタジオで探してもらうと、ドーナツキャッチに興味を持ったので自分で作ってもらいました。難しかったので写経しながら進めましたが、不等号が出てきたので意味を確認すると今算数で習っているとのことでした。何だったっけと言っていましたが、少しヒントを出すと思い出すことができました。', null, 'タイピング: 集中していました。
盛り上がり: 大好きな野球をピンポンゲームの題材にしていました'),
  ('fccd1619-13bc-5d93-b028-5b4907af2f3f', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-10-26', '16:30:00', null, '通常 / 楽しみながら問題慣れする', '問題を解きましたが、この前のよりも難しいと言っていたので、「応用問題でレベルは上がっているから焦らないでできるところまでやろう」と伝えました。答え合わせをすると、「もし～なら」や「～回繰り返す」などの制御ブロックの中身の範囲が違っている場所がありました。検定問題文の独特な書き方に慣れていないようなので、「どこからどこまで？」を一緒に確認しました。また、「～度に向ける」と「～度回す」を間違えていたので、具体例を使って問いかけながら違いを確認すると、全然違うということを納得しました。', null, '盛り上がり: 少し難しくても、モチベーションを保ったまま頑張れていたと思います。'),
  ('31f7367b-5bb7-5334-8088-55484c45e052', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, null, '2023-10-26', '16:30:00', null, '休み（未対象）', null, null, '備考: 10/17分の振替予定日'),
  ('1579beb4-e070-5dba-b17b-779752f82316', '7d01236e-620e-5177-a6f4-af325a582aae', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-10-24', '17:30:00', null, '通常 / 検定4級応用課題', '検定問題の本文については、間違うことなく完璧に作成することができていました。しかし、アレンジをする時間はそれほど残っていなかったようで、これからしたいアレンジを答え合わせをした後に試していました。文章を読み取る力はかなりあるので、全体的なペースを上げての作成であれば、アレンジ問題も時間内に取り掛かることができるのではないかと感じました。', null, '盛り上がり: アレンジの作成で、自分のやりたいことがあらかじめ固まっていたようでサクサクとアレンジをすることができていました。思い通りの内容に仕上がったらしく、アレンジ作品について細かく説明してくれていました。'),
  ('ec05fbc3-df31-5830-b779-0febe23c2984', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-10-24', '17:30:00', null, '通常 / タイピング本番 検定問題3級②', '検定問題の作成はかなり早く終えることが出来ており、残り時間が半分ほど残っている状態でアレンジへと取り掛かっていました。作品の内容に関しても、資料の読み間違いが少しありましたが、ほとんど間違うことはなく作成することができていました。時間にはかなり余裕があったので、ゆっくりと解くことができれば完璧に作成することができると思います。', null, 'タイピング: 何度か練習をして本番に臨んでいました。速さと正確性もそれほど問題があるようには見えなかったので、本人の納得のいく点数が出ると思いました。
盛り上がり: 作品のアレンジの部分に関しては、本人もかなり満足していたようで完成してから何回も遊んで楽しんでいました。'),
  ('106a5156-3431-5f8b-9787-2620c316a40b', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-24', null, null, '通常 / 定義の使い方の確認をする', '前回の続きの動画視聴から始めました。定義の使い方、定義を使う理由なども確認しつつ、特に疑問点もないようで、スラスラと終えていました。 20分くらいで上記を終えていたので、次の課題の希望を聞いたところ、よくわからないけどプログラミング的なことをやりたい、とのことで、Monacaの最初の教材「おみくじ」の概要をプログラム部分を見ながら説明し、おみくじが引くたびに変わる部分を抜き出して、そこだけフローチャートを書いてもらいました。 その後、Scratchで同じおみくじゲームを作成しました。Monacaでは乱数の結果によって画像ファイルを変えていましたが、ここは自由にアレンジするようにさせたところ、コスチュームで対応していました。目的意識があったためか、ひいろくんにとっては簡単な課題でしたが、一生懸命取り組んでいました。', null, '時間帯: その他
盛り上がり: 久しぶりにScratchでの課題が続いていますが、一応何のための課題かを毎回説明しているせいもあるのか、だれることもなく頑張ってくれていました。'),
  ('c6c31f60-da32-5f21-bd34-e25ed4250204', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-10-24', '16:30:00', null, '通常 / タイピング本番 検定問題4級応用課題1', '問題の中ですべてを止めるのブロックで三種類の中からどれを選択するのかをかなり悩んでいました。それぞれがどのような働きをするのかがイマイチ理解できていなかったので、説明したところすぐに理解することができていました。それ以外の箇所に関してはほぼ完璧にできていたので問題はないと感じました。', null, 'タイピング: 今回が本番ということもあり、練習はかなり長めに取り組んでいました。本番でも、集中して自分本来の実力を発揮できていたと感じました。
盛り上がり: 問題作成が終わった後に、アレンジをしている際新たなキャラクターを背景が変わったタイミングで出現させ、喋るというプログラムを作成しており、作成に苦労しているようでしたが解決することが出来ていたので思っていたものができて満足していました。'),
  ('f9d8ec68-8e2e-5513-a35a-cd9641e288bd', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-24', null, null, '通常 / 基本スキルの確認、習得', '初めに課題として用意していた「【Prg】12 モンスター・ハントゲームを作ろう！」を見せたところ、それを一から作ることにしり込みをしてしまったため、作成のための文章がある方がやりやすいかと検定問題を見せたら、すぐに食いついてきました。 とりあえず短めの問題からということで応用課題1を準備し、最初の数問を一緒に解いてみたところ、その後は自分で進めることができていました。 最近のしょうたくんの様子からみても、今日は最後まで飽きずに楽しそうに取り組めていたと思います。', null, '時間帯: その他
タイピング: タイピングへの意欲はあまりなかったようですが、今日は「あいうえお」だけ、と促したら、「それくらいできるよ」と得意そうに始めていました。
盛り上がり: すべて解き終わってから、これは試験問題だったと教えたところ、とても嬉しそうに、「この問題は記念にもらっていい？」と言っていました。挑戦してきちんとできたことで、達成感も味わえ、自信にもなったようでした。
備考: お父さんに今日の報告をしたところ、家では検定を受けてみたいと言っていたとのことで、親子共に嬉しそうにしていました。 もともと本を読むのが好きで、文章を読むことは苦にならないようです。 台詞の入力にローマ字表がないとできない、と心配していましたが、4級はセリフのブロックが用意されていることを説明したら、安心したようでした。'),
  ('3753e9cd-739e-5254-94c9-488a8ec0aeeb', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-10-24', '16:30:00', null, '通常 / アルスタジオレッスン/ゾンビをたおせ1', 'レッスン動画を見ながらの作成でしたが、今回は自分が手伝ったりアドバイスを出したりすることなく、1人でほとんどの内容を完成させていました。動画の内容をしっかりと読み取ることはできていたので、次からの作成でも基礎的なことを理解はしていると思うので、どのように自分の中で噛み砕いて理解していくのかが重要になっていくのではないかと思いました。', null, 'タイピング: タイピングではまず間違わないようにすることを意識して取り組んでいたので、このままの調子で続けていけば上達していくのではないかと感じました。
盛り上がり: 作品を完成させていくにつれて疲れた様子も見せていましたが、自分のやっていることが進んでいるということをより感じられていたと思います。'),
  ('f81e1ad0-de98-5de3-a1ec-34e2a6ae6687', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-10-24', '17:30:00', null, '通常 / 【小技】体力ゲージをつくる イメージがわきやすい教材で定義の使い方の確認 https://app.arstudio.fun/contents/33714', 'ゲーム自体にあまり興味はなさそうでしたが、定義の確認も兼ねて取り組みました。描く機能はほとんど使ったことがなかったようですこしびっくりしていました。見本を見ながら作ってもらい、最後にゲージ部分の定義の使い方とプログラムの内容を確認しました。変数が使われている部分もありましたが、内容はしっかり把握することができていました。定義の使い方も大丈夫そうです。', null, 'タイピング: 取り組んでいました。'),
  ('f80eddb4-4ed0-5be0-ae74-db1f261d6448', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-24', '16:30:00', null, '通常 / ゲームの完成度を上げる', 'スクロールとジャンプはできているので、ゲームの完成度を上げることを目的に始めました。 前回、ジャンプしただけでスコアが変わるため、ある得点になったらゴール用の旗が出てくるのがうまくいかなかったため、爆弾を確実に飛び越えたときにスコアが加点されるにはどうしたらよいかを考えるところから始めました。 いつも通り、「じゃあ、どうすればいい？」と聞いてきたので、爆弾の動きに着目するようヒントを出すと、「爆弾がこのへんまで来たら飛び越えたことになる？」というところまでは導き出すことができました。ただ、ここからブロックに置きかえるためには、「左端まできたということはどういうこと？」などのヒントが必要でした。 スコアが思い通りにできてからは、旗スプライトの表示、スプライトの動きを止める、クリアスプライトを出すなどの一連の動きも自分で想定して作成することができました。', null, 'タイピング: 20分くらい、とても集中して取り組んでいました
盛り上がり: ゲームの完成度を上げるためのアイディアを考えるのは、さらちゃんの好きな分野なようで、楽しそうに考えていました。それをブロックにするための質問は多かったものの、集中して完成までもっていけたと思います。'),
  ('252ed817-2023-50b5-98cb-2a8d77db6a07', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-10-24', '17:30:00', null, '通常 / 検定問題1級応用課題1 自宅でやってきたようなので、答え合わせ すぐに済むようなら、応用課題8、9、10から選択', '全体的によくできていました。問題に「〇回繰り返す」があるときの次のプログラムの場所のミス、日本語の順番の把握ミスなどがありました。修正部分もミスがあったので自分で考えるように促しましたが、ひとりでは気が付きにくかったようです。アレンジも考えにくかったようなので、難易度の設定を提案しました。 また定義をやったことがない様子だったので、体力ゲージやその他作品を参考に定義の使い方をおさらいしました。難しすぎるものではないことが分かってくれたようです。', '今日は応用課題10の問題を持ち帰りました。やってくるかな？', 'タイピング: 集中してとりくめていました。'),
  ('74f71bc8-e26a-5f83-ab8b-0efe62cd0313', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-10-24', '17:30:00', null, '通常 / 【単元】リスト＿完成版 都道府県と県庁所在地クイズ', '一度完成品を見ながら自分で作成してみて、その後に一緒にリストの内容について説明していきました。今回の説明で、リストを使うことにおける利点と変数として「i」を使い、どのような動きをするのかとなぜ「i」を使うのかを説明していきました。内容理解はかなり早く、今回説明した内容に関してはちゃんと理解することが出来ていたようなので、リストを使った他の問題にチャレンジしてみても良いと思いました。', null, '盛り上がり: リストの内容を以前動画で視聴していたので、飲み込みが早くすぐに理解することが出来ていたので、満足していました。'),
  ('644d2e9f-a0fd-525f-bfbb-f69aa910e2f0', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-21', null, null, '通常 / 基本操作コースの中のスキルを複数獲得する', '今日はお家で「教室の表にスタンぷを押す」と約束してきたらしく、時間になったらゲームを切り上げて、どれかを進めたいと自分からファイルの表を出してきました。 内容について説明すると、「音楽をやってみたい」とのことで、基本操作コース05の01から04まで進めました。 「音」グループのブロックと「おんがく」グループのブロックの両方を使って、とても楽しんでリズム作成をしていました。 それなりに集中して30分ほどコースを進めていましたが、急にそこで電池が切れたようで、5分休憩を入れました。 休憩後はゲームを続けたそうなそぶりも見せましたが、休憩5分の約束だったと念押しをすると、名残惜しそうではありましたが、きちんと切り替えることができました。 後半は、興味のあるゲームをリミックスしては中身をのぞいて、スプライトを変えたりすることを楽しんでいました。', null, '時間帯: その他
タイピング: 初回のあたりは慣れてきて、Sが出せるようになっています。
盛り上がり: やりたいことは説明しきれないくらいたくさんあるようで、終始ハイテンションでしゃべっていました。'),
  ('f7ae2241-586a-5473-893c-09dd13d0d851', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-21', null, null, '通常 / 基本的なスキルを確認する', '今日は知りたいブロックが3つある、と、教室で質問したいことを明確にして来室しました。 「ではない」については『コード探求【ではないまで待つ】 レース順位ゲーム』を見せたところ、すぐに、連射防止のときのやりかただ！と読み取って、これまで自作でも使ったことがあった、とすぐに思い出して理解していました。 「かつ」「または」の違いについては、『【Prg】17 かくれんぼゲームを作ろう！』をプレイしてコードを見せてみました。その上で、もともとのコードで「かつ」を使っていることを「または」に変えさせて、動きの違いを見つけさせました。少しPlayしてからすぐに、「どこでマウスをクリックしても、見つかったになる」と気づくことができ、「かつ」と「または」の違いを自分で説明できるようになりました。 最後の質問は、条件分岐の「でなければ」の使い方だったので、『【Prg】09 ネコとネズミの追いかけっこ、』をプレイしてからコードを見せ、ネコの動きを口頭で説明した後で、条件分岐のところを削除して自分で作らせてみました。 これも、条件を満たした時とそうでないときの動作の違いはすぐに気づいて、自力で作成できていました。 3つの質問がクリア出来て、満足そうに「少しだけ課題を進めたい」と、『基本操作コース08_さあ踊ろう』の6、7、8をやりました。画像効果で初めて見るものもあったらしく、楽しそうでした。', null, '時間帯: その他
タイピング: まだちょっと苦手意識があるようです。タイピングをするときは、やすのりくんと席を離した方がよいかもしれません。
盛り上がり: 疑問に思っていたことを教室でクリアにできるのがとても満足そうでした。 自分の課題が解決すると、素直に教室の課題を進めようとする姿勢も良かったです！'),
  ('0f9dbd62-ac8f-568e-8350-91e4af246544', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-10-23', '16:30:00', null, '通常 / ジャンプ、スクロールの復習 ゲームの作成', '前回までに学習していたジャンプと背景スクロールの復習と、この二つを用いた新たなゲームの作成をしていきました。復習に関しては、ジャンプに関しては完璧でしたが、スクロールは少し疑問が残っているようだったので、解決してからゲーム作成に取り掛かりました。ゲームに関しては、背景から自分で作成していて、かなり手の込んだ作品を作ろうとしているようでした。敵キャラクターのジャンプしてから元いた場所へ着地するまでが難点となりそうな作品でした。', null, '盛り上がり: ゲームの背景とゲーム性そのものについてかなり悩んでいました。自分の納得のいくような出来になるように、かなり多くの要素を入れようと楽しそうにアイデアを出していました。'),
  ('cfe934dd-5a64-584b-8b92-e55383141eec', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-10-23', '17:30:00', null, '通常 / 検定一級問題の作成', '検定問題の解答を作成していきました。かなりの量があったので終盤はかなり疲れていた様子でした。今回で本体の問題の内容はほぼほぼ完成しているので、次回からは今回の続きと完成した作品にアレンジを加えていく作業が主になると思います。作品の内容に関しては、解答を見ながらの作成でしたが、かなりの理解度で作成をしていたのでおおよそ理解はできていそうでした。', null, 'タイピング: タイピングの正確性はかなり高かったので、今後は速度を重点的に鍛えていけば、かなりの高得点が狙えると思いました。
盛り上がり: 正答例でもかなりの量がある問題なので、少しづづ取り組んでいき順調に量が減ってきていたので、達成感はかなり感じていました。'),
  ('48caef95-990a-5747-aa6f-bbf467b33fda', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-10-23', '17:30:00', null, '通常 / 背景スクロールの作成', '前回でジャンプのプログラムをやっていたので、今回は背景スクロールのプログラムを作成していきました。一つの素材をクローンしてずっと続くように作るには、クローンをどこに配置して実行しているのかを重点的に教えていきながら作っていきました。完成した後は、今回のスクロールと前回のジャンプを合わせてゲームの作成をしていきました。内容としては、キャラクターが右端からスクロールで迫ってくる敵キャラをジャンプやしゃがみで回避しながら左端からスタートしてゴールまで辿り着くというものでした。', null, 'タイピング: 今回はかなり調子が良く、正答率もかなり高く維持しつつ最高スコアを出すことに成功していました。今回のタイピングにはかなり満足していました。
盛り上がり: ゲームの作成にあたり、どのようなゲームにするのかを悩んでいました。ジャンプした時の当たり判定としゃがんだ時の当たり判定がシビアなので、試行錯誤しながら作成していましたが、楽しそうに作成していました。'),
  ('9ca09c54-7ebe-5f0b-84c3-e8429e35c6be', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-10-21', null, null, '通常 / アイデアを取り入れつつ自由作成', '最初に【Prg】08 海にしずんだダイヤを探せゲームを作ろう！ を遊んでもらって自由作品のアイデアに取り入れることを促しましたが、あまり合わなかったようで、2,3回遊んだだけで終わってしまいました。その後は前回までのゲームの続きを作りました。今日は回復アイテムを追加し、「もし～に触れたら」を使って動作を作りました。ゲームの構想については前回までと同じように、新しいアイデアをどんどん話しています。', 'こうしろうくんが作りたいゲームに近い内容のゲームを、PRGなどで探して提案する', '時間帯: その他
盛り上がり: 「一度作り始めたゲームは何があっても終わりまで作る」と言っていて、相変わらず気持ちがかなり強いです。また、あしらわれたり、自分の言ったことが理解されなかったりすると嫌がってしまうので注意が必要です'),
  ('39efd124-435f-57a3-9842-e5ac851df535', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-10-21', '16:30:00', null, '通常 / 【単元】リスト 都道府県と県庁所在地クイズ', 'リストについての有用性と定義についての可視性についてを学習していきました。都道府県では、リストがなぜ必要であるのかと、変数「i」がどのような働きをしてなぜ使われているのかを理解することが出来ていました。定義については、前回作成したものを定義を使い、より見やすくするという工程を理解することが出来ていました。応用として、本日作成した都道府県の作品を定義を使いより短いコードへと作り替えていきました。', null, '盛り上がり: リストと定義とはなぜ必要で、どのような場面で使われているのかを理解していて、今後やっていくJavaScriptにも関係してくるということも理解できていました。'),
  ('d04ec2bd-7156-5193-ac89-a90f8b374953', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-10-21', null, null, '通常 / 【Prg】08 海にしずんだダイヤを探せゲームを作ろう！', '今回の単元では、ランダムに移動するコードを座標を使って指定の範囲内で出現させるという内容で作成しました。このランダム出現のやり方は初めてでしたが、説明したところすぐにどのようになっているのかを理解することが出来ていました。結果、時間内に完成させることが出来ていました。エフェクトを使ったコードをかなり気に入ってアレンジをしている際に使おうとしていました。', null, '時間帯: その他
盛り上がり: 正答例であるコードとなるには、どのようにコードを作成していくのかを考えていき、自分でどのようになっているのか理解できたときは頷いて納得していました。'),
  ('3cd378a6-a940-5f56-bb7d-71effb64399f', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-10-14', null, null, '通常 / 教材にのっとり基礎をしっかり進める', 'これまでロボットの振替で体験的に参加していたので、最初はスキルアップしたり教材をやるという意識が皆無でした💦 教材のファイルの中身をプリントアウトしていなかったので、急ぎカードで基本操作コース02の名前を動かそうを説明。 他の子の作品を見せて名前を動かす作品を作ることを伝えたが、まだ具体的なイメージができていない様子だったかも。', 'いっぺんにたくさんの種類のブロックをいじったので、いっぱいいっぱいだったかと思う。次回は、全部の復習からでいいかな。 あと、名前を動かす作品を、今まで使ったブロック全部使ってね！と、改めてお題を出した方が良いかも。', '時間帯: その他
タイピング: 初めてやったようで、丁寧に進めていました。
盛り上がり: スプライトを細かく動かせる、大きさを変える、音を出す、色を変えるなどができることに、一つ一つ「こんなこともできるんだ！」と驚いてくれた(⌒∇⌒)'),
  ('2df25cc0-b398-58f4-9322-e6936a6e1be5', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-10-16', '17:30:00', null, '通常 / 本人が楽しめるゲームで丁寧にスキルチェックになりそうな事', '検定問題ではあるが、検定を意識しないで作品作りとして取り組む。穴掘りなのですぐに制作に取り掛かった(^^)v アレンジイメージもいくつか浮かんだようなので、完成した後アレンジしてもらう方向が良いかも。 ◆スキルのポイント ・いろいろな固さの土を作ってもらうことで、変数「かたさ」のコントロールができているか ・宝以外に、ごみや他のアイテムを隠すアレンジをすることで、座標を演算と乱数を使って、マスの中に埋め込むことができるか', '前回の続きから。上記のスキルのポイントができるか、「こんなアレンジして」と頼んで作ってもらおう。一度完成したら、新しい場面を作るなどのさらなるアレンジ希望', null),
  ('c8fe5597-40d8-5dca-873f-8d03823d7408', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-10-20', '17:30:00', null, '振替 / リスト学習', 'この時間はお疲れなのか眠たそうだったので、考えるところは細かく時間で区切って、答え早生は動画の形で進めました。作り途中で気になったこととしては、もしを使うときにずっとを必ず持ってきてしまうことです。スクラッチに慣れてずっともしはセットに使うという考え方が染みついていて、それぞれのコードの意味が区別できていなかったので、そこは説明しておきました。最後の読み込みは、リストに対してあまり興味を示していなそうな中でも、声を出してリアクションをしていたので、手法が広がったと思います。', null, 'タイピング: ほんとは本番を今日やる予定でしたが、やっていませんでした。'),
  ('4458c8dc-9313-57d7-90a7-9639f95b3a02', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-10-20', '18:40:00', null, '通常 / フォートナイト風続き', '今日は敵の動きを作成しました。前回まで使っている定義の使い方の確認をしたり、敵が出現する度に見た目が変わる部分（もし～でなければ～のブロックが入り組んでいる部分）を少し解説したりしました。本人はあんまりよくわかっていなそうですが、難しい漢字や長いタイピングに諦めることなく挑戦できていました。 スプライトのプログラムは一通り終わったようです。後半はステージのプログラムに取り組んでいました（ステージのプログラムの重要性が分かってないかも。作品の構成の中心となることをプログラムする場所という認識がもう少しあってもいいかも？） 最後までプログラムしましたがおじさんが無敵状態になっているなど、うまくできていない部分があるので来週一緒に見直す予定です。', 'フォートナイト風プログラムを一緒に見直し', 'タイピング: 何回か練習してから本番に挑戦しました。'),
  ('c7875fe8-5820-56ca-a03b-65969c1c229e', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-10-20', '17:30:00', null, '通常 / 検定4級／3週連続実施 ⇒検定問題を楽しくやっているので、今週もやるか？', '本人がやりたいと言っていたので検定問題に取り組みました。最後にうまくプログラムがうまく動かず悩んでいましたが、最後まで悩めたのが素晴らしかったです。「繰り返し」の部分を読み飛ばしてしまっていたようです。また、「他のスクリプトを止める」というブロックを思いつくのも少し難しかったようです。（本番と違ってブロックのヒントもないからかな？）最後にアレンジをしてもらいましたが、最後までプログラムしきれなかったようです。次回やるときには一緒に取り組んだ方が良いかもしれません。', null, 'タイピング: ミスタイプ率がとても低かったです！'),
  ('9c80bad5-b534-50fa-9279-4f2948086468', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'bccc3401-27c9-585a-943b-e6cd207e8a46', '2023-10-20', '16:30:00', null, '通常 / リスト学習', '前回はあまり動画を見ずに自力で作っていたこともなっていたこともあって、冗長になっていたので、今回は整理のために初めから見てもらいました。手間がかかっていたことがきれいに作ることができたので、そのありがたみは感じでいました。変数で番数を決めるやり方は、自力でできていたので良かった思います。後半の定義を使うところは、引数はまだわからなかったそうなので、何となくの理解で見てもらいました。', 'リスト動画④⑤', 'タイピング: こちらの不手際で申し込みしたのが練習していたの英文ではなく和文Aでした。とりあえず、ローマ字は受けてもらいました。
盛り上がり: タイピングは調子よかったです'),
  ('192b0e7b-f590-5cd6-9abc-0215f3cbc2ce', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-10-20', '17:30:00', null, '通常 / ⇒プラットフォームセットの続き 放物線のプログラム確認・横スクロール →ジャンプに変数を使うことに抵抗のある子、案外多いね。 →ここで変数を使うことで、ゲーム上で何が実現できるかをイメージさせてあげてから、変数を再度確認したい', 'かなりジャンプをやりたくない様子だったので、さらっと前回の復習をしてクローンでやるスクロールをしました。座標とクローンをつくるタイミングに注目してもらい、スクロールができている仕組みについて解説しました。なんとなく理解できたようです。 後半は自分で作っているオリジナル作品を見せてもらいました。どうしてもこの話をしたかったようで一生懸命解説してくれました。もともとは他の作品をリミックスしたようですが、その後自分なりに要素を追加したり削除したりしているようです。動きのプログラムはあまり見られませんでしたが、メッセージのタイミング、表示非表示は自分でしっかり作っているような印象です。', null, 'タイピング: 取り組めました。難易度ふつうにも挑戦してほしいです。
盛り上がり: 自分の作品を説明してくれるときはかなり楽しそうでした。'),
  ('a4574532-eae7-5043-8745-d0df6502d3a0', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-10-20', '16:30:00', null, '通常 / 3級応用課題３', '40分かけて取り組みました。プログラムをする箇所を間違えていました。どこにプログラムするのかを読み飛ばしてしまったようです。見本通りにプログラムが動いていない様子でした。前半の確認で時間を使ってしまったので、答え合わせが最後まで終わりませんでした。次回続きからやりたいです。', '3級応用課題3答え合わせを続きから', 'タイピング: 集中して取り組めていました。少し緊張していた様子です。'),
  ('21648cb9-7f7b-55e9-be9d-502d245f9cde', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-10-20', '16:30:00', null, '通常 / 横スクロールを学ぼう', '目的を忘れないためにスクラッチでプラットフォーマのゲームを何個見せて、共通しているで横スクロールを見つけ出してから作り始めました。メッセージ型の横スクロールは一見どのようにつながっている川か憎そうだったので、図解をして何にメッセージを理解してもらいました。ゆっくり説明して買いもあって、コードづくりは上手くいけました。そこで前回作った放物線ジャンプのスプライトを持ってきましたが、そのままのコードでは足場に乗らず、苦戦していました。段差を上ることを身に着けるために、アルくんの冒険(本人はまだやったことない)をやってもいいかも思いました。それか、ジャンプをもう1歩踏み込んで重力ジャンプに作るのもありだと思います。', null, 'タイピング: 数回の練習でうまくできていました'),
  ('cf4d9410-75b3-585f-a7d5-b4f5d03a8d0e', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-10-14', '16:30:00', null, '通常 / 検定1級のリストの問題対策／テキストコードの配列の基礎概念の理解', 'アルスパーク／リスト動画', '動画を丁寧にみているので、理解は進んでいる。これの応用ができると素晴らしいので。1000問自動問題作成／これに合わせて、都道府県問題作成⇒テキストを読み込むこと：すなわち外部のデータをとりこむことができること、これの活用という「データ活用」の基本を体験してもらいたいです。 その他、リストを使った作品の応用をいくつかみてもらおうかなと。', '盛り上がり: リストの動画①②③ 定義を使うverの途中までで。概念の理解はしっかりできている様子だ。この単元の目的である、テキストコードへ移行する際に必要な配列の基礎を理解することも問題なさそうです。'),
  ('e22e5fae-85b1-59ed-b587-10940385590a', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-10-14', '16:30:00', null, '通常 / 検定1級のリストの問題対策／テキストコードの配列の基礎概念の理解', 'すぐにROBROXのゲームをやり始めるので、ヤル気がそがれるようだったら、基本「次のステップにいくために絶対必要な概念理解をしている最中である」ことを意識付けしていきたいです。これらのステップを踏まないとテキストコードに行けないことを伝えてください。 次のステップのために、リストの動画、まずは①②を作成。基本概念は理解できています！！', '1000問自動問題作成／これに合わせて、都道府県問題作成⇒テキストを読み込むこと：すなわち外部のデータをとりこむことができること、これの活用という「データ活用」の基本を体験してもらいたいです。', 'タイピング: コンテスト実施
盛り上がり: リストの最初の方は、「これで何がいいのか？」となりがちで。今日はそこで終わってしまったので。⇒次回へ'),
  ('28d32104-cea3-5601-ad67-3218427f36e1', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-10-20', '17:30:00', null, '通常 / この１ヶ月やったことの「応用」', '最初にこの１ヶ月にどれだけの新しいことを学んだかを確認。アルスパークの過去の作品を一つ一つ、動かして、ブロックを確認しました。 次に、これらのブロックを使って新しいゲームを作る「【Prg】09 ネコからにげろゲームを作ろう！」をみせました。実際にゲームで遊んだところ、ネコの動きが早くてネズミがすぐつかまってしまい、楽しそうにゲームをしました。これを作る！ということで。 当初、動画をみせてと思ったのですが。画面が漢字でまったくわからないというので、見本の写経にしました。 「ネコ１」を動かすところまでで。次回は続きから。', '「ネコ１」の続き。画面にコメントで作成する順番があるので、それに沿って。', 'タイピング: 割愛
盛り上がり: 写経のため、わからないところがあったら声かけてねと伝えた。入力の個所で「先生手伝って」と言ってきたので、「自分でできるところと、わからないところをしっかり区別できててすごいね」というと、嬉しそうに「自分でここはできる」とやり始めてくれました(^^)v ネコ１のコードが出来上がったのに、動かないので「？？」となっており。「０」の数字がおかしいとヒントを出したところ、全角と半角の違いを理解して修正できました。
備考: 最初はヤル気なし(T_T) 何ども声をかけても無視してゲームを続けていたので、私もそろっと席を立ち無視したところ。数分で「今日何やるの～」とソウちゃんから声をかけてきました(*´σｰ｀)'),
  ('b4e9c02c-af2e-5878-b73f-d3ca532665f9', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-10-19', '17:30:00', null, '通常 / 躍らせよう', 'ゲーム系が続いていたので、見た目の部分のコードが詰まった基本操作コース08をやりました。コスチュームを順に変えて、踊っている風に見せるコードは、まず「コスチューム～にする」のブロックを何個もつなげて表現していました。同じ風に表現するにはずっとと次のコスチュームでできるよと教えたら、「今まで無駄じゃん。けど、勉強になったわ」といじけず、ポジティブに考えて楽しめていました。メッセージを使って順番に踊ったりして、最後に音を付けたら、ホラーティックになった良い踊りなものが完成できていました。今日はあんま時間を気にすることなく楽しくできたと思います。', null, 'タイピング: スコアが順に伸びてきました
盛り上がり: 新しく買ったスマホの自慢を楽しく話してくれました。
備考: 「メッセージを送る」と「メッセージを受け取った時」の違いがまだ少し曖昧です。何度か繰り返し使用させて定着させたいところです。（大原）'),
  ('cc65fa64-27ff-57dc-967d-ac53abd333f8', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-19', '17:30:00', null, '振替 / 基本操作コースで座標を中心としたスキルの確認を', '毎パソの本番で疲れたのと、時間が普段と違って遅かったせいもあるのか、なかなか気力がわかないようでした。お腹もぐーぐー鳴っていたので、ちょっと辛かったのかもしれません。 今日の課題が終わったら遊んで構わない、という約束で始めましたが、キャッチゲームを最初にプレイして「これは難しいから僕にはできないと思う」と言ってゲームをしようとするので、しばらく隣について一緒にやるから、ということでようやく取りかかりました。 ゲームについて、スプライトごとにどんな動きをするか、特徴は何か、などの問いにはスラスラ答えられるので、頭の中での細分化はある程度できているようですが、それとブロックとの結びつきがイマイチのようです。間違ったブロックをつなげるのが嫌ということもあるようで、あっているブロックでも、こちらの表情を伺ったり、カードを見て確かめようとする傾向が強いです。 「○○に触れたら」等の条件分岐はよくできていますが、「座標を〇〇にする」と「座標を〇〇ずつ変える」の違いが未だに不明瞭なようで、こちらの説明も、今日はわりと聞き流していました。また元気な時に、ゆっくりと動きを確認させたいところです。 スコアやゲームクリアの作成では、「もうここまででいいよー」と言いつつ、変数等はよく覚えていて、スラスラ作っていました。', null, 'タイピング: 最後の練習よりも本番の方が間違えてしまったとしばらく悔しそうにしていました。
盛り上がり: 口ではぼやいたりしつつも、自力でできているところをほめると少し得意げに、嬉しそうにしていました。'),
  ('6136db69-1d0f-5b43-9cab-30b69d003157', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-19', '17:30:00', null, '通常 / 検定問題に慣れる', 'タイピングの本番を終えて、少し気が抜けたようでしたが、こちらの声掛けで取りかかっていました。 途中までは順調に進めている様子でしたが、最後の方になると姿勢がどんどん悪くなり、苦戦して疲れも出てきたようでした。 試験時間が終了後に感想を聞いたところ、あいこのところがうまくいっていないとぼやいていました。 試験終了で授業時間も終わってしまったので、焦らず次回、ゆっくり見直しをしようと声をかけました。', '検定問題2級②の答え合わせ', 'タイピング: 練習では準1級～1級レベルでした。本番も無事に終えていました。
盛り上がり: 検定問題自体には、苦戦しつつもあまり嫌がらずに取りかかっています。 タイピングもそうですが、変にぐだぐだ悩まずスパッと取りかかるところが、由希ちゃんの体育会らしいところかな、と…'),
  ('397e362c-0223-5034-a5a8-f8b3f6cf75bb', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-10-19', '17:30:00', null, '通常 / 毎パソ本番＆リスト1000問自動問題', '今回は児童に1000問計算作る問題でしたが、最初にノーヒントで作っていたが、あまり進んでいない様子で、画面を見るとか変数が乱雑に存在して無駄に難しく考えすぎていたので、軽く方針伝えてあげました。そこから、先週のクイズとあまり変わらないと気づけたので、嘖々と作り上げていました。クイズを作るときに、承太郎君の中では次の問題にいくときリストの中を順に出していく考え方ではなく、順に消していく考え方は面白いと思いました。 最後に、リストは外部から読み込むことができるを知ると、驚きがあったので、今後の作品の幅につなげていけるといいと思います。', null, 'タイピング: 練習を少なくしてささっと本番に臨んでいました。
盛り上がり: まだスイカゲームのブームは続く'),
  ('2456a06d-5c2f-55ac-9b59-833ee9b7a998', '57f45872-1f3e-5540-b676-bf9023444e39', null, null, '2023-10-19', '16:30:00', null, '休み（未対象）', null, null, null),
  ('cad65acb-65ab-5490-b367-03913ece754f', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-19', '16:30:00', null, '通常 / 検定問題への挑戦', '検定に対してどのような反応をするかわからなかったので、ポジティブな雰囲気で勧めてみたところ、わりとあっさりと「やってみる」とのことでした。 途中、自分でブロックを作成したため、Defaultのブロックが余ってしまって「これは捨てても構わないのか？」などと悩んだところと、小数点のキーがわからなくて質問してくる場面はありましたが、他は問題なく、時間内に解き終えていました。 7～8分時間が余ったので、自由にアレンジタイムにしたら、その後はひたすら楽しそうにアレンジをしていました。一応時間内にスプライトを変えるアレンジまでができたので、残り時間はこの作品を好きにいじって構わないとしたら、スプライトや背景をすべて変え、牧場での鶏の毛刈りゲームに上手に変えていました。 問題文の通りにやれば一つの作品が完成するため、こちらの予想以上に楽しめていたようでした。特にアレンジは最後まで集中して楽しそうに取り組んでいて、こういう勉強ならこれからもしていきたい、と前向きになっていました。', null, 'タイピング: 今日は周りがタイピング検定をやっていたため、よけいにやりづらいようでした。 落ち着いたら、りょうやくんのペースに合わせたタイピングをゆっくり勧めてみたいところです。
盛り上がり: とにかく作品がきちんと完成するのと、そこからアレンジができるのがとても楽しそうでした。
備考: 検定に対してどのような反応をするのか、お母さんも予想がつかなかったようで、喜んで一生懸命やっていたと報告したら、とても驚きつつ、嬉しそうにされていました。 学年的にも4級は少し簡単で、りょうやくんにとっても余裕があるようでしたが、ギリギリで挑戦させると委縮してしまいそうなので、本人が楽しめる程度のレベルで無理せず受けていこうということで、お母さんとは合意しました。'),
  ('71b08cfc-63ff-5f37-8564-a80c5f3a5d9f', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-10-19', '16:30:00', null, '振替 / 検定練習', '2回目の3級の問題でしたが、問題文自体は20分ちょっとで終わり、ミスもありませんでした。悩んだところも少なく、スムーズにできていました。安心して検定は受けられると思います。アレンジはボールの魔法のところでドラゴンが倒しやすくなるようになっていて、よりゲーム性が増していました。', null, 'タイピング: 練習練習
盛り上がり: 検定が終わった残り時間もアレンジ続け、新たなスコア要素も増えていました。'),
  ('52daaf33-1fab-5a3b-b5c8-0dcc3e4152a5', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-19', '16:30:00', null, '通常 / 検定問題の読み取りに慣れる', '応用課題はセリフを自分で打つ必要があるため、ローマ字表を一生懸命に見て打っていました。 最後のネコの動きがムービーと違うと言って自分で問題を見直し、動きがy座標であることに気付いてノーヒントで直せていました。 問題文の読み取りにはずいぶん慣れたようで、バグ探しのときも、見るべきところがわかっているようでした。 20分で解き終わったので、楽しそうにアレンジをしていました。', null, 'タイピング: 練習で最高記録（6級）を出してから、気分よく本番に入りました。 本人によると、最初に少し間違えてしまったそうですが、集中を切らさずがんばっていました。
盛り上がり: 検定問題にもだいぶ慣れ、自信もついてきたようでした。 問題をゲーム作成の仕様書のようにして、楽しんで取り組めているようです。'),
  ('54dff1cf-5bb0-5d11-bf87-a42dcf9a3bff', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-12', '17:30:00', null, '通常 / 検定問題の見直し', '前回解いた問題を振り返りました。自分でも、いくつか間違えた自覚があったようで、一緒に答え合わせをする前に直す時間が欲しいとのことで、10分ほど修正タイムにしました。 問題の読み違いや勘違いなど、細かいところでのミスが目立ちました。どこまでをどの処理の中に入れるか等、問題を確実に読むか、普段の知識で作成できるか、いずれかの対応ができるようになると安心かとは思われます。', null, 'タイピング: 順調ですが、急ぎすぎると不正解数が増えることも…
盛り上がり: 前回は試験時間等で焦りもあったのか、落ち着いて考えると解ける部分もあることがわかったのは嬉しそうでした。'),
  ('561a74e7-6581-5d5c-a68a-743f56c0cf0f', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-10', '16:30:00', null, '通常 / 図形を描く', 'ペンツールを本格的に使ったのは初めてだったようで、面白がってくれました。 図形を描く繰り返しの動きはわかっていましたが、四角形以外では向きを何度に向けてよいか、計算して考えるのは苦手そうでした。わりとイメージで角度を入れようとするところもありました…。 角度を考えるのは算数の分野になるので、今回は軽く説明するにとどめ、繰り返しの中の処理や繰り返しの回数など、プログラミング的な面に焦点をあてて、楽しく作成することを目指しました。', null, '盛り上がり: 繰り返しの回数や動く歩数を変えると、思ってもみなかったような図形ができるのが面白かったよで、数値を細かくいじっては、楽しんでいました。'),
  ('39584792-8f5b-5601-9869-66af013a8a95', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-17', '17:30:00', null, '通常 / 検定問題3級にチャレンジ', '現状、検定までには余裕があることも伝え、今日は余裕をもって4級の応用課題をするか、3級に挑戦してみるか選んでもらったところ、3級問題をやりたいとのことでした。 問題文のa.b.c.d.を繰り返す、という表記が初めてだったようで、aキーかつ↑キーが押されたとき？と考えてしまったようで、混乱して手を挙げてきました。これは問題文の書き方であり、abcdはただの行頭文字だと説明したところ、納得していました。 中問(①②③…）の冒頭の書き方に気が回らず、複数のコードを一つにつなげて書いていたため、犬が動かないと悩んでいました。問題文の書き方がヒントであり、「旗がクリックされたとき」なのか、「○○のあとの動作」と書いてあるかに着目するようヒントをだしたところ、コードを分割できて、解決できたようでした。 ⑥の問題で、「かつ」を使用するべきところの見落としがありました。 基本的に、コード自体は自力で余裕でできたようでしたが、問題の読み取り方にはもう少し慣れた方が良さそうでした。', null, 'タイピング: 来室時は「今日はタイピングはやりたくない」と言っていたため、来週やることで合意しましたが、1時間の待ち時間のうちに受験票をまじまじと見たりして気になってきたのか、こちらが気が付いたら普通に練習をして、本番に取りかかっていました。 お迎えのお母さんも、家を出るときに「やっぱり嫌だ」と言っていたとのことで、受検できたことに驚いていました。
盛り上がり: 一つ一つの問題に対しては、どれもしっかり答えられたので、3級受験に対する意欲や自信も持てたような様子でした。'),
  ('b44bf10f-056d-56e4-a00b-060fdf777a58', '7d01236e-620e-5177-a6f4-af325a582aae', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-17', '17:30:00', null, '通常 / いろいろな課題に挑戦する', 'ゲームを作成するか、応用課題をするか選ばせたところ、応用課題のプリントを何枚か見て、こちらがやりたいと選んでいました。文章を読んで作成するのは、わりと好きだそうです。 問題文では、ネコの足を動かす動作が一番最後にあるため、問題文の途中でネコが学校についても足を動かさない、コスチュームの指定が間違っているのではないか、と混乱していました。このような問題では、自分が思っているのと違う順番で作成を進めることもあるため、問題を最後まで解き終わるまでは、ムービーと違っていても焦らないよう伝えました。 ⑦で、まだ作成していない⑨のコードを止めるという問題文の順序の不親切（？）さにも、とまどっていました。こういうときは、コードを作成する前でも、問題文の先まで目を通すことに慣れていけば大丈夫かと思われますが…。', null, 'タイピング: 何度か練習してから本番に取りかかっていましたが、練習の時の方がうまくできた、と、少し残念そうでした。
盛り上がり: 多少とまどったところはあったものの、作成自体は楽しんでできていました。時間にも余裕があったので、その後はスプライトや背景に手を加えて楽しそうにアレンジをしていました。'),
  ('b53fd53a-a8c5-500b-9c30-0106599a1e63', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-10-17', '17:30:00', null, '通常 / 検定問題1級① 答え合わせと解説。', '時間内に作成できていた部分に関しては、ケアレスミスが何箇所か見られたので今後注意して行けば、大丈夫だと感じました。そして、作品全体の2割ほどが時間内手をつけることが出来ていなかったので、時間配分に気をつけて取り組んでいかないと厳しいと感じました。初めての１級ということもあってかなりてこずっていたようですが、以上の２つを改善していければ高得点を獲得することも可能なのではないかと感じました。', null, '盛り上がり: 最後まで作成することが出来ていなかったので、答え合わせをしていく際に自分がどこをどのように間違ったのかと、手をつけることが出来なかった続きの部分に関してどのようなプログラムで、どのようにして動作をするのかを完成したプログラムで操作している際は、自分が今どれくらい出来ているのかをなんとなく感じることが出来ていました。'),
  ('c816a6aa-627f-505c-acca-9944a57a2819', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-17', null, null, '通常 / フローチャートの作成、フローチャートを元にしたプログラミングの練習', '最初に完成版を見せて、ひいろくんがこれまで学習したチエテラスでのJavaScriptの内容を思い出してもらいました。わりとスムーズに、このブロックはたぶんこんなコードで書くのでは、というような発言ができていて、イメージもわいたようでした。 全体を把握した記憶をもとに、フローチャートのプリントを見せてプログラムの流れをイメージしながらフローチャートを作成しました。こちらはほぼ助言なしで、スラスラと書けていました。それをもとに、再度Scratchでプログラミングをすることも、スムーズにできていました。 30分で上記課題が終わったため、次の課題の希望を聞いてみましたが、珍しく、こちらが選んだScratchの課題をやりたいと言ってきたため、【Prg】50 まほう早うちゲームを作ろうに入りました。動画を見ながら、10分くらい延長して一生懸命作成していました。', '【Prg】50 まほう早うちゲームを作ろうの続き', '時間帯: その他
盛り上がり: フローチャートは初めてだと言っていましたが、その必要性などを説明すると、熱心に取り組んでくれていました。'),
  ('335bc800-a0dc-503f-90f0-a218cdbb2c2a', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-17', '16:30:00', null, '通常 / プラットフォーマー系ゲームの完成度を上げる', '前回、ジャンプと背景スクロールができた時点で本人は完成だと思っていたようですが、実際に遊んでみておかしいところや気になるところはないか、探すところから始めました。 ゲームオーバー時に背景のスクロールが唐突に止まって（クローンが消えて）後ろの白い画面が見えてしまうことや、ゲームのクリアがないことなどに気付いたので、そこを改善することを今日の目的としました。 やることは決まったものの、即座に「どうすればいい？」と聞いてきたので、今問題となっている現象は何が問題か、どこのコードが関係していそうか、など、順次質問していくことで、なんとか修正箇所を見つけることはできました。 問題やバグの理由、場所、修正内容などを一度に考えようとしてわけがわからなくなっているようなので、今日は段階を追って問いかけをすることで対応していきました。 ヒヨコが爆弾に触れた時点ですべてを止めるのではなく、メッセージを使って背景等の他のスプライトを制御する、クリア条件となる旗のスプライトを作成するなど、これまでの知識を使ってゲームの完成度を上げることができました。 背景スクロールのクローンがうまく消えなかった件も、座標に注目するよう促したら、演算式の座標の数値が小さすぎることがわかり、修正することができました。', null, 'タイピング: 何度か練習して、本番にチャレンジしました。
盛り上がり: 少しずつバグをつぶして、思い通りに動くようになったときはとても喜んでいました。'),
  ('3f19be47-d22e-5861-8077-5bf5b0aed1f4', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-10-17', '16:30:00', null, '通常 / アルスタジオレッスン/アルくんをおえ1', '前回まで作成していたクイズを出題するプログラムよりも内容としては単純でわかりやすい内容となっていたので、かなり早く動画の通りに完成することが出来ていました。アレンジ内容として、時間制限内に何回キャラクターをクリックすることが出来たかを可視化できるように変数を使いスコアを出したり、スコアの結果をキャラクターが喋るようにとアレンジを施していました。', null, 'タイピング: ローマ字を覚える所からのスタートでしたが、画面上にキーが表示されていたのでゆっくりですが間違えずに打つことが出来ていました。この調子で少しづつ打てる範囲を伸ばしていければより早くタイピングをすることができるようになると思います。
盛り上がり: アレンジの際は、キャラクターのグラフィックを特にこだわっていました。色の変化や形そのものの変形などで作品にオリジナル性を持たせていました。'),
  ('5f23ab3e-d67b-5868-b517-8f897fbff224', '13bd73d0-f535-5291-8362-6712e5cd7384', null, null, '2023-10-14', null, null, '休み（振替対象）', null, null, '時間帯: その他'),
  ('b81bf832-8e1e-51d2-92d0-34c3699f7f93', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, null, '2023-10-14', null, null, '休み（振替対象）', null, null, '時間帯: その他'),
  ('3d9d577b-e06d-54f6-9f3e-3d943c3d4f83', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, null, '2023-10-14', null, null, '休み（振替対象）', null, null, '時間帯: その他'),
  ('bcbd2fe1-f8ff-5632-a98a-91040a99df33', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '54b88baf-3796-5e07-979a-a1635802e385', '2023-10-16', '17:30:00', null, '振替 / プラットフォーム初回 ゴール（カエルのプログラム）を遊んでもらってから、プロセス（ジャンプ、背景スクロールなど）の確認。ジャンプからスタート。', '最初にカエルのプログラムを見てもらいました。背景が動いていることに少し気が付きにくかったようです。 等速ジャンプを作ってもらいました。バッチリでしたが、その後変数を使ったプログラムを作ってもらおうとすると抵抗がある様子でした。変数にまだあまり馴染めていない?様子です。 最後に放物ジャンプのプログラムを見本を見ながら作ってもらいました。スプライトをたくさん増やしてにぎやかな作品になりそうです。まだ内容の確認ができていないので来週行う予定です。', '放物ジャンプのプログラムの内容確認から', 'タイピング: 集中して取り組めていました。
盛り上がり: 自分で作っている作品があるようです！！'),
  ('3095e8f5-7ad8-558f-b6e7-62d6ec0f8166', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-10-16', '17:30:00', null, '通常 / →自由に作品作るのが好きなので。今日、改めて最後のプラットフォームゲームの見本を見せて、自分が作ろうとしている作品のイメージを創造させてから。ジャンプと背景の必要性を、復習かねてお話ししてくださいm(__)m ジャンプの復習と【小技】簡単な横スクロール', '最初にカエルのプログラムを遊んでもらい、ジャンプや背景スクロールなどの必要な技術に気づいてもらいました。 変数を使った等速ジャンプ、背景スクロールとも一度取り組んだことがありましたが（作品を見せてくれた）、放物線ジャンプはなかったようです。一度見本を作った後、プログラムの内容を一緒に考えました。図を描いて説明するとなんとなく理解できた様子でした。最後に来週の紹介としてスクロールを使った作品をいくつか見てもらい、いろんなスクロールの方法があることを説明しました。', null, 'タイピング: 集中して取り組めていました。練習の方がうまくいった箇所もあるようです。'),
  ('0e77768b-27f2-58fb-af9c-46e35b89fd6c', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-10-16', '16:30:00', null, '通常 / ⇒毎日タイピング本番実施 ⇒プラットフォームセットの続き 放物ジャンプへの変更', '前回やっていた背景スクロールが途中だったので背景スクロールを進めました。動かす基本となる部分はもうできていたので、2枚目、3枚目がきれいにでるように整えました。考え方がまだよくわかっていなかったようなので、絵を出す順番、タイミングについて一緒にプログラムを見ながら確認しました。少し理解できたかな？といった印象です。', null, 'タイピング: 熱心に練習していました。本番は少し緊張していたようです。'),
  ('f1d30ccf-5cfd-50a6-8351-42550b1f611c', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-10-02', '17:30:00', null, '休み（未対象）', null, null, null),
  ('a2e9360d-f42a-54c9-94b3-bf888c7b0735', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-14', null, null, '通常 / オリジナル作品を作りながら基本スキルの確認や習得をする', 'やりたいことを書いたノートを忘れてきてしまったとのことで、怒涛のように説明をしてくれました。かなり熱心に考えてきてくれているのですが、年齢的に順序だてて話すことや名詞を統一して話すことがまだ難しく、やりたいことがうまく伝えられなくてじれることもありました。 思い込みもかなり激しく、やりたいことをシンプルにさせようと提案しても、「それだとうまくいかないと思うから、自分はこうしたい」と強弁することも何度かありました。 背景をすべて選択でコピーしてスプライトにしたがる傾向が強いです。スプライトにした方が、作成したボタン等のスプライトを最前面にできるから、というのが本人の理由でしたが、基本的にスプライトは背景の前面にくるし、前面に出したいスプライトに対して「最前面」のコードを使えば解決することを説明しても、なかなか納得はしてくれませんでした。 結果として、説明と、表示するボタンを作成することで満足してしまったので、今日はプログラミングを一つもしていないから、と納得させ、ボタンを押したら背景が変わるコードを作成して、希望通りの動きをすることを納得させることができました。', 'ホーム画面からボタンを押すとゲーム画面に変わるところまでは作れたので、次は、ゲーム画面になってから表示されるスプライトを作成し、ゲーム内容を作成していく予定です。', '時間帯: その他
タイピング: タイピングもローマ字も得意だと言って、楽しそうに取り組めています。
盛り上がり: やりたいこと、作りたいことがあふれすぎていて、とにかく嬉しそうに話し続けていました。'),
  ('19a9ddac-8a8d-5745-b394-1275ff25184f', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-10-14', null, null, '通常 / プラットフォームゲームを作れるようになる', 'まずは目標とするプラットフォームゲームを遊んでもらい、次に「速さの管理に変数を使う」というポイントを伝えながら放物ジャンプに取り組んでもらいました。新しい変数の使い方に慣れないながらもなんとか完成し、左右移動も付け加えてプラットフォームゲームで活用できる形になりました。背景スクロール①にも取り組み、座標の動きを考えながら背景1枚のみのスクロールができました。', '【小技】簡単な横スクロール② 完成版 クローンを使う からスタート', '時間帯: その他
タイピング: 今まであまり練習しようとしなかったのでタイピングスキルが不明でしたが、今日は練習をしていて速く打てることがわかりました。本番も難なく終えました。
盛り上がり: 一つずつ習得したスキルを積み上げていると思います'),
  ('d61f213f-4da6-5b2e-a346-ad4b52336aa7', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-14', null, null, '通常 / 音楽やダンスを作成する上でのスキル確認', '今日もスタンプを埋める方をやりたい！とのことだったので、基本操作コースを進めました。音楽も飛ばさないでやってみたいとのことだったので、一問ずつきちんと取り組みました。 一つできると嬉しそうにスタンプを押していいか許可をとっては満足そうにしていました。 バックパックの使い方を覚えて、感激して使いまくっていました。 コースの内容は、ほぼ質問なしで自力でできていました。', 'スキルチェックも良いけれど、そろそろ一度クローンをやりたいとのことなので、宇宙バトル3とまゆねこあたりをやってみてもよいかもしれません。', '時間帯: その他
タイピング: タイピングを開くと、やすのりくんが「俺はタイピングもローマ字もよく知ってる！とくい！」と言ったためか、一気に暗い顔になって「あまり得意じゃない」と言い始めたので、あえて教材を変えて、速さは気にしないで、「あいうえお」を下を見ないで打つことに挑戦してもらいました。 まだ指が小さく、上段のキーを押すときに他のキーを押してしまったりというミスもありましたが、「あいうえお」がうてればローマ字の半分は打てたことになるという説明には納得していたので、ゆうとくんのペースで進めていきたいと思います。
盛り上がり: 自分の現在のスキルで一覧表を埋めていけるのがとても嬉しそうでした。 音の変化にも、大好きな乱数を使って楽しそうにしていました。'),
  ('4d3a3e0f-4e8e-5a90-8454-c2fdb0defeb5', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-10-14', null, null, '通常 / 自主的なゲーム作成', 'のあくんと一緒に動画を見ながらクラゲのゲームを作ろうと促しましたが、先週から自分で作っているゲームの製作を進めたいと希望したのでそうしました。必要なスプライトを準備し終わってから動きの作成に入りました。まずはゲーム開始時に隠すスプライトの処理、左右移動、敵に触れたときのゲームオーバーの処理をしました。これらは今までにもやってきたことなので、少し助けを借りながらもしっかりできました。 ゲームの構想については新しいアイデアをどんどん話していました。星に触れたらそれを回収し、10個集めたら特殊能力が使えるようになるそうです。また、スペースキーを押したら敵を吸い込むとのことだったので、そのコスチュームを作ってスペースキーを押したら切り替えるようにしました。', null, '時間帯: その他
盛り上がり: このままゲームを完成させるのはスキル的な問題で難しそうですが、作り続けたいという気持ちが相当強いです。そのため、その情熱を製作に向けつつも、完成までもっていくには他のレッスンの内容もマスターする必要があると納得してもらいたいです。'),
  ('7d64b11f-5597-56ca-a3dc-a5ac39aa1601', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-10-14', null, null, '通常 / プラットフォームゲームを作るために必要な技術を学ぶ', '最初に、「このゲームが作れるようになることが目標」と伝えてカエルを家に帰せを遊んでもらいました。すると中のコードが気になったようで見ていましたが、よくわからなかったようです。そこで「ジャンプから順番にマスターしたいからまずは等速ジャンプをやろうか」と伝えましたがなかなかやろうとせず、ジャンプの種類などを軽く説明したところで終わってしまいました。', '等速/放物ジャンプ', '時間帯: その他
タイピング: 最初は集中できなかったようですが、途中から集中して本番はしっかり決めていました。
盛り上がり: 今日は運動会で疲れていたうえに毎パソで頑張ったので、モチベーションがわかなかったようです。'),
  ('598f68d4-3ffc-511b-adba-377e935eeb90', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-14', null, null, '通常 / 検定問題に慣れる', '応用課題の画面を見せて自分で選んだ課題に取り組みました。 初めて作成するタイプのゲームだったためか、時間を10分ほどオーバーして最後まで悩んでいました。 持ってくるブロックはきちんとあっていて、メッセージを入れる位置が繰り返しの中なのか等に混乱が見られたようでした。', 'どこまでが繰り返しや「～まで待つ」の範囲なのか等に注意して答え合わせ', '時間帯: その他
タイピング: 無事に本番を終えていました
盛り上がり: 問題を読むのは苦にならないようで、検定問題へのチャレンジも自分から申し出ていました。'),
  ('275a3632-1f7b-57c5-98dc-1f4b8fe04aa1', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-10-14', null, null, '通常 / これまで、アレコレやってはいるのでスキルの整理', '動画：08 海に沈んだダイヤを探せ.mp4 07:04まで ▼のあ君のレベルだったらマスターしているだろうコード 「マウスのポインターへ向ける」 「マウスのポインターへいく」 ▼少しあやふやっぽいので、しっかりマスターしたいコード 「もし＜〇〇〇に触れた＞なら」 乱数 メッセージ === 「【Prg】08 海にしずんだダイヤを探せゲームを作ろう！」の単元では、X座標とY座標に乱数を使い、あちこちにダイヤを登場させるのがポイント。のあ君はまだ学校で座標、X軸、Y軸を習っていないので、（一番最初に使っていた教科書の）座標を見せて確認。 ダイヤの動きを乱数を使って動くところまでやれた。 ここは、次回もしっかり復習したいところ。', '・ゲーム完成のイメージの再確認 ・座標の復習 ・細分化を意識して、それぞれのスプライトの動きを説明してから（のあ君に説明してもらうのもいい）着手するといいかも。 ◆座標の復習で定着を ◆「もし＜〇〇〇に触れた＞なら」の理解を', '時間帯: その他
備考: 最初、動画をみていたのですが、乗り気ではなかったようで。それは漢字がわからないことが理由だと後で発見。画面も漢字表記にして、形でやってみるよう勧めると、手が動き始めた。 漢字の習得のためにはいいかも。'),
  ('a176c15b-4a2d-5a40-8a36-fce7320cdc41', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-10', '17:30:00', null, '通常 / 検定問題1級に挑戦', '前回、2級問題があっさりとできてしまったため、本人の希望もあって、様子見で1級をやってみました。 途中で唐突に爆笑し始めたので見に行ったところ、敵のスプライトが連なって板のようになって出てくると言って、「これは絶対間違っている」と大笑いしていました。 その後自分で問題と自分のコードを照らし合わせて、自力で解決していたようでした。 手ごたえはあったようで、このまま1級の問題を続けてみたいとのことでした。', '授業回数が少なく、スキルの抜けが不安なため、答え合わせの後、他の問題をするか、スキルの穴埋めをするか検討', 'タイピング: いきなりの本番で驚いていましたが、早めに来室したため結構練習時間を取ることができました。授業が始まったら、「そろそろやってみる」と言って、あっさりと本番を終えていました。
盛り上がり: 試験中の間違いなどにも焦らず、笑いながら対応できる余裕があったようで、終わった後も満足気にしていました。
備考: 1級の応用課題7を自宅でできるように準備'),
  ('dace1b76-8cb5-5513-9cc0-6ee66b6a51a0', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-10', '17:30:00', null, '通常 / 検定問題に取り組む', '前回、今度は検定をやると話してあったので、比較的スムーズに検定問題を始めてくれました。 途中まではスラスラ解いていたようでしたが、実際に動かしてみると、敵が動いてくれないといって長時間苦戦していました。 試験中は教えることはできないので、とりあえずそこを飛ばして、できるところを全部うめることを勧めると、納得して他の部分を完成させようと頑張っていました。 以前は、うまくいかないことがあると声を上げて頭を掻きむしったり、そこで作成をやめてしまったりすることもあったため、ずいぶん辛抱強くなったと感心させられました。 とりあえず、試験中でも最後まで投げ出さないでできるところを確実にがんばる、という取り組み方の練習はできたと思います。 バスの時間があったため、終了後は急いで退室しました。', '答え合わせと解説。教室内ではあまり表に出しませんが、わりと繊細で自信をなくすこともあるので、なるべく前向きにできれば。', '盛り上がり: 1級にチャレンジできているという満足感と、結果が出るものに対するみずきくんの慎重さ、不安感の両方が出た一日でした。'),
  ('a8464e9b-3d63-572a-95c2-ffa72cbc407d', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-10', '17:30:00', null, '通常 / リストについての理解を深める', '今リストの復習をする意味を説明してから、動画の視聴を始めました。 淡々とやっていたましたが、イヤフォンだったこともあって、途中で少し眠くなったようでした。 初めのうちは、先生側が様子を見つつ、適宜動画をとめて作業時間を入れるなど、もう少しメリハリのある授業構成をこちらから提示した方が、学習効果が期待できそうです。', '次回は声掛けや進行について、もう少し気を配ります。', 'タイピング: 淡々と取り組めていました
盛り上がり: 新しいことにチャレンジしている、という満足感はあったかもしれませんが、「させられている」感は強かったかもしれません…。'),
  ('db5a217d-a77e-5f0d-b492-4d288ce0d883', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-07', null, null, '通常 / ジャンプのスキルを身に付ける', '検定系をやらない代わりに、スキルアップとアレンジや作成を繰り返して、全体のレベルアップを目指すという合意ができていたため、今日はジャンプのスキルアップに取り組みました。 課題の完成例や、カエルを家に帰せをプレイして、ジャンプができたらスクロールの学習をし、最終的にプラットフォーマー系のゲームを作成することを目指して学習をしました。 物理系の話は好きなようで、放物線とは何か、という発問にも丁寧に答えてくれ、変数を使用して実際のジャンプのイメージに近づけることにも興味を持って取り組めていました。 課題が完成した途端にちょっとおふざけモードに入るのは寛太君の定番で、今日も残り時間は好きなアレンジを、と勧めたら、文字の弾幕などを作って楽しそうに遊んでいました。', null, '時間帯: その他
盛り上がり: スプライトのちょっとした動きなどを面白がるところがあるので、ジャンプのときの足のバタつき制御まで、終始楽しそうに作成していました。 そのあとのアレンジも、変な言葉を入れてはこちらの反応を面白がったりしていました。'),
  ('fd940456-1632-5286-9d2e-1fc71f904b1f', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-07', null, null, '通常 / 教室に慣れる、基本的なスキルの確認', '体験時にゲーム作成経験があり、基本的なシューティングゲームができていたので、今日はスキルチェックをすることを伝え、できたらスタンプを押していくことにしました。 やり始めは「簡単～」と言って、もっとすごいこともできるよ！という雰囲気も見せていましたが、スタンプが埋まっていくにつれて楽しくなってきたようでした。 基本操作コース02を終えた時点で、ご褒美に残り時間はゲームを作ってもOKとしたところ、「この表を全部うめたい！」となって、立て続けに04、06と進めて最後までできてしまいました！ 向きなどは、ブロックに表示されるやじるしを参考にしないとどちらがマイナスか迷うことがありましたが、座標の考え方などはそれなりにわかっているようですし、先走って進めてしまうことがあっても、完了してから「ほんとはどうやるの？」とカードの解答例を確認してこちらが教えることを聞くこともできていました。 矢印キーで上下左右へ動かすやり方は、ずっと条件分岐の方法で作っていたらしく、「○○キーが押されたとき」で動かすやり方を見て、かえって驚いていました。（それぞれのメリットは説明して納得していました）', null, '時間帯: その他
タイピング: 英文字はきちんと読めていて、画面に表示される大文字とキーボードの小文字との違いもある程度理解できていますが、小文字への対応に悩んで時間切れになってしまったりすると、癇癪の一歩手前、という様子を見せることがありました。キーっとなった気持ちを自分で抑えようとする努力もできていて、実際に爆発することはなかったですが、せかされるとできるものもできなくなり、自信やモチベーションに悪影響がありそうです。 せっかく文字は読めていて、打とうとする意志もありますが、やすのりくんが自信ありげにタイピングできることもあるせいか、既に少し苦手意識も持ち始めているようです。 英文字の個々の早打ちではなく、ローマ字が理解できかけていることを褒めて、ゆっくり確実にタイピングする方向で進めた方がよさそうです。 ご両親も、このような方針に賛成でした。
盛り上がり: プログラミングでは最後まで熱中して、本人にとっては簡単なことでも只管楽しそうに取り組んでいました。'),
  ('a7c7e1d9-4dda-56b2-a95d-70e3b43fdd19', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-10-13', '17:30:00', null, '通常 / プラットフォーマ―ゲームの基礎作り', '前までフォートナイト風ゲームをやっていたので、それに似たプラットフォーマ―ゲームの基礎を段階を踏んでいきました。等速、変数の使い方はすんなり行けたが、放物ジャンプはフォートナイトのゲームはコードが離れていたので、何が基本なのかあやふやなとこがありました。いじっていくうえで、どこで高さ制御するところは自力で見つけ出していました。 次に横スクロールところは、まずはノーヒントでやらせてみたが、全く手が動くことがなかったです。だが、図説してヒントを出してあげると、そこから自走してできました。こんな風にきっかけを出してあげれば進められるまで能力をつけているので、何回かやっていけば、さらに良くなると思います。', '横スクロールクローン', '盛り上がり: 時代はスイカゲームらしいです'),
  ('3cc2724e-4b59-5fd6-9012-441487e820bb', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-10-13', '18:40:00', null, '通常 / ⇒フォートナイト風ゲーム続き', '前回やったことをよく覚えていました。今日は壁と階段の挙動をプログラムすると自分で決め、時間いっぱい頑張っていました。一度プログラムを作った後や作る前に、プログラムの意味（落下、消える、スクロールなど）を一緒に考えたり声をかけたりしました。本人的にもじわじわ完成に近づいているところに達成感があるようです。敵の動きがまだなのでそろそろ取り組みたいところです。', null, 'タイピング: 基礎に取り組むことになりました。本番も来週なので集中して取り組んでいきたいです。'),
  ('8c59077c-3130-5600-af42-943dab67371d', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-10-13', '17:30:00', null, '通常 / ⇒タイピングコンテスト、参加するかしない【本人要確認】⇒【保護者へ要確認】 ⇒検定1級の応用問題 ⇒前回のは1級の中で一番簡単だったので、一気に応用やってみよう！と持ち掛けましょう', '1級応用課題4続き', null, 'タイピング: 1級応用課題4/アルスパーク'),
  ('25c659ae-aada-5bdb-a840-0338121403ec', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-10-13', '17:30:00', null, '通常 / 前回、単元別演習「F条件分岐 F-3玉を発射」の続き まずは、前回の復習 「もし●●なら」を学んでいる意識づけを', '前半20分、後半15分取り組みました。後半はかなりやりたくなさそうでした。 前回作ったものを確認してから取り組んだからか、「～に触れた」「もし」などの使い方はなんとなくできていました。一方で、動きのプログラム「～へ向く」「～秒で～へ行く」といったものは忘れていたようです。特に、秒数を変化させたときに早く動くと思ってしまっているようなので、これから何回か使って覚えてもらたいです。 また「ずっと」への意識も薄く、プログラムは言われて作ったら終わりと思っている様子です。自分で思っていてもなかなか行動に移しにくいのかなぁ。', null, 'タイピング: た行をやりました。最近伸ばし棒も打てるようになったと教えてくれました。よかったです。タイピングがそんなに嫌いじゃなくなったそうです。
盛り上がり: また逃げる恐竜をマウスの方へ動かしたいと言ってくれましたが（サメの記憶が強いのかな？）今回は場所のプログラムで動かしてもらいました。'),
  ('b946ded4-9d26-5386-9f33-44e26084c560', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-10-13', '17:30:00', null, '通常 / ⇒タイピングコンテスト、参加するかしない【本人要確認】⇒【保護者へ要確認】 ⇒前回の続き水泳PRGを見本のプログラムと見比べて取り組む', '見本のプログラムを見ながら取り組みました。最初進まない問題があったので、怪しそうな箇所（x座標、動きに関するプログラム）を探し、修正していました。制御のブロックの使い方や、演算のブロックにミスがあったようです。（YouTubeの動画が荒くて見づらかったと言っていました） 最後にゴールのメッセージを送ってゴールをプログラムしましたが、正確に動きませんでした。見本通りにできていて、メッセージをなくし工夫しましたが直りませんでした。本人的にも完成ということになりました。 本人はしっかり取り組めてかなり満足そうでした。', null, 'タイピング: タイピングコンクールがあることはお母さんに話してくれたそうです。「絶対受けなさい」と言われたそうです。'),
  ('f1ecc587-b044-5c48-8787-dc45392d184f', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-10-13', '16:30:00', null, '通常 / 検定3級①の答え合わせ＆見直し', '数字の入力ミスがありましたが、ほぼよくできていました。制御の部分で少し混乱してしまっている部分があったので問題を見ながら一緒に整理しました。分からない部分も回答を見ると理解できる様子でした。後半はアレンジに挑戦してもらいました。もとのプログラムを削除せず、追加する形でプログラムを考えてもらうようにお願いしました。 最後に、来週以降作るかもしれないプラットフォームセットのカエルのプログラムで遊んでもらいました。プログラム自体は好きではないようですが、ジャンプ、背景移動などのプログラムを勉強することは納得してくれました。（動画を見てゲームを作りたいらしい） 検定が好きなようで（クリエイティビティなくても取り組めるからって言ってた）、次週以降も検定問題に取り組みたいそうです。', null, 'タイピング: 集中して取り組めていました。パソコンのコンクールは出ない（出たくない）ようです。'),
  ('2816486d-60d6-5b3c-8663-7c313eb31884', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-10-13', '17:30:00', null, '通常 / 検定練習', '最初に、検定まで期間を説明して、まだ練習したいとのことだったので、検定問題をやりました。やっている最中に、問題文の②③をコードの中から探して悩んでしまうことがあったので、少し問題文の読み取りが上手くいっていない所がありました。問題文の地続きでコードをそのままもしの中に続いてしまうミスがありました。一緒に見直すと、うまくいかなかったところで、正解のブロックを持ってくると、「それだよ」とみてリアクションよく思い出すことがあったので、アウトプットがあともう少しところがあります。2匹目の魚は1匹目と似たようなコードだったのでそこは自力で治せました。全体的に検定は嫌になること少なく楽しめていると思う。', null, 'タイピング: 授業前にしっかりやっていました。
盛り上がり: みんなスイカゲームにはまっているようです'),
  ('0e120510-079d-5db7-8397-4246c0086d43', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-10-13', '16:30:00', null, '通常 / リストの理解', 'スキルアップのために、リストの動画を見てみました。リスト自体は、1回しか触れたことがなかったそうです。リストの基本の動画を見て、それぞれのブロックは自分でとりあえずいじって思えてみました。寄り道して、それなりに形あるものができていたので、各ブロックの理解はできていると思います。動画中のクイズの作る問題は2級で出てきた「聞いて待つ」のブロックもできたことから、さらに難しくなるやんとぼやいていたが、次回も含めてゆっくりやれば、なれるようになると思います。', null, 'タイピング: 英文に苦しんでいました。'),
  ('581f3f40-f3a0-5435-878c-92b2d3542bfb', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-10-13', '16:30:00', null, '通常 / ジャンプの区別や変数を知ろう', '基本操作コースのジャンプの仕方から変数に発展させて放物線ジャンプにつなげる形で進めていきました。変数を使って回数や上げ幅を変更する際にある場所ずつ変えていく必要がないことはこれは楽だ」とつぶやいていました。また、放物線ジャンプに関してはコードをまず見てもらいどうゆう風になっているか考えてもらいました。上がり幅が徐々に小さくなっていることを飲み込むのに時間がかかっていました。そのあとに、高さを変える際に正しく変更ができていたので、それなりにコード理解はできていたと思います。', null, 'タイピング: 準2級まで制してました'),
  ('7b00a44b-cd8e-5d3e-b2ae-b3fd7f6a2e42', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-12', '16:30:00', null, '通常 / 検定の問題形式に慣れる', '時間内に最後までいけたようですが、ムービーの動きと全然違ってしまったらしく、「むりだーーー」と連呼していました。 一つのスプライトに対し、問題の最初に「旗がおされたとき」と書いてある設問が2つある問題が初めてだったらしく、2つのコードにわけるところを一つに続けていたのが原因でした。 問題文の最初に「旗がおされたとき」と書いてある場合と、「①の続き」と書いてある場合で作成するスクリプトが変わることを説明し、問題文は最初から最後まで見落とさないで全部読むことを教えたら、素直に納得していました。その後の問題も自分で読み直して、「なるほどー」と感心していました。 答え合わせの前は、自信をなくしかけていたようですが、こうやっていろいろなパターンの問題をやれば、次は覚えているからできるはず、と話したら、「いろんな問題をやってみる」と前向きになってくれました。', null, 'タイピング: もう2、3点で7級というところまでいけて、嬉しくもあり、悔しくもあり…という感じでした。
盛り上がり: まだ問題の形式に慣れていない部分もありますが、納得して解決できたので、満足げにしていました。タイピングも検定も、前向きに取り組めています！'),
  ('f7dd0a1d-797a-51e0-964c-285b9c5f3c4f', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-10-12', '17:30:00', null, '通常 / リストの理解', 'リストの各ブロックの使い方に関して、動画の一回の説明だけで、すんなり理解できていました。クイズの複数問題に対してもコードの省略化も、複製なし方法で考えてもらったが、最初にリストを1問ずつ消すしていく動画にない方法も生み出していました。変数使ってみてと提案したら、自力で作り直すことができました。何回繰り返すのところもリストの長さになることも自力で修正できていたので、応用力は効いていました。そのあとの定義を使って直すところでは、定義はまだ習っていなかったが、動画だけで定義の何となくの使い方を理解はできていました。そんな感じだったので、定義は機能の集約と見やすさの重視の軽い説明を加えてあげました。', null, 'タイピング: ほどほどにできていました。
盛り上がり: みんなスイカゲームは待っているそうです'),
  ('41b421fa-6f88-574c-ad78-f1e5afbc3206', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, null, '2023-10-12', '17:30:00', null, '休み（未対象）', null, null, null),
  ('0da1839c-9708-5126-8e69-ff5b45e7213a', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-10-12', '17:30:00', null, '通常 / リストを覚えよう', '承太郎君とともに、リストのついての説明で頭にいっぱいいっぱいになっていたので、間に解説しながら、直感的にわかるように補完していきました。クイズの問題を作るところでは、動画を見ながら作り、リストでは最初に全削除する必要性、番目と含む場所の違いをは何となく理解はできていたと思います。本人も難しく感じていたので、次使うときのきっかけが通りやすくなればいいと思います。', null, null),
  ('c26019d0-f7c4-59ca-ac78-f209f17e672a', '57f45872-1f3e-5540-b676-bf9023444e39', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-10-12', '16:30:00', null, '通常 / ピンポンゲームの作成', 'ピンポンゲームは、学校で友達とやったことがあるらしいので、動きの読み取りがスムーズにいきました。今まで見てまねるが多かったので、アウトプットを優先させてやっては見ましたが、前に進むようにしてといっても、どのコードを選べばいいか悩んでいました。逆に何歩動くのブロックを持ってきてこの意味は何と尋ねるとちゃんと答えられることはできるのですが。あと、コードを作っているときにあっているかどうか1ブロックごとに顔をうかがってきます。さすがに頻度が多いので、自分を信じて試してみることも大事だよ伝わってほしいです。途中鼻血がでたこともあって、赤線触れたら止まるところまで終わました。', null, 'タイピング: 評価Aが続いていました
盛り上がり: 野球で八王子市で一番強いチームと戦ったそうです。'),
  ('4e3ffe45-739e-5365-9942-c5532c5bdceb', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-10', null, null, '通常 / 引数を複数使った定義や、「割ったあまり」の演算を使いこなせるようになる', '今日も、なぜこの教材をやってほしいのか説明するところから始めました。 教材を見せたところ、やったことがある気がする、と言ってアルスタジオの履歴を確認していましたが、見当たらなかったそうなので、復習も兼ねて取り組んでもらいました。 途中までは自力で作成していましたが、動画があることを伝えると、一応用意してほしいとのことでした。作成中、悩んだ際には参考にちらちらみていたようでしたが、40分くらいで完成させていた。心配した引数の当たりなども含め、特に質問しなければわからないようなところもないとのことでした。', null, '時間帯: その他
盛り上がり: とても久しぶりに、2週連続してScratchの教材でのプログラミングになりましたが、スッキリした感じで終えていました。 完成後はフリータイムにしたら、自主的にチエテラスを開いて問題を解いていたので、こちらは本当に好きなのかも。'),
  ('6a5d4253-c400-5a1a-a114-3aeb9b1c97c7', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-10', '16:30:00', null, '通常 / 細分化をしてスプライトの動きを読み取る', 'だるまさんがころんだとはどんな遊びかということを、まず細分化してから、ゲームをプレイしてもらいました。 細分化には、こちらの誘導や発問が必要でしたが、一度細分化ができてからの個々のスクリプトは、ほぼ自分でできていました。 祥太君にとっては少し難しい教材だったので、細分化は一緒にしないと困惑モードになっていましたが、一つ一つのパーツをきちんと作ることを意識して取り組めたと思います。ブロックもよく覚えていて、コスチューム番号での判定なども自力でできていました。 終了8分前くらいに完成させることができました。', null, 'タイピング: タイピングはあまり気乗りがしないそうです…
盛り上がり: 難しい作品を完成させることができ、思い通りの動きにすることもできたので嬉しそうにしていましたが、お迎えのお父さんの顔を見たとたんに、少し疲れた、という表情をしていました。'),
  ('8021850f-64dc-5138-af07-7cc9e22931cd', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-10', '16:30:00', null, '通常 / プラットフォーマー系ゲームを作ることを目的に、ジャンプとスクロールのスキル習得', '楽しそうに作っていましたが、イメージからコードに置きかえることはまだ苦手なようです。どういう動きを作りたいかというイメージがあっても、すぐに「どうするの？」と作業が止まり、基本操作コースのカードや参考になる作品がないと、先に進めるのがきつそうな様子でした。過去のこの教材のここでやった、とアドバイスすると、思い出すことはできるのですが…。', null, '盛り上がり: 自分でイメージからコードを作成することには苦労していましたが、それでも腐らずに前向きに取り組む姿勢は評価できるものだと思います。 スクロールができたときは、とても嬉しそうでした。'),
  ('7c0a926f-9cb7-55a9-a328-2a0962e2c3a4', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-05', '17:30:00', null, '通常 / 検定問題に挑戦', '前回の2級受験が1点及ばずだったため、受験の勧めも慎重にしてみましたが、かなりあっさりと「またやります」との返事でした。 一応時間内に最後まで取り組めたようですが、バグの見直しができずに、動きは不完全でした。 最小単位の問題はできているのですが、コードを入れる場所が違ったり、条件部分を入れていなかったり、条件分岐が入る場所がずれていたりという、全体の構成への不注意部分が多く見られました。', '見直しをしながら、問題の読み方の再確認を', 'タイピング: 前回の記録は超えたいようで、がんばっていました
盛り上がり: 検定に前向きな姿勢はとても良いと思われます！ 由希ちゃん自身も、難しいとは言いつつも、最後まであきらめないでがんばっていました。'),
  ('cfa12fbd-7e69-5c9b-917e-bee8dad71bee', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-10-10', '17:30:00', null, '通常 / 検定問題4級②', 'キャラクターの動きが少し歪になっていましたが、ケアレスミスで起きていたので問題文をよく読んでいくことが重要だと感じました。そして、スプライトの他のスクリプトを止めるというブロックの意味をあまり理解できていなかったので、教えたところすぐに理解をすることが出来ていました。', null, 'タイピング: ミスをすることがほとんどなく打てていたので、今後は速度を上げていく方を重視していった方が良いと思います。
盛り上がり: 作品完成後のアレンジをしている際には、自分のやりたいことをしっかりと作品の中に取り入れる頃ができていて、かなり楽しんで作成していました。'),
  ('150439cf-2459-560b-9047-598d19095a2e', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-05', '17:30:00', null, '通常 / 定義や論理演算式を活用したゲーム作り', 'スラスラできる部分と、何これ難しい、とぼやく部分があったようでした。 最近は文字PVでスプライトを複雑に動かすことが多かったですが、このような単純なスクロールは久しぶりだったせいか、座標の計算式にしばらく考え込む様子も見られました。ただ、悩んでもヒントまでは必要ではなかったようで、スプライトを使ったスクロールまでは完成させることができていました。', 'ネコの動きから 続き作成', '盛り上がり: ゲームっぽいゲームを作るのは久しぶりだったせいか、それなりに集中して頑張れていたと思います。'),
  ('0c572c1b-4d63-5099-b4f1-737aaa78fe1c', '7d01236e-620e-5177-a6f4-af325a582aae', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-10-10', '16:30:00', null, '通常 / 検定問題4級②', '基本的には正解でしたが、このスプライトの他のスクリプトを止めるというプログラムの内容についてあまり理解できていなかったらしいので、その箇所については間違っていましたが、それ以外の部分については完璧に作成することが出来ていたので、次回以降は完璧に作成することができると思います。', null, 'タイピング: かなり早い速度でタイピングをすることが出来ていました。ミスもそれほど多くなく打てていたので、その数少ないミスをなくすことさえできれば完璧に打つことができると思います。
盛り上がり: 自分の間違えていた箇所を知ることが出来た際には、どうして見本の動画と違うのかを理解することが出来ていたので、とても納得していました。'),
  ('60c29c7f-a18d-554c-bf3a-798f44bd3d61', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-10-10', '16:30:00', null, '通常 / 検定問題4級②', '検定問題をやっていきましたが、問題文をよく読んでいなくて見逃した箇所が一箇所あったのと、スクリプトを間違って消してしまっていたので、そのようなケアレスミスをなくすことが出来れば、４級程度の内容であれば完璧に作成することができると感じました。', null, 'タイピング: スピードはゆっくりでしたが、間違っている箇所がかなり少なく基礎的な部分はできていると感じました。なので、手の配置や単純な速度アップをしていくとさらに伸びていくと感じました。
盛り上がり: アレンジをしている際はプログラムが完成されているので、自分のやりたいことを作品に落とし込むことが出来ていて、満足していました。'),
  ('4e11075a-4f89-550b-b274-b49d39753c0b', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-10-10', '16:30:00', null, '通常 / 3-1_簡単クイズの続き', '前回から作成している簡単クイズの続きを作成しましたが、プログラムの作成に苦戦しているというよりは、タイピングに苦戦している様子だったので五十音表を見ずにタイピングが出来るようになると、さらに成長することができるのではないかと感じました。', null, 'タイピング: 画面上に打つべきアルファベットが表示されているので、練習に関してはそれほど問題はないと感じました。しかし、実際に文章を作成するとなると五十音表が必要となっているので、五十音を覚えることができれば一気に伸びるのではないかと感じました。
盛り上がり: 問題の作成はかなり悩んで作っていました。より良い問題を作成しようと頑張っていたので、自分の作りたい問題を作れたと思います。
備考: 授業の開始時に5分〜10分タイピングをやると約束しました。'),
  ('36960cc8-5571-5a43-9c27-c59fa64a0107', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-05', '16:30:00', null, '通常 / ジャンプのコードを習得する', 'コンテストのために未履修だったジャンプに取りかかりましたが、基本操作コースの内容だけだと学年的にももったないので、等速ジャンプや変数を使うジャンプを学習しました。少し難しいと感じたところもあったようですが、高さと回数を変数にするジャンプを完成させることはできました。 そのあとは、少し疲れたのか、脱線してジャンプするときの動きに画像効果を付け足して面白がっていました。', null, 'タイピング: ローマ字、ホームポジション基礎を試してみましたが、もともと好きそうではないところに、結果が良くないのも自覚できる年齢なので…コンテスト参加は見送り、検定が終わってから少しずつチャレンジしていければよいかと。ゲームを作る熱意はあるので、そちら側からモチベーションを高めていければ。プログラミングのときはゆっくり考えて打つので、早打ち系のタイピングソフトは向いていないかも。
盛り上がり: ジャンプを作成できたことも嬉しかったとは思いますが、その後の画像効果をひたすら試すところが、今日で一番楽しそうな雰囲気でした。'),
  ('c880e961-d8a5-5934-aa0b-6af05ba5f300', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-10-07', null, null, '通常 / 作りたいゲームの構想', '始まってもずっとゲームを遊んでいたので、マイペースで今日はイチゴの反乱を作りたいとことでした。クローンとかまだ習っていないので、話題そらしにどんなゲームを作ってみたの？と聞いてみたところ、意気揚々と話してくれました。全部は把握しきれていないがやりたいことを書いておきます。 「タッチでカービィスーパーレインボー」のボス戦のところを作ってみたいそうです。 参考動画、https://www.youtube.com/watch?v=tYpHFcWxclY&t=38s 敵は「クラッコ」という雲の形の敵で、その攻撃パターンとして、弾幕の攻撃を入れたいそうです。2段階深化で、そこでステージも変わる。 参考動画、https://www.youtube.com/watch?v=aG0tIl0zR9、 ほかにも、ワドルディなどのモブキャラや爆弾攻撃、HPバー、も出したいそうです。操作は、虹色のペンを描いて動かしたり、攻撃を防いだりするそうです。 全部を再現するのは、むずいので、妥協ラインを否定しない程度に進める必要があると思います。これ作るために、既存教材をやる必要があるよと写経でもうまく進められたらいいと思います。それで、こう活かせるとなればいいけど、 絵は完成できたぽいです。', '作りやすいバグ弾攻撃や虹の', '時間帯: その他'),
  ('ca4cb453-e6bc-5d6f-94a5-f3117bb70c7d', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-10-07', null, null, '通常 / 検定練習', '今回も時間が足りず、赤玉の動きで時間切れでした。分を1文ずつ線引きながらやっていたので、コードをしっかりできていました。はるくんももしの後に続くコードがもしの内側に続いてしまっていました。本人は中か外か迷っていたらしいので、検定問題にこのような書き方が多いことを説明してあげました。', null, '時間帯: その他'),
  ('5111455b-6c0f-515f-b444-ae7934611be2', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-10-07', null, null, '通常 / 検定練習', '問題を解いてもらったところ、5分くらい余裕を持って終わりました。答え合わせをすると全て完璧にできていました。リストの扱いやネストの階層が複雑な所など難しいポイントがありましたが、理解できていると思います。', '検定練習', '時間帯: その他
盛り上がり: 淡々と集中して進めていました。'),
  ('b38c8384-290e-5cf5-a7a1-60453c0e33d7', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-10-07', null, null, '振替 / 検定練習', '今日は通常レッスンに決勝大会の振り替えを追加して2時間行いました。 前半は問題①の答え合わせをしました。「バグってるところがある」と言っていたので、問題文をたどれば原因がわかるよと伝えて始めました。ミスしたところは2か所あり、ブロックの置き場所の間違いと「ずっと」ブロックの忘れでした。集中すればなくせるミスなので問題をしっかり読むことを促しました。話を聞くと、国語が苦手で文章を厳密に理解することには抵抗があるとのことです。ただ、合格するのには問題ない範囲だと思います。 後半はちひろくんと一緒に問題②を解きました。わからないところがあったようですが、印をつけて飛ばし、あとで戻ってくるなどうまくやっていました。解き終わるところまでは良かったですが、残りの時間で答え合わせをしようとするとロブロックスを始めてしまいました。', '問題②の答え合わせ', '時間帯: その他
盛り上がり: 問題を解いているときは真剣にやっています'),
  ('2dd66bea-0010-5919-a91c-1490a29c4cdf', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-10-07', null, null, '通常 / 基本操作コース＿２ オリジナル作品制作', '基礎がしっかりとしていることもあり、基本操作コースに関してはつまづくことは全くなく、完璧にこなすことが出来ていました。自分のオリジナル作品に関しては、事前にやりたいことをノートに書いてきて事前にやりたいことが決まったいたので、スムーズに制作を進めることが出来ました。次に来る時までに、ノートにやりたいことを新たに書いてきてくれると言っていました。', null, '時間帯: その他
盛り上がり: オリジナル作品の制作で、基礎的な力がかなりあるので幅広いことを取り入れようと様々なことを試しながら、ノートに書いてあることと照らし合わせて製作していき、納得のいくものが出来ていくことに満足していました。'),
  ('fd75b166-f54e-5839-8785-eeeb6f81eb70', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-10-07', null, null, '通常 / 検定練習', '時間をフルに使って、問題文をすべて解き終えていました。見直す時間がなかったので、ドラゴンが端についても消えないバグが残っていました。順に動作するで、もしの後のコードが外に作らず、中に続いて作ってしまうよくあるミスの1つだけでした。本人の手ごたえはドラゴンのコードを作るのが難しかったといっていたが、この程度の出来栄えだと安心してお飲めると思います。', null, '時間帯: その他
タイピング: 4級程度まで進めていました。
盛り上がり: バグが解消された時の驚きは達成感あるものでした。'),
  ('b793a4e5-f3d7-5528-a3f3-2d59656c4a1e', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-10-07', null, null, '通常 / 検定問題３級①', '今回初めての３級問題でしたが、時間内にアレンジまですることができ、ミスをすることなく完成させることができていました。内容の理解も完璧にできており、アレンジもコードを追加してさらに複雑なものへとすることが出来ていたので、初めての３級問題で素晴らしい出来を見せてくれました。', null, '時間帯: その他
盛り上がり: 答え合わせの際に自分ができていることを確認していたので、自分はこの問題はできるのだということで、自信につながったと思います。'),
  ('da3f0782-1cb2-5d10-b24f-6defada697d0', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-10-07', null, null, '通常 / 検定練習', '4級をやり、行うスピードは速くて、今回はミスがなくてよかったです。ただ、解き終えた瞬間、スクラッチの画面に戻ろうとしたので、どんなに出来が良くても見直す癖はつけた方がいいと思います。', null, '時間帯: その他
タイピング: ミスをためたくないので、あまりやってくれませんでした
盛り上がり: とても速さは良いです。'),
  ('e6e49672-ab32-5b5f-bba5-317e7cbd755a', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-10-07', null, null, '通常 / 検定問題4級17', '検定問題は時間ちょうどに終わり、アレンジをする時間はなかったようです。問題は間違っている箇所はなかったので、問題自体は４級の中でも難しい部類ではあったため、ミスすることなく完成させることができたのは大きいと思います。', null, '時間帯: その他
盛り上がり: ミスをせずに出来たということで、自分の実力を知ることができていてさらに自信をつけていました。'),
  ('84557a69-863e-5630-9c0a-2cc52a3c0295', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-10-02', '17:30:00', null, '通常 / 検定問題三級⑳', '今回取り組んでいた三級の問題では、時間内にほとんどの箇所を手順通りにこなすことができていました。そうでなければの処理の部分が複雑であったため、少しつまづいていました。しかし、慎重に問題を読み直しながら解いた結果、自分ひとりの力で解決することができていました。', null, '盛り上がり: 自分で疑問を解決できていたので、達成感をすごく感じていました。試行錯誤を重ねて正解を導き出すことができるので、プログラミングというものに向いていると感じました。'),
  ('9e82cb60-55d3-513a-9dc6-8e870196a6e4', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-10-06', '18:40:00', null, '通常 / フォートナイト写経（定義の意味を確認しながら）', '定義を多くつかっているプログラムなので、最初に定義の役割について説明しました。プログラムが見やすくなっていることが大きなメリットですが、あまりピンとこなかったようです。前回の振り返りから行いました。ミスがあったので修正していました。 『見本を見てもいいけど、内容を確認して見直しして丁寧にやる（？）ことを先生と約束した』と伝えてくれました！えらい！！今日も文字入力もあきらめることなくプログラムしていました。 おじさんのプログラム、おじさんの弾、背景1を作っていました。重力が働く様子を最後に一緒に確認しました。', null, 'タイピング: まだローマ字入力に自信がない様子なので、ホームポジに挑戦してもらいました。応用と基礎の両方に取り組んでもらいましたが、基礎の方がよいそうです。'),
  ('6b488a43-b4f8-5861-bf71-bc89610d4280', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-10-06', '17:30:00', null, '通常 / 検定4級② 前回、初めて検定にチャレンジし難しかったと。なれるために、2回目の検定。その際、一文一文線をひく方法をおさらいしておいて', 'プログラムした文章を線で引くように伝えましたが、実際に引いたのは一文目だけでした（笑）時間は終わっていませんでしたが頭を抱えて悩んでいたので、見直しのポイント（制御のブロック）や怪しい箇所の探し方（どのスプライトの動き・見ためなのか）を共有しました。制御のブロックミスは自分で気が付くことができました。プログラムを止めるためのブロックの作り方はバッチリでした。問題文中にある「ずっと、繰り返し」とずっとのブロックの意味がリンクせず、悩んでいました。 残り時間で最後にアレンジにも挑戦してもらいました。アレンジのポイント（既存のプログラムに追加するアレンジ、色を変えるなどの方法）も説明しました。 自分が苦手な部分（制御）をしっかり自分で把握できていました。すごい！ 答え合わせまで終わっています。', null, null),
  ('b8ac6fb7-535c-56c4-a460-a84769c71fae', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-10-06', '17:30:00', null, '通常 / ・マイパソ（小学校高学年和文） ・前回お休み、その前が「prg水泳」、その前が検定3級 ・水泳が途中なので、前回の復習してから続きが良いか ⇒続きやりたいそうなので続き', '来てすぐに「続きを作りたい！」とリクエストがありました。動画を見て取り組めていました。スプライトがうまく前に進まないこともありましたが、自分で関連している変数を考え怪しそうな箇所を発見し、動画をみて修正することができていました。浮いてしまう現象も同様に考えて取り組めているのですごいです。 動画を一通り見ましたが見本通りに動かないので、次回は見本のプログラムと見比べつつ、怪しそうな箇所を考えつつ、完成させたいです。', '水泳PRGを見本のプログラムと見比べて取り組む', 'タイピング: 少し苦戦している様子でした。短い時間だけ取り組みました。'),
  ('d8745875-815c-5431-9c4f-6156d58fdc1f', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-10-06', '17:30:00', null, '振替 / スキルアップ', '前回Scratchの「【Prg】51どこまでいけるか」で縦スクロールゲームを作り、その流れでScratchの発展形をやるか、テキストコードをやるか聞いたら、即答テキストコードでした。Scratchはもう、すっかり飽きたのかもしれませんが。 monacaのJavascriptの第４章「変数」で今日の日付、年などの文法をやりました。きちんと仕上がったのですが難しい（10段階でいうと6難しいと）ということだったので。HTMLに戻りました。 monaca第2章P29～35をやりました。', '次回はそのままCSSの第３章をやるといいかなと思います。 その後は、Scratchの「【Prg】47 しゅんかんきおく順番当てゲーム」→演算、プログラミングらしい難しい単元 （テキスト参照）をやってもいいかな。', 'タイピング: 省略
盛り上がり: 次回の予定参照'),
  ('8930561a-3441-5202-8fea-88ba2fb75a95', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-10-02', '17:30:00', null, '通常 / 条件分岐について', '今回のメインである条件分岐については、これがあったらこの処理が起きるという内容についても理解することができていたと思います。自分でゲームを作成して、そのゲームが完成するという目標や、あといくつや何分で終わるかなど明確なゴールを設定してあげればより集中して取り組んでいけるのではないかと感じました。', null, '盛り上がり: 自分で決めた目標を達成したということを、休憩している時間で実感していました。自分の興味のあることには集中して取り組んでいました。'),
  ('77400008-2800-587f-9cdc-08005a2c7ca1', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-10-06', '16:30:00', null, '通常 / ・検定3級①の問題 前回4級の問題が楽々だったので、一度3級を試してみようと 「前回4級やったけど、楽々だったので飛び級して3級やろうか」と話してみてください。 3級は使うブロックが多いので、なるべくたくさんの問題をやった方がいいよ、という話をしてあげてください。', '集中して取り組めていました。時間がなかったので特に分からなかった部分の確認をしました。「かつ」の意味が分からなかったようなのでもう一度説明をし、プログラムしなおしてもらいました。条件分岐が比較的丁寧にできているようですが、乱数とまざると分からなくなってしまうようです。 来週答え合わせをする予定です。', '検定3級①の答え合わせ', 'タイピング: 集中して取り組めていました。得点は52点ほどでした。'),
  ('3385611c-44a0-5f92-b85d-179ddb78ec90', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-10-06', '16:30:00', null, '通常 / 検定3級①', '今日は本人からスプラトゥーン風のゲームが飽きてしまったから次回取り組みたいと申し出があったので、今日は検定3級①に練習として取り組みました。（忙しい日と検定実施日が被ることはない様子です？） 時間がほぼなかったので答え合わせは終わっていませんが、答えと見比べてさらっと内容を確認しました。明らかな間違えはないようですが、検定独自の書き方やプログラム順序にミスがありそうです。 来週丁寧に確認したいです。', '検定3級①の答え合わせ、見直し', 'タイピング: 去年は忙しかったため受けていません。練習として取り組みました。'),
  ('6cf12ac3-5ab4-5afe-b915-59b77bb884b3', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-10-02', '16:30:00', null, '通常 / 検定問題四級⑰', '今回やった検定問題は、四級の内容だったので理解はすぐにすることができていました。しかし、問題文をよく読まずに作っていたので結果的に、かなり間違っている箇所が見受けられました。なので、問題文をちゃんと読みながらやっていけば四級の内容はすぐにでも完璧にすることができると思います。', null, 'タイピング: ローマ字のタイピングで、それなりの速さで打つことができていました。タイプミスが少し目立つ箇所があったので、より正確にタイピングができるようになればさらに点数を伸ばすことができると思います。
盛り上がり: 自分がなぜ、どのように間違っているのかを理解するとすぐに修正して正しいプログラムを組むことができていて、自分の間違いに納得していました。'),
  ('f1c58456-a78b-5bbd-99cc-1adb6dd38e78', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-10-02', '16:30:00', null, '通常 / 検定問題二級③', '今回挑戦した二級の問題は、二級という事もあってそれなりに難しい問題ではありましたが、時間内に指示通り完璧に仕上げることができていたので次回からの問題も解いていけると感じました。しかし、苦手な分野を取り扱っている問題の場合はつまづく可能性もあるので、その際に重点的に見直していくのが良いと思います。', null, 'タイピング: タイプミスをすることが非常に少なく、正答率はとても高いです。結果も準一級とかなり高い結果を叩き出していました。本人は速さよりも正確性を重視してのタイピングでしたので、今後もこの調子でやっていけばさらに伸びていくと思いました。
盛り上がり: 時間内に完成できたので、お手本の動画と見比べてみて間違っている箇所がなかった時はちゃんとできたことを実感していました。'),
  ('d427004f-7e8e-5ed4-b980-ab903ba5a9c8', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-09-29', '17:30:00', null, '通常 / ジャンプの方法を学ぼう', '新しい単元として、ジャンプの項目をやりました。ジャンプはy座標が上がって下がることは理解できていましたが、上がった分下がる必要があることに理解があやふやでした。かずまくんにはよくやることだが、1動作できるとそれで遊び続けてしまうことが今日は特に長めでした。地面に埋もれてしまうことは特に気にしてなかったので、スルーしました。何度かやった触れる判定は時間はかけて自力で作れていました。ゴールまではなんとか作り終えました', null, 'タイピング: 高ランクが多かったです'),
  ('56eb9e47-ce63-5a68-b799-69226bbbe89a', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '95364df8-51b5-55ec-b4db-d1ebfc449f4c', '2023-10-05', '16:30:00', null, '通常 / プラットフォーマ―ゲームの作成', 'プラットフォーマゲームに近づけるため、今回はスクロールの方法をやりました。メッセージとクローンの方法があったが、メッセージ法で自分で選んで自覚をもってそのコードが作れていました。特に迷いもなくそのステージを作りこんでいたので、問題はないと思います。ジャンプに関しては、まだ党則ジャンプのままだったので、次回、放物線ジャンプを変えるべきだと思います。最後の方に、ステージの足場の当たり判定で悩んでいたので、そこもアドバイスお願いします。足場と足場の間に落ちたら、左に押し流されるようにしたいそうです。', '放物ジャンプへの変更 ステージ足場の当たり判定', 'タイピング: ミス0が多くて素晴らしいです
盛り上がり: 真剣に取り組んでいました'),
  ('1634dc90-6aee-54c2-a960-ad9cc8dfb149', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-05', '16:30:00', null, '通常 / 検定問題にチャレンジ', 'タイピングで気分が盛り上がったまま、検定の方にも喜んでチャレンジしていました。「文章題は得意！」とのことで、問題を楽しそうに読んでいました。 小問の番号表記がa.b.になったりするのが初めて見たようで、少し混乱も見られましたが、解き方を教えると素直にできていました。 たまに気分が盛り上がって、先走ることもありましたが、「問題にヒントが全部書いてある」と何度か伝えると、コツをつかめたようでした。', null, 'タイピング: 初めてホームポジション基礎をやってみましたが、9級～7級一歩手前あたりまでできていたので、受験をおすすめしました。本人も「7級を取る！」と頑張っていました。
盛り上がり: タイピングも検定も、とても意欲的に取り組んでいました！ こちらから受験の声掛けをしたのも嬉しかったようでした。'),
  ('57a9fe64-fb70-5572-91e7-121135f00516', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '8e5e25f2-453f-5e44-86ae-ae60cddee3d4', '2023-10-05', '17:30:00', null, '通常', '最初は、アルスパークにあるゲームを遊んで、少しアレンジしてゲームの難易度を変えて遊んでいました。そのあと、ボールキャッチを黙々と作成し、音やリンゴの位置の変化もしてゲームをうまく遊んで楽しめていました。', null, '盛り上がり: 簡単にさせるアレンジでコードを見分けられた板野がすごい'),
  ('6da0697a-8dc1-5ef2-8619-a64c45df050e', '57f45872-1f3e-5540-b676-bf9023444e39', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-10-05', '16:30:00', null, '通常 / 色判定やコードの並び方の意味を理解しよう', 'このイライラ迷路はコードとしては簡単だが、色に関することに補足事項がたくさんあるので、新たな発見になったと思いました。コードが別のスプライトに作っていたので、移動させる際に、ぐちゃぐちゃになっていたので、作ったコードを再確認しました。コードが上から下へ進むことに慣れてなくて再構築にヒントを出して時間をかけて作れました。あと、それぞれのブロックの意味があやふやな感じするので、毎度確認しながら作っていけばいいと思います。', null, 'タイピング: 集中してやっていました。'),
  ('eb29b832-dc09-59cc-a071-e30838c16b1a', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-03', '17:30:00', null, '通常 / 検定問題に慣れる', '問題自体はスラスラと解いていて、半分ほどの時間で最後までいけたようですが、その後しばらく、動きがおかしいと悩んでいました。 答え合わせを一緒にしてみると、「○○に触れるまで繰り返し」をすべて、「ずっと、もし○○に触れたなら」で作成していたため、問題文が最大のヒントであり、「○○まで繰り返し」と「ずっと、繰り返し」の使い分けは問題文に明記されていることを伝えました。 そこを確認したところ、該当2か所をすぐに自分で直すことができ、アレンジや記述もできていました。 問題自体は簡単だったようなので、今回のような問題文の記載に慣れるためにもう１、2回4級問題をやって、簡単すぎるようなら3級をお試ししてもよいかも、と提案したところ、嬉しそうな様子を見せていました。', null, 'タイピング: 少しやってみましたが、こちらはあまり得意ではないようで、やる気もイマイチかと思われます。
盛り上がり: 初めての問題に少しとまどうところもありましたが、繰り返しブロック以外は余裕でできたようで、アレンジも音楽などに凝るいつもの余裕をみせてくれていました。 お母さんに報告しているときも、お母さんにからまりながら、少し嬉しそうに、得意げにしていました。'),
  ('cc30d13a-6a35-506a-80cd-16a62b0f138b', '7d01236e-620e-5177-a6f4-af325a582aae', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-03', '17:30:00', null, '通常 / 検定問題に慣れる', '検定とはどのようなものか、という説明だけで、あとは黙々と解いていましたが、終了10分前くらいに手をあげてきて、少し混乱してきたというので答え合わせを一緒にしました。 大きさやコスチュームをブロックではなく直接変更していたので、問題文にあるものはすべてブロックで作成することを伝えました。 すべては問題文の通りに、順番を変えないこと、という注意をしたところ、おかしくなっていた箇所もすべて自分でスラスラと直すことができ、アレンジもできていました。', null, 'タイピング: チャレンジする意欲もあり、がんばっていました。
盛り上がり: 問題文通りに直していく過程でとても納得がいったのか、終わった時はスッキリした表情をしていました。お父さんにお話した際も、タイピングも検定も頑張ってみる、という感じでした。
備考: 検定のチラシがなくなってしまったので、お父さんのご要望で、LINEでサーティファイ該当ページのリンクをお送りしました。'),
  ('e7253bbc-c2b2-5a1c-b2a0-e77d6f472d89', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-03', '17:30:00', null, '通常 / 検定問題に慣れる', '選抜大会の感想などを最初に少しヒアリングしました。キャラクターの表情を場面によって変えるなど、最後までこだわりをもって仕上げられたようです。 タイピング練習の後、本人の「チャレンジしてみる」という宣言によって検定問題に取り組みましたが、試験時間が長かったせいもあるのか、途中2回くらい、とても疲れたようなそぶりをしていました。 試験時間終了とお迎え時間がほぼ同時でしたが、「きつかった」との感想でした。 振り返りは次回になりますが、様子によっては本人の意向を確認しつつ進めてもいいかもしれません。', '検定の振り返り。きつそうなら、応用課題を一度一緒に解いてみたりしてもよいかもしれません。', 'タイピング: ローマ字に取り組んでいました。上位の級はねらえそうです。
盛り上がり: 選抜大会の話や、親子大会の最終選考ノミネートの話は生き生きとしてくれましたが、検定ではかなり疲れたようでした…。'),
  ('920d3680-67f0-5fec-9022-abe8c8609061', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-10-02', '17:30:00', null, '通常 / スプラトゥーン風オリジナルゲームの作成 続き', '前回まで作成していたオリジナルゲームの続きとして、キャラクターの状態を複数作成や潜伏状態をできるようにプログラムを組んでいました。進捗のもそれなりに進んできており、作品の基礎となる部分をかなり完成させてきています。残りとしては、基礎部分が少しとグラフィックにこだわっているようなので、その部分をより納得のいくように仕上げていくと思います。', null, '盛り上がり: キャラクターの動きに関して試行錯誤していましたが、今回の作成で悩んでいた部分もかなり解決されたようなので、次回からの作成も張り切っていました。'),
  ('a7f6f9d4-7ed1-55bb-8658-3b96cc275a05', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-10-02', null, null, '通常 / 【Prg】51 どこまでいける？ネコのお散歩ゲームの作成', '基本的にはお手本の動画を視聴しながら作成をしていました。終始つまづいている様子もなく、順調に作成していました。今回の作成で、scratchのほとんどを完璧にできているのではないかと感じました。自分のやることに集中していたので、自己解決の力が強いのだろうと感じました。', null, '時間帯: その他
盛り上がり: 自分ひとりでプログラムを完成までさせていたので、基本的には悩むこともなくスラスラと出来ていたので、しっかりと出来ていました。'),
  ('0ba33881-5efd-5b8d-8ec3-193b7c43494f', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-03', '16:30:00', null, '通常 / 検定問題に慣れる', 'タイピングも検定も、どちらも説明するとすぐに「やってみる！」と前向きでした。 文章を読んでその通りにコードを作成していくという作業が、自分でゼロから考えるよりもやりやすかったらしく、楽しそうに進めていました。 あまり使ったことのない「止める」ブロックの3種類の違いや、「○○までくりかえす」ブロックについては若干の説明を入れましたが、ほぼ自力で時間内にできていました。 ①が終わって答え合わせをしてからすぐに、②もやってみると申し出るほど、乗り気で頑張っていました。', '検定問題②を、残り10分ほどで。そのあと答え合わせ。', 'タイピング: ゆっくりではありますが、ミスなく打てることもあるためか、初挑戦で9級相当でした。もう少しで8級レベルです。
盛り上がり: 検定問題は性に合ったようで、終始楽しそうに、熱心にがんばっていました。
備考: お迎えのお父さんにも様子を話したところ、少し驚いたようでしたが、検定日をチェックして帰られました。'),
  ('a50f6e6b-6bf2-563b-9a42-f713e0a99ec4', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-10-02', '16:30:00', null, '通常 / アイスを食べにの続き', '前回から作成している作品のアレンジの続きで、アルくんが敵に当たった際に別のコスチュームへと変化するプログラムを組んでいました。自分のやりたいことがはっきりとしていたので、完成は早くすることができました。少し次の作品も取り掛かっており、オリジナル要素を取り入れていました。', null, 'タイピング: 濁音の入ったものを重点的に挑戦していました。速さと正確性はそれなりにあったので、正しい指の配置を意識していけばさらに伸びると思います。
盛り上がり: やりたいことが実際にプログラムを直してできるようになったという実感は、しっかりと感じることができていたと思います。'),
  ('72d934ab-d551-5d8d-8a47-7d944358d484', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-10-03', '16:30:00', null, '通常 / フラグとしての変数の使い方を学習する', 'ゲームをプレイした後、コードで着目してほしいところを説明してから始めました。 コスチュームを乱数にする意味なども、問いかけると「わからない」と即答していましたが、実際に動きとコスチュームタブの中を見てからコードを確認することで、納得がいったようでした。 フラグとしての変数の使い方は、スイッチのON/OFFの説明でなんとなくイメージがわいたようでした。 いろいろなところで乱数が使われているため、若干の混乱が見られました。それぞれ、何を乱数で表しているのか、乱数を使うことでどのような効果があるのか、実際に動かして確認しながら理解しようと努めていました。', null, 'タイピング: 和文Aは難しいと言っていましたが、ローマ字は相変わらずよくできていました。
盛り上がり: 新しいゲームへの取り組みには積極的で、がんばって作成していました。 検定ではなく、こういうゲームを作ってスキルを増やしていこうと声掛けをすると、安心したように笑っていました。
備考: タイピングの参加部門は、ローマ字と和文Aを候補として家で話してくるとのことで、チラシを持ち帰ってもらいました。'),
  ('1e0ba8c8-c6db-57a3-af7c-699bf6a1b07a', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-10-02', '17:30:00', null, '通常 / 変数を使ったたジャンプを学ぶ', '最初に前回の検定の答え合わせをしました。ほとんどできていましたが、アレンジをするときに問題文の指示からそれてしまった部分があったので、アレンジは問題の指示を守ったまま作ろうと伝えました。 その後ジャンプに取り組みました。4カ月ほど前に変数を使ったジャンプをやったもののうまくいかないで終わってしまったので、今ならできるようになっているはずと声をかけて取り組んでもらいました。ジャンプ中に変数が変え続ける必要があるので難しかったようでした。そのため答えを先に写経してからその意味を考えると、y座標がどのように動いているかイメージがつかめたようでした。また、今回扱ったジャンプに加えて背景スクロールもできるようになるとマリオのような本格的なゲームが作れるので、本人のやる気があれば背景スクロールの方も進めたいです。', '【小技】簡単な横スクロール', 'タイピング: 久しぶりだったので最初はスコアが落ちてしまったのですが、繰り返し練習するうちに調子を取り戻してきました。ミスタイプが少なかったのがよかったです。
盛り上がり: 眠かった様子ですが頑張っていました。'),
  ('be936825-6dbf-54db-8140-d64bd4705caf', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-10-02', '16:30:00', null, '通常 / スキルをワンランクアップしよう⇒今まで使ってきたスキルを応用できるようになる。「変数」と「横スクロール」', '前回、等速ジャンプ、放物線ジャンプ、そして高さを「変数」にする方法を習得しました。 一方で、「変数」を使う意味があまり腹落ちしていないとのことでしたので。 ◆放物線風ジャンプで変数を使い、「邪魔者」にあたるとジャンプ力がおちる、「ラッキーアイテム」にあたるとジャンプ力アップすると、ゲーム性が高くなるという話しをしたところ。 アイテムキャッチだね！とイメージがわいたので。その方向で。 ◆最終的に、２～３回で作成する目標：「カエルが家にカエルゲーム」か「アル君の冒険」＝プラットフォーマーできれいなジャンプを描くゲーム＋ジャンプ力アップ、ダウンのゲームを作ること ◆そのために ①放物線ジャンプの復習 ②「変数」でジャンプがアイテムにあたると増える、別のアイテムにあたると減る、を作る ③背景の横スクロールの復習 以上３つのスキル復習したら、目標ゲームを作ろう！となりました。 →→次回のところ参照。', 'すみません！！！！私が大失態をしまして_(_^_)__(_^_)_ 前回、【単元】放物（風）ジャンプ01でヒロト君作成していたのですが。 私が、ウッカリ「等速ジャンプ」で作った見本を見せてしまいました💦 次回、少し混乱しているかもです。', 'タイピング: 初めての毎パソで入力方法に少しとまどっていましたが。ヤル気満々でした。
盛り上がり: 「ジャンプの応用＿カエルを家に帰せの」を見せたところ、さらに、これに空中にコインとかあったら、ジャンプ力がアップしたらとれるようになるじゃん！ 変数でこれを変える、というので、ゲームのイメージがわいたようでした。 https://app.arstudio.fun/contents/44222'),
  ('0f4de5d9-f9d6-524e-8613-93c5b2324a02', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-09-22', '18:40:00', null, '通常 / フォートナイト風ゲームの作成を進める', '最初に、間違えて消してしまったスプライトなどを一緒に元に戻し、動画で言われていないことを意味がわからないままにやるとコードが壊れてしまうかもしれないと伝えました。前回、自分の力で最後までやり切ると決めていたのでその通りに進めました。レベルの高い場所が多く大変そうでしたが頑張っていました。今回完成まではできませんでしたがある程度進みました。', null, '盛り上がり: ブロック定義などもなんとか理解しようとしていました。'),
  ('105590c5-ce8b-57f3-8061-c54b8589bbd9', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-09-30', null, null, '通常 / 検定問題に慣れる', 'チェックポイントの変数がうまく動かず、そこでずっと詰まってしまって、2問を残して時間切れでした。 変数をフラグ的に使うという発想がなかったらしく、条件分岐の中で使用するのは「変数を○○ずつ変える」だと思い込んでいたようでした。 問題文をよく読むと、「変数を○○にする」と書いてあることに気付くことができていました。 それ以外はスムーズにできていて、アレンジも記述も問題ありませんでした。', '今回、変数は知っていても、初めての使用パターンで混乱していたので、新しい問題を解いてスキルチェック、という形でよいかと。', '時間帯: その他
タイピング: もう少しで6級レベルまでいきました。少しずつ記録はのびています。
盛り上がり: 3級の問題を納得して解き終えることができて、少し自信になったようでした。 時間外のアレンジも楽しんでいて、自分のアイディアもよくしゃべってくれていました。'),
  ('8e2fc99e-df6e-5903-ba29-9e144d4d0a90', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-09-30', null, null, '通常 / 水族館を作ろう', '最初15分くらいはゲームをずっとやっていて、その後「なんか作るか」と言ってデジタル水族館を作りました。跳ね返って動き回るようにしたいとこうしろうくんが要望してきたので、それに寄り添って「もし」の復習や回転するブロックなどの新しいブロックを取り入れました。作るときは集中のすいってが入って作りこんでいました。こんな風にマイペースでオンオフが激しいので、今回はオンのときに乗せられてうまく進められました。', null, '時間帯: その他
タイピング: タイピングには気が向かないようです
盛り上がり: クリオネの知識が食事の仕方まで知っていてすごかったです。'),
  ('75fbac57-e7b2-571e-8467-7384034343d9', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-09-30', null, null, '通常 / 検定練習', 'あおしくんと同様に4級の2回目をやりました。作るスピードはあおしくんよりも速いが、何かミスってバグが発生したとき、修正力がなかったです。ふだんから「どうやるの？」と口癖が多かったから、その分、差が付いたと思います。何度か最初からみなすようしたが、わからずじまいで答え合わせをしました。ヒントのブロックを使ってなかったからバグが発生していいて、注意力も必要だと思います。バグ修正の項目もやってもいいかも', null, '時間帯: その他
タイピング: うまくいかなくてぐちゃぐちゃに乱打している盤面が何度も見られました。'),
  ('9ccc9590-7a1b-5154-8516-119eeb3f4308', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-09-30', '16:30:00', null, '通常 / 検定問題の答え合わせ及び新たな検定問題の挑戦', '答え合わせについては、キャラクターが動かないなどの不具合がありましたが、デフォルトで作成されていたコードを削除していたことが原因であったため、次回から注意していけば大丈夫であると感じました。新たな検定問題への挑戦では、時間に余裕を持たせて一通りの作成を完了させていて、余った時間で見直しや疑問に思うとことの修正などをやることができていました。', '今回挑戦した検定問題の答え合わせ', '盛り上がり: 問題に取り組んでいる際は、集中していて黙々とプログラムを作成していく様子が見て取れました。'),
  ('ae87f984-51ff-5bc6-ae67-7044376b5d1d', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-09-30', null, null, '通常 / 検定練習', '検定のやり方と進め方のポイントを確認して4級の問題をやりました。忠実にルールを守り、集中してできていました。途中、バグが発生してうまくいかないこともあったが、修正ができ時間内にアレンジも含めて終わることができ、ミスもなかったです。アレンジの文章も何をどうしたかしっかり伝わりました。内容も時間も大丈夫だと思います。', null, '時間帯: その他
タイピング: ミスがかなり少なく丁寧でした'),
  ('c265479e-bf80-549c-95fc-e7bc69c8d2de', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-09-30', '16:30:00', null, '通常 / デジタル水族館の作成', '動画を見ながら、デジタル水族館の作成を行いました。キャラクターのデザインを変えたり、新たなキャラクターを追加したりとアレンジを行いながら作品を完成させたいきました。プログラムの作成については、動画にて解説していた内容を間違うことなくこなすことができていました。さらに、完成させてもかなり時間が余るほど早く作ることができていました。', null, '盛り上がり: オリジナルのキャラクターを作成していたので、自分のやりたいことを作品の中に入れることができて満足していました。'),
  ('f3104d51-8b0a-5995-9e43-d309925c9c6a', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-09-29', '16:30:00', null, '通常 / 検定問題に慣れる', '授業初めに、作成中のウェイトリフティングのプログラムを嬉しそうに見せてくれましたが、検定の話をするとすぐに「やってみる」とノッてきてくれました。 一度も質問することなく淡々と解いていて、10分前に声をかけたところ、問題は解き終わっていてアレンジで遊んでいるような状態でした。 スプライトのネコに荷物を持たせて荷物が面白く動くようにしたり、通行人を付け加えたりと、余裕で楽しめているようでした。', '4級の問題が余裕のようなので、一度3級を試してみたいです。', '盛り上がり: 検定問題でも楽しんでアレンジをして、少しでも面白くしようという意欲が見られました！'),
  ('fcd84e4e-59e5-5ab0-8934-2ff81ea3f580', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-09-29', '17:30:00', null, '通常 / 検定問題に慣れる', '初めは、授業前にやっていたたこ焼き作りゲームにハマっていて、検定問題を見せたら「これやるの～？」という反応でしたが、周りの皆が取り組んでいるのを見ているうちに、前回合格したときの気持ちを思い出したのか、突然やる気になってくれました。 特に質問をすることもなく、8分くらい前に「終わった！」と言って見せてくれましたが、そこで最初のセリフが違っていることに気が付いて、急いで直していました。 また、スプライトを一つ増やして追いかけさせるというアレンジを作成しかけたそうですが、それをすると既定のスプライトのセリフがおかしくなるからと言って削除したようでした。', null, 'タイピング: 毎パソを勧めてみましたが、今回はタイピング検定はパス、とのことでした。
盛り上がり: 問題通りにきちんと作成することができて、得意げにしていました。 途中でミスに気付いて直すことができたり、アレンジを冷静に取りやめることができたりしたのも、けいとくんの成長と思います！'),
  ('11a62f73-b679-5f2d-9ece-0178aab14fc1', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-09-29', '18:40:00', null, '通常 / 検定練習', '過去に4級の最初の問題を解いていたので、応用問題を解きました。問題文は20分くらいで解き終わり、アレンジも倍くらい作り余裕そうでした。本人に手応えを聞くと、そんなことないと謙虚だが、全くミスなくメッセージのやり取りもよくできています。3級受けてもいいかもしれないです。', null, 'タイピング: 集中して打っていました
盛り上がり: アレンジが問題文のコードをうまく活かして、面白くなっていました'),
  ('32575386-4a79-57fb-8db0-635b51ab8ef2', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-09-29', '16:30:00', null, '通常 / 検定問題に慣れる', '最初は問題を見せただけで、こういうのはやりたくない、好きなものを作りたい！こういうのはどうせできない、と拒否していましたが、たっちゃんならできると励まして、早く終わったらゲームタイムにしようと提案したら、やってもいいとなりました。 一度やる気になったら、こちらの説明も丁寧に聴いて、こちらの提案どおりに一問解いたらチェックをつける作業も最後まで律義にできていました。 初めは動画を見た印象だけで作ろうとしてとまどっていましたが、一度説明してからは、問題の読み方、ヒントのブロックの使い方などもすぐに慣れて、ほぼ問題なく時間内に完璧に仕上げることができました！ 授業時間は15分ほど余りましたが、当初の約束通り、残りはゲームタイムにしました。', '余裕で受かりそうだから、これから何度か検定の練習をするからね、と伝えてあります。', 'タイピング: ローマ字にとても熱心に取り組んでいました。最高で3級が出せて、かなり盛り上がって繰り返し練習していました。
盛り上がり: 問題に取りかかってからは、とてもスムーズでした。できていくと楽しくなったのか、最後は満足げに課題を終えていました。'),
  ('313549d0-5318-51b8-b82a-3c470cfd2efe', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-09-29', '17:30:00', null, '通常 / 検定練習', '検定問題の1級をやりました。30分くらいで問題が解き終わっていて、あとはアレンジをしていたので、余裕そうでした。1ミスでしたが、そのミスがa〜dの順で動くのところの中に、「〜のとき」で「もし」を使い、その後の動作がもしの外側でなく内側に続いて作っていました。このミスの形は、1級でよく出るパターンで、過去に受けた人が間違えがちなところと伝えてあげました。また、アレンジの際に他サイトから画像を持ってこようと無意識にしていたのので、カンニング行為になると伝えてたらハッとしてました。', null, null),
  ('064cb11f-b0a6-5e97-b493-ea23f966a576', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-09-29', '17:30:00', null, '通常 / 検定の問題に慣れよう', '今回初めて検定の問題をやりました。出来具合はまだ使ったことはない「まだ繰り返す」がわからなくて、詰まってしまい後半の問題ができずに終わってしまいました。見直しでは上記以外はできていました。 本人の手応え的には難しかったと言っていたが、時間がなくてできなかったところをやってもらうとスムーズにできていたので、慣れていないことからの難しさだと思います。アレンジは色変えしたことも文章にできたいました。次回は、わからないところがあったら飛ばして次の所をやること伝えてあげたいです。', null, '盛り上がり: アレンジ作業中は楽しそうでした。'),
  ('d8b60b03-56fd-5f8f-affe-812985ca0edb', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-09-29', '16:30:00', null, '通常 / 検定問題に慣れる', '「答えを聞いて待つ」と「答え」のブロックが初出のため軽く解説をしたのと、問題文の「答えが正解の場合は～」から自分で演算式を作成するというのが思いつかなかったらしく、「問題のどこに書いてないけど、正解かどうかの判定はどうするのか」という質問があり、そこは自分で演算式を作成する必要があるという説明はしましたが、それ以外は時間内に自分で仕上げていました。 色々な形式の問題に慣れれば、問題なくいけそうです。', 'タイピングもプログラミング検定もやる気で取り組んでいるので、このまま問題②に進んでよいかと思います。 「答え」や「リスト」についての経験が浅く、そのあたりで質問がある可能性はあります。 たくさんの問題を解いて、知らないブロックが無いようにしていくという目的はとらくんも理解しています。', 'タイピング: ローマ字と英文Aに挑戦していました。 ローマ字で最高準2級相当を出せていました！
盛り上がり: 問題を解きながら、どんどん「これはできるかも！」という気分が盛り上がってきたようで、時間いっぱい熱心に取り組めていました。'),
  ('e0e4c5cd-15fe-57a6-a480-5a12781b7b4c', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, null, '2023-09-29', '17:30:00', null, '休み（振替対象）', null, null, null),
  ('1b1b9244-7fd1-5a80-90dc-fa7feedb6aa0', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, null, '2023-09-29', '17:30:00', null, '休み（振替対象）', null, null, null),
  ('a87c575b-e327-5fdf-8a5b-12a036801079', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, null, '2023-09-29', '16:30:00', null, '休み（振替対象）', null, null, null),
  ('55f1e225-1ab1-5a67-90a5-470e02c53f80', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-09-25', '17:30:00', null, '通常 / 検定3級 17問題 https://drive.google.com/drive/u/3/folders/1byfMw3SSG_7f2pjTDNbN3BBCP-aQd8ca', '時間が足りなかった様子でしたが文章を理解するのが難しかったようでしたが、問題自体はコードをキチンと組み立てられていたところをみると理解はしているようでした。なので来週は答え合わせです', null, 'タイピング: なし
盛り上がり: アレンジ問題になったときに、カニの動きだけが一緒で気になりましたがそれ以外は自分でもできた！と話していたので概ね問題ないかなと思います。'),
  ('54550f24-828a-506a-b15a-b92d5514bfd9', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-09-25', '17:30:00', null, '振替 / 先週の金曜日に行っていた検定問題の答え合わせ 水泳ゲーム https://youtu.be/b_v5JgIL3is', '検定問題は7~8割ほどしっかりできていました。問題の読み間違えが1箇所、読み飛ばしが1箇所ほど、日本語の前後関係を理解しきれず制御のブロックで混乱してしまっている箇所がありました。一緒に確認しましたが、制御の部分は自分で考えるのも難しい様子でした。アレンジとしておばけのスプライトを増やしてくれました。 後半は水泳ゲームに取り組みました。集中して取り組めていました。パソコンで動画を開きましたが、解像度が低く見にくいことがストレスになっている様子でした。プログラムにもしっかり取り組んでほしいのですが、スプライトの見た目の方に気がよってしまうようです。遊んだときにタイマーがあることに注目できていたので良かったです！動画は9分半まで進みました。', null, 'タイピング: 集中して取り組めていました。
盛り上がり: 今日はよく集中して取り組めていました。本人も「今日はできる日だから」と言っていました。'),
  ('ed4787cb-5800-5e54-bbca-6ad1c0e9abbb', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-09-25', '17:30:00', null, '通常 / 検定問題３級 応用１７https://drive.google.com/drive/u/3/folders/1dZFWHP4IBpDpDnzM9tGcV_j3IV-vwNfC', '時間がどうやら足りなかったらしくカニに当たる動きのあたりでタイムアウト。 ひとまず残りが15分だったので、授業が終わるまで最後まで完成させるとしました。ただし私がみた時に、自分のUSBファイルにデータを保存したり、動作をいっこずつ確認しながらはコードを組み立てないという癖があるようで、旗を押した時にゲームが動かないというバグに・・・今回の件で強く言ったので、今後は一個一個確認してもらえるといいのですが・・・', '次回は答え合わせ 多分スクリプトが止まる〜系のがひっかかっている感じ', 'タイピング: なし
盛り上がり: アレンジをしてみて〜と話したら、自分で思い付かない！と話していましたが色々とアイディアを出し合ったりしたら、自分で考えついた感じなので、次回が楽しみです。'),
  ('010c4491-4ec9-5f6c-9d01-236f8de84bc9', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-09-25', '16:30:00', null, '通常 / 前回おやすみだったため、変数のおさらいをまず行う 等速ジャンプ①と②、放物線ジャンプ①の理解 https://tool-zukan.com/column/5078/', '等速ジャンプのプログラムとして座標を使うことを伝えました。「座標～～へ行く」を使ってプログラムを考えてくれました。最終到着地点をイメージをすることが多いのかな？変数の使い方について確認し、回数と高さの変数を設定してプログラムを作成しました。ジャンプの高さを簡単に調整できるところが気に入ったそうです。 左右に動かすプログラムもスムーズに作ることができていました。あまり「もし」を使い慣れていないようでした。見た目にこだわり、かわいいクマのプログラムを作ることができていました。 放物線ジャンプのプログラムは見本を見ながら作成し、ブロックの意味する役割を一緒に考えました。まだ完全には理解できていないようです。何回か使って慣れていく必要がありそうです。', null, 'タイピング: ローマ字に挑戦してみました。少し難しかったそうです。
盛り上がり: 楽しく取り組めました！'),
  ('5f32228d-b490-5b9d-b3c8-1dabc18d78ed', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-09-23', null, null, '通常 / 検定問題に慣れる', 'やる気を促すため、4級から3級に飛び級をする方向で、3級の問題を解いてもらいました。また、文章を正確に読み込むことは苦手と思われたので、最初の数行は問題文の読み方を学んでもらうため一緒に線を引きながら取り組みました。その結果、問題文を音読するなどしっかり文章を理解しようとする姿勢が見られました。アレンジはできませんでしたが、その他は解き終わりました。答え合わせをすると、頑張ってはいたものの、読み落としがいくつかあったので線を引きながら確認しました。ただ何回かやって慣れれば十分合格できそうです。', null, '時間帯: その他
盛り上がり: ドローンが抽選で当たったことを伝えると少し喜んでいました'),
  ('f726d048-de4a-59cc-9174-6d1d8e136bf6', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-09-23', null, null, '通常 / スプライトが押されたときの処理、クリア・ゲームオーバーの分岐', '動画を見ながら進めました。スプライトが押されたときだけ動かすことや、「もし～なら」を使ってクリアやゲームオーバーの画面に移動することは簡単にできていました。迷路の形については、途中で休憩地帯を入れるなど工夫していました。アレンジとして、黒い壁と似た色だが実は通れるというゾーンを作って、面白い仕掛けにしていました。完成したあと、こうしろうくんが「このゲームを色んな人に遊んでもらいたい」と言ったので一緒にアルスタジオに公開しました！', null, '時間帯: その他
盛り上がり: 今日は特にゲームを作りたい意欲が高かったと思います。その分、作成中少しでも困ったことが起こると焦ってしまったので、落ち着くよう促して一緒に問題を解決しました。'),
  ('1556e542-bdc8-5836-8b1c-3a953aac39af', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-09-23', null, null, '通常 / 検定問題に慣れる', '検定問題にも素直に取り組んでいました。 問題ができたら問題用紙にチェックを入れる説明も素直に聞いて、淡々と行き詰まることもなく、25分くらいで終えていました。 アレンジと、それを紙に記述する練習もできました。', null, '時間帯: その他
タイピング: 早々に申込書を持ってきてくれて、やる気を見せてくれました。 最初は、間違えた時にしきりにBackspaceを押したりととまどいがありましたが、やりかたのコツに慣れれば、丁寧に打つタイプなので、記録をのばしていけそうでした。
盛り上がり: どちらの検定の練習も問題なくできていて、なつめちゃんにも少し自信になったようでした。学習した基礎が身についていることの実感も得られたようでした！'),
  ('e44cd25e-f7a7-5094-b994-c760f28b5ab9', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-09-23', null, null, '通常 / 検定問題に挑戦する', '初めての検定問題だったので概要を説明したあと取り組んでもらいました。慣れない形式なので、ときどき問題文の指示が分からないところを質問しながらやっていましたが、最後まで解き切りました。アレンジに関しては、時間はあったのですが何をしていいか分からないとのことだったので、音を加えるなどのシンプルなものを勧めました。答え合わせをすると小さいミスが1つだけだったので、4級には十分受かる見込みがあると思います。', null, '時間帯: その他
盛り上がり: 検定の形式にはすぐに慣れそうです。'),
  ('94e6970f-1415-5645-9af0-77d98b944393', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-09-23', null, null, '通常 / 検定問題に慣れる', '来室時にお父さんに伺ったところ、検定はテストということでしり込みをしているとのことだったので、ゆうかちゃんの今のレベルと読解力があれば、必要な手順が全部問題文に書いてある分、普段のレッスンより簡単かもしれないと伝えたところ、試してみる、という反応になりました。 実際に問題の読み方のコツなど、最初に少しだけ説明したら、あとはスムーズに解いていました。時間も10分ほど余ったので、のんびりとアレンジを考えてもらい、紙に記述する練習もできました。 思ったより簡単で、悩むところもなかったとのことなので、次回は1度3級にチャレンジした上で、どちらを受けるか決めてみようということになりました。', '検定3級問題', '時間帯: その他
タイピング: 最初は仕様にとまどったようで、10級相当でしたが、2，3回チャレンジすると、そのたびに1級ずつ上がっていました。慣れればもう少し上を目指せそうなので、その旨を伝えておきました。
盛り上がり: 文章をそのままコードにしていくという手順は、ゆうかちゃんにはやりやすかったようで、達成感も感じられたのか、終了時はスッキリした顔をしていました。 帰り際に今日の様子をお父さんに報告したときも、来室時とは違って前向きになっているように見えました。'),
  ('12c60781-749b-5bd2-9e96-7a7d451bda6a', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-09-23', null, null, '通常 / 本人の意思を確認してから…検定4級① すぐに終わって簡単なようなら、3級でも。 検定に乗り気でなければ、単元別演習G-1をやってから自由アレンジ ジャンプの速さを変数にするやり方の習得', 'プログラミング検定とタイピング検定の話をしましたが、どちらも即座に却下でした。そういうのはあまり好きではない、とのことなのでそれ以上は勧めず、スキル的にはやる気になったらいつでもできるので、高学年になってやりたくなったらやってみようということで同意しました。 オリジナルを楽しそうに作っているようなので、毎回汎用性のあるスキルを覚えていくことを目標にしようと提案したところ、嬉しそうにノッてきました。今回のジャンプの単元も、見本を見せたらすぐにやる気になっていました。 見本のプレイで、基本操作コース09のジャンプと何が違うか説明を求めたところ、上に上がるときに重力に負けて、など、「重力」という言葉を使って説明してくれました。プログラミングと宇宙が好きだそうで、こういうところにはとても興味があるそうです。 高さが変わるにつれて、y座標が変わる数値を変えていきたい＝変数を使う、など、理屈の説明はとてもよくできていました。ただ、実際にコード作成に入ると、y座標を〇ずつ変えるのところには数値しか入らないと思い込んでいたりと、まだ経験不足な面も見えましたが、説明するとすぐに納得できたようでした。 カード通りのコードは、正答例を見ずにできていたので、x座標を別コードで動かして左右を自由に行き来しながらジャンプできるように作成させ、その後は好きなようなアレンジに入りました。', null, '時間帯: その他
タイピング: 毎回記録をタブに残して新記録にチャレンジしていました。
盛り上がり: 汎用性のあるジャンプが作れたのが嬉しそうで、熱心にゲームへのアレンジをしていました。こういうスキルを覚えて活かしていくことが楽しいようでした。'),
  ('dfef7b7a-a19a-5de5-8c44-aac4feac272d', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-09-23', null, null, '通常 / 検定の問題文が読めるようにする', '数か月前に検定問題をやったときモチベーションが微妙だったのですが、今回は湊太くんと同じ問題に取り組んだからか集中してやっていました。問題文にしっかり目を通して読んでいました。答え合わせすると細かいミスが1つあっただけで、アレンジもしていました。ただしアレンジの内容を問題用紙に書くことは渋っていたので、本番は書かないと得点にならないよと伝えました。', null, '時間帯: その他
盛り上がり: 検定を受けることにそこまで抵抗を感じなくなっていると思います'),
  ('466bb32e-83a5-5c22-a63e-3c74647715d1', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, null, '2023-09-23', null, null, '休み（振替対象）', null, null, '時間帯: その他
備考: 親子プログラミング決勝大会のため'),
  ('ccc4b9a8-ef86-5975-b994-831e3659be1b', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, null, '2023-09-23', null, null, '休み（振替対象）', null, null, '時間帯: その他'),
  ('5801b68d-8d97-56a5-82c1-2ca2747ea924', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-09-16', null, null, '通常 / レッスンを進める', '動画を見ながらコードを書くとき、それがどういう意味か問いかけながら進めました。左右の移動については今まで何度かやったのでわかっているはずなのですが、コードを見て理解することはまだ苦手なようでした。そのあとのジャンプや敵の動きやゲームクリアなどは作れました。スプライトの大きさを変えてふざけたりもしましたが一応完成しました。', null, '時間帯: その他
タイピング: 楽しみながらやっていました。
盛り上がり: 今日の最初はあまりモチベーションが高くなかったように見えましたが、こうしろうくんと同じ題材に取り組むことで多少やる気が出たと思います。'),
  ('c9c44a2f-1d55-5c33-a0e7-5340f2c8ef57', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-09-22', '17:30:00', null, '通常 / チーズを探せとは違う跳ね返り方を学ぶ', 'チーズを探せでは-10歩動かすことで壁で跳ね返りましたが、ピンポンゲームではボールの角度を変えることで跳ね返る動作を再現しました。ゆづきくんは角度の扱いに慣れていないのでそこを重点的にやりました。結果、〇度回転するという操作のイメージはつかめたようでした。回転する角度には乱数を使いますが、前回も乱数を使ったのですぐにできました。マウスのx座標を使うところは、難しいかと思いましたが少し助け舟を出すと思いついていました。ゲームオーバーやクリアも作れて完成しました。', null, 'タイピング: タイピングをやる気自体はあったようですが、毎パソのホームポジション基礎をやってもらったところ、かなり詰まっていて大変そうでした。
盛り上がり: 今までやったことを活用しようとする姿勢が見られました。'),
  ('a76877d2-eedc-539c-ac19-2431ec9f3c21', '80660755-d846-5cdd-91a4-0ab78fe29034', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-09-22', '18:40:00', null, '通常 / 検定３級問題 応用２', '30分間まずは自分でやってみて、どうかな〜という感じで進めていました。問題自体はそこまで難しくなかった様子。ただみたことがないコード＞「スプライトを止める」系で少し悩んだみたいではあった。 自分でコードを書いてみて、間違っていたら修正するというので答えがわかったみたい。 アレンジが難しかった（どれくらいの時間配分にすればいいのかなど）みたいで、慣れれば大丈夫そうな感じ', '検定の応用問題を行う', 'タイピング: なし
盛り上がり: アレンジをどれぐらいすればいいのか？を悩んではいました！'),
  ('d4588570-3984-5a4a-b86b-be663abd84e0', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-09-22', '16:30:00', null, '通常 / 水泳ゲームの続き', '作成自体は基本的にサクサク進みましたが、ゴールするはずのところでゴールの演出が出ないというバグが一つだけ起こりました。すると、関係する変数の値を表示して確認するという方法でバグの原因を探っていました。 「速さを速さ*0.8にする」というブロックが出て来たときは、速さが段々遅くなるという意味だと分かっていました。 ゲームが完成したあと、コードに登場した以下の演算ブロックについて勉強しました。具体例を出しながら説明すると、おおむね理解してくれたようでした。 ・絶対値とは何か ・「((数値*10)を四捨五入)/10」と「数値を四捨五入」はどう違うか', null, 'タイピング: 何回かやるうちに得点が上がっていました！
盛り上がり: 集中して最後までやりきっていました。'),
  ('e01361db-449a-508e-9cdb-8f4bdf4f6802', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-09-22', '17:30:00', null, '通常 / フォートナイト風ゲームの続き 後半～ラストまで 自分の作品をみんなに見てもらう～ということを意識してアレンジに入ってもOK 今日一旦自分でやってみて、どうしたいか（みんなにやってもらいたいかどうか）を聞いてみる', '前回の復習をした後に、動画を見ながら進めていました。定義がうまくはまっていなかったり、コードが重なってて見にくくなっていた部分は自分で整理してプログラムすることができていました、スランプ？に入っているという話ですが、たまに息抜きに話をしながら自分で集中して取り組むことができていました。はす向かいに悠真がいてくれたのが良かったのかもしれません。途中でおじさんの弾がうまく動かず、一緒に動画を振り返りながら確認しました。解決しました（不注意が原因）', null, 'タイピング: マイパソに挑戦しないか聞いてみましたが、本人はかなりやりたくない様子でした。'),
  ('19c73c66-87c6-52af-9ca0-2ab9cd46d82d', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-09-22', '17:30:00', null, '通常 / 自分の作品作成の続き 銃弾の動作自体は出来上がっているので、ここからどうするのか？手をうごかしながら決めているっぽいので、相談に乗りながらでもいいかな', 'あるくんがジャンプして敵を狙うプログラムを作っているそうです。「ジャンプして敵を狙う」ということをふまえて、ジャンプしないと届かない場所を作る、ジャンプの頂点での様子を少し変えるなどのアドバイスをしました。弾数、リロードなどのプログラムを作成していました。弾が端で跳ね返るコードを作る際にうまく動かない部分などを話し合いつつ修正していました。', null, 'タイピング: 集中して取り組んでいました。次週以降自分の作品にしっかり取り組みたいとのことだったので、15分ほどしっかりやりました。'),
  ('01bcf394-83dc-565a-afe7-fbed57bc6005', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-09-22', '16:30:00', null, '通常 / 【Prg】21 アイテムで脱出ゲームの続き～ 次の場面に行った時に最初の旗が干渉して、１面＞２面に映ることが繰り返し起こっている（メッセージの受け取り、もしくは最初のスタートの部分の問題）場面展開、アレンジ（どう遷移するのがベストなのか？）', 'うまくステージが変わらない原因として、スラボーからも天球からも同じ内容のプログラムを作っていることが原因でした。話していくと間違っている内容に自分でなんとなく気が付けるようでしたが、イチから自分で原因を考えるのはまだ苦手なようです。メッセージを使うことはできますが、使っている最中に何のためのメッセージなのか、どのような状況のときにメッセージが送られているのか分からなくなってしまうようです。最後に変数を整理して、2ステージ目でもうまくコインが回収できるようにしました。 アレンジとして邪魔者の弾丸を作ることになりました。見た目にこだわっていました。弾丸のプログラムにかなり悩んでいるようすでした。どの部分からプログラムをつくるのかが難しいようです。 プログラムの実行順序や「もし～」を使うタイミングなど、もう少し細かいところまで気を配れるようになるといいかなと思います。', null, 'タイピング: 集中して頑張っていました！得点が前回よりあがったそうです！'),
  ('0853e1e2-88b6-5c59-bcdb-fd174d88cc3a', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-09-22', '17:30:00', null, '通常 / 検定３級の問題 ２１番', '最初はあんまり乗り気ではなかったですが、お母さんとの約束があるから〜と伝えると自分でちゃんと30分やってみると話したので結局自力で解くことに。 時間終了して大体が動いていたものの、多少敵が当たった時の判定が甘いと思ったみたいで、結局授業のすべての時間を使ってバグを修正すると言うところまでやってみることになりました。', '来週は答え合わせ', '盛り上がり: 自分で大体７割ぐらいは解けたという自信はついてきたみたい'),
  ('1d4b8704-3d19-595c-b502-8b12d6ffbc17', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-09-22', '17:30:00', null, '通常 / スロットマシーンゲームで、コスチュームが全部揃ったら？という判定をもう一度学ぶ', '今日は動画を見ながら最後までやり遂げることができました。（途中文字タイピングも先生の力を借りないで自分で打ちました！）単にコードを移すというだけなら問題なくスラスラとできましたが、最後にどうして「もし〜なら〜」というコードを使わないといけないのか？また数字１〜３までのコスチュームが全部そろうことはどういうことなのか？をおさらいして、なんとなく考え方は理解したかんじではありました。', '条件分岐系のゲームを行うことができれば！', 'タイピング: なし
盛り上がり: 前回行ったコードのゲームと照らし合わせた時に、判定と動作を起こさせるためには条件分岐がないといけないんだね！と話していたので次回からは自分の力でも理解することができるかと思います！'),
  ('73785ccd-efa2-56dc-9266-6a68de903883', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-09-22', '16:30:00', null, '通常 / 【Prg】26 ウェイトリフティングゲームを作ろう「https://youtu.be/U0_KpGruirg」', '今日は自分の作品に役立てるために、レベルが選べるウェイトリフティングのゲームにしました。 一旦ゲームの中の確認と今まで使ってきたコードのおさらいでおそらくこんなコードがこのゲームでは使われているのが予測できるよねと伝えて、動画を見始めました。 色の数値まで動画と同じようにしようとする忠実性が見られ、ちゃんとコードを繋げようとしていました。 途中途中コードがあっているかを確認し、バグがあったらその場で戻ってちゃんと確認するという正確さもあったので、とても素晴らしいと思いました', '今日の続き', 'タイピング: とてもいい調子でタイピングしていました！
盛り上がり: 自分の作品に役立つものをやりたい！と意思がはっきりしていたのが素晴らしいと思います！'),
  ('70fd72c2-630c-5a11-8011-c6f638986f53', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, null, '2023-09-22', '16:30:00', null, '休み（未対象）', null, null, null),
  ('83405463-2098-5650-85af-b10202407c28', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-09-15', '17:30:00', null, '通常 / チーズを探せの完成', '乱数でチーズを出現させるのは前回やったようなので続きを進めました。壁に当たった時の判定は自力では難しいと思ったので、壁を貫通してしまったら反対方向に戻るということをイラストを描いて説明しました。スコアを追加するタイミングは自分でわかりましたが、ゲームが始まった時に0点にするのを忘れていました。どこかで点数をリセットしないとねと伝えると気づいていました。敵の虫が動くのが速すぎてゲームとして難しかったので、難易度を調整して完成しました。', null, 'タイピング: 徐々に成長してきています
盛り上がり: バグになったとき、なぜそうなっているのかじっくり考えていました。'),
  ('1900db67-640e-573b-99d0-c5a22cc4084b', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-09-15', '16:30:00', null, '通常 / 曖昧にしていたキャッチゲームをしっかり作り直す', 'まずは様子見で基本操作のほうのキャッチゲームを作ってもらいましたが、とても手際よくやっていて理解度は完璧に近かったです。ゲームクリアの判定(スコア>〇なら)で、等式ではなく不等式を使うということもわかっていました。バグになったのは、「20点ちょうどかそれ以上」のつもりで「スコア>20」と書いていたところくらいでした。 時間が余ったので、そこまでで作ったものをもとに、クローンを使ったきょうざいやさんのキャッチゲームも作ってもらいました。クローンは慣れていないとのことでじっくり取り組みました。スプライト本体とクローンの動きがごっちゃになっていたので、両者は分けて考えようと伝えると整理できました。最終的には乱数を使ってランダムなコスチュームのクローンを生成して、クローンを使いこなしていました。', null, 'タイピング: 集中して取り組めていました
盛り上がり: 新しいことの吸収が速かったです')
on conflict (lesson_record_id) do update set lesson_date = excluded.lesson_date, start_time = excluded.start_time, end_time = excluded.end_time, title = excluded.title, content = excluded.content, homework = excluded.homework, memo = excluded.memo;

